-- Poems batch 296
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7bb94a58-6f48-4fa2-a045-8dea5a1313a5','和吳辨叔知鳳翔見寄','司馬光','宋','宋诗','song-poetry','','[]','岐陽府舍始相逢，四十餘春屈指中。',64,'全唐诗/poet.song.30000.json','["岐陽府舍始相逢，四十餘春屈指中。", "昔日布衣今露冕，當時小吏亦衰翁。", "醉吟久作藏身計，條教應多及物功。", "惟是綵衣難再著，長林極目起悲風。"]'),
('9b1edd27-7d9b-479c-a241-e9ffc9cdfd9f','和安之今春於鄭國相公及光處得綴珠蓮各一本植之盆中仲夏始見一花喜而成詠末句云未知先合謝誰家','司馬光','宋','宋诗','song-poetry','','[]','春凍消時種兩芽，南風薫日見孤花。',32,'全唐诗/poet.song.30000.json','["春凍消時種兩芽，南風薫日見孤花。", "先開必自陶鈞力，且合歸功丞相家。"]'),
('dcd6f171-0707-41a3-93f1-751f3afe4c66','君貺環溪','司馬光','宋','宋诗','song-poetry','','[]','地勝風埃外，門深花竹間。',48,'全唐诗/poet.song.30000.json','["地勝風埃外，門深花竹間。", "波光冷於玉，溪勢曲如環。", "榮路回翔厭，華軒嘯詠閑。", "堪羞謝太傅，不復到東山。"]'),
('731b16e9-535e-496e-874b-43d173f91e50','瞑目','司馬光','宋','宋诗','song-poetry','','[]','瞑目思千古，飄然一烘塵。',24,'全唐诗/poet.song.30000.json','["瞑目思千古，飄然一烘塵。", "山川宛如舊，多少未來人。"]'),
('26add637-048b-4291-8342-cb7f9d784c4c','獨樂園二首  其一','司馬光','宋','宋诗','song-poetry','','[]','獨樂園中客，朝朝常閉門。',24,'全唐诗/poet.song.30000.json','["獨樂園中客，朝朝常閉門。", "端居無一事，今日又黄昏。"]'),
('dd3cc2c9-1633-406d-aee1-dd43e5225b2d','獨樂園二首  其二','司馬光','宋','宋诗','song-poetry','','[]','客到暫冠带，客歸還上關。',24,'全唐诗/poet.song.30000.json','["客到暫冠带，客歸還上關。", "朱門客如市，豈得似林間。"]'),
('a6c92f73-e3e6-4cf9-9fd5-40fe125fb5e1','放鸚鵡二首  其一','司馬光','宋','宋诗','song-poetry','','[]','野性思歸久，籠樊今始開。',24,'全唐诗/poet.song.30000.json','["野性思歸久，籠樊今始開。", "雖知主恩厚，何日肯重來。"]'),
('5d502386-0ccf-4d7b-804f-ba2ff0717804','放鸚鵡二首  其二','司馬光','宋','宋诗','song-poetry','','[]','雖道長安樂，爭如在隴頭。',24,'全唐诗/poet.song.30000.json','["雖道長安樂，爭如在隴頭。", "林間祝聖主，萬歳復千秋。"]'),
('a708716c-9dde-44e4-8c88-4d6c6f803c6c','呈樂道','司馬光','宋','宋诗','song-poetry','','[]','歡迎俛仰皆陳迹，薄宦須臾即色空。',32,'全唐诗/poet.song.30000.json','["歡迎俛仰皆陳迹，薄宦須臾即色空。", "試憶昔年雙桂會，只如前日夢魂中。"]'),
('fe152148-3738-4140-aaa3-a20dbbca9928','太皇太后挽歌詞二首  其一','司馬光','宋','宋诗','song-poetry','','[]','麟閣承家慶，軒星應德暉。',48,'全唐诗/poet.song.30000.json','["麟閣承家慶，軒星應德暉。", "帝猷陰有補，嬪則動無違。", "遽就蒼梧野，空餘大練衣。", "只應彤管在，萬古播鴻徽。"]'),
('077d67fb-a2cf-4e33-860a-d4ce1157f913','太皇太后挽歌詞二首  其二','司馬光','宋','宋诗','song-poetry','','[]','四紀褘衣盛，兩朝長樂尊。',48,'全唐诗/poet.song.30000.json','["四紀褘衣盛，兩朝長樂尊。", "九州貢甘旨，萬乘問晨昏。", "明辟歸元子，嘉謀賚孝孫。", "群生資后土，難答化光恩。"]'),
('aa9e83c3-2f57-4f7d-b4ec-d69c00b07dca','和劉伯壽陪潞公禊飲','司馬光','宋','宋诗','song-poetry','','[]','旌幢車騎滿沙頭，鼓吹喧繁畫鷁浮。',64,'全唐诗/poet.song.30000.json','["旌幢車騎滿沙頭，鼓吹喧繁畫鷁浮。", "十里羅紈光照地，千家簾幕遠臨流。", "觴隨洛水周公事，月映鳳樓裴相遊。", "令典久墮今更舉，行聞美俗徧中州。"]'),
('22f146e0-2c14-4191-b09b-3f42caa3d473','南園雨霽景物粗佳有懷正叔安之','司馬光','宋','宋诗','song-poetry','','[]','洛陽秋雨闋，荒圃物華饒。',72,'全唐诗/poet.song.30000.json','["洛陽秋雨闋，荒圃物華饒。", "白鶴寒尤盛，紅薇晚未彫。", "鳥驚朱實墮，雲滅翠岑遙。", "揚子方嘲白，相如尚苦痟。", "徘徊瞻望近，邂逅笑談遼。", "官冷慚無具，相思不敢招。"]'),
('a015833d-1aa3-4adc-b930-522d07d4914c','和潞公與昌言正叔遊獨樂園徘徊久之主人不至','司馬光','宋','宋诗','song-poetry','','[]','茂勛成亮采，勝賞寄風流。',48,'全唐诗/poet.song.30000.json','["茂勛成亮采，勝賞寄風流。", "閑引翹林客，同爲獨樂遊。", "厭居華宇盛，翻愛弊廬幽。", "愧不先操篲，迎塵立道周。"]'),
('5cfd5054-cbd4-4540-aff1-a181760799bb','潞公遊龍門光以室家病不獲參陪獻詩十六韻','司馬光','宋','宋诗','song-poetry','','[]','旄節擁憑熊，逶迤向鑿龍。',192,'全唐诗/poet.song.30000.json','["旄節擁憑熊，逶迤向鑿龍。", "順成時過蜡，閉塞令行冬。", "雪壟痕猶濕，梅林思已濃。", "傳呼空谷應，前導白雲逢。", "飛蓋多邀客，停車數問農。", "禹功雙壁斷，佛劫萬龕重。", "絕頂標孤剎，疏林透遠鐘。", "氣蒸泉郁郁，冰綻水溶溶。", "藥閣低臨渚，茅庵背倚峰。", "凍醪資野酌，寒筍佐晨饔。", "棋局多依石，茶爐坐蔭松。", "醉醒皆衆共，小大盡公從。", "顧以私恩累，難追勝賞蹤。", "原思初不病，叔夜亦非慵。", "稽古慚經笥，摛華怯筆鋒。", "會須參後乘，異日待從容。"]'),
('144ea7bc-6e9d-40bc-b698-dfc55f963833','初夏獨遊南園二首  其一','司馬光','宋','宋诗','song-poetry','','[]','取醉非無酒，忘憂亦有花。',24,'全唐诗/poet.song.30000.json','["取醉非無酒，忘憂亦有花。", "暫來疑是客，歸去不成家。"]'),
('ae76d1b4-8fe9-4010-b306-3bf87c7d3812','初夏獨遊南園二首  其二','司馬光','宋','宋诗','song-poetry','','[]','桃李都無日，梧桐半死身。',24,'全唐诗/poet.song.30000.json','["桃李都無日，梧桐半死身。", "那堪衰病意，更作獨遊人。"]'),
('d6c08387-555a-4d26-887f-c8d602951da0','和景仁答才元寄示花圖','司馬光','宋','宋诗','song-poetry','','[]','高士閑居舊，名花獨步今。',48,'全唐诗/poet.song.30000.json','["高士閑居舊，名花獨步今。", "移從洛浦遠，濯自錦江深。", "傳得巫山貌，非因延壽金。", "不須天女散，已解動禪心。"]'),
('0eba5bd3-2912-465f-a953-3cd5a424f7bc','或謂光嗤景仁談禪而自談又因用前韻爲景仁解禪','司馬光','宋','宋诗','song-poetry','','[]','賤子悟已久，景仁迷自今。',48,'全唐诗/poet.song.30000.json','["賤子悟已久，景仁迷自今。", "良因拯溺急，是致涉波深。", "到岸何須栰，揮鉏不見金。", "浮雲任來往，明月在天心。"]'),
('3338b49e-8dc2-4f68-b16b-1b1a1cc1df4a','題傳燈錄','司馬光','宋','宋诗','song-poetry','','[]','呷著聲聞酒便狂，它州浪走不歸鄉。',64,'全唐诗/poet.song.30000.json','["呷著聲聞酒便狂，它州浪走不歸鄉。", "誰曾縛汝安用解，彼自無創勿誤傷。", "探月拾針傳妄語，安居暇食賴先王。", "但令時世如三代，達磨從他面向墻。"]'),
('7e949f53-cbc2-4054-8cf7-b6e08d696c12','奉和大夫同年張兄會南園詩','司馬光','宋','宋诗','song-poetry','','[]','露濃秋過半，氣爽雨收餘。',120,'全唐诗/poet.song.30000.json','["露濃秋過半，氣爽雨收餘。", "取酒邀嘉客，呼兒掃弊廬。", "生涯數畝地，官業一軒書。", "竹結垂綸屋，泉分入座渠。", "愜心皆樂事，容膝即安居。", "梁静栖無燕，波澄戲有魚。", "茂林穿繚繞，微徑步虚徐。", "果落方知熟，莎長不忍除。", "過從當苦遠，接侍每慚疏。", "不厭茅茨陋，時迂長者車。"]'),
('6dd76ca9-c937-408c-849e-66581a86b04a','答張伯常之郢州塗中見寄','司馬光','宋','宋诗','song-poetry','','[]','適意遺軒冕，輕於鴻一毛。',48,'全唐诗/poet.song.30000.json','["適意遺軒冕，輕於鴻一毛。", "扁舟千里遠，佳句百篇豪。", "酒飲宜城美，歌聞白雪高。", "家林已春色，慎勿滯江臯。"]'),
('acfc34c9-e643-4d38-8375-f2743f0bac9a','獨樂園新春','司馬光','宋','宋诗','song-poetry','','[]','春風與汝不相關，何事潛来入我園。',64,'全唐诗/poet.song.30000.json','["春風與汝不相關，何事潛来入我園。", "曲沼揉藍通底綠，新梅剪綵壓枝繁。", "短莎乍見殊堪喜，鳴鳥初聞未覺喧。", "憑仗東君徐按轡，旋添花卉伴芳樽。"]'),
('fc61ee06-20b9-4c93-ac41-721498001459','和潞公真率會詩','司馬光','宋','宋诗','song-poetry','','[]','洛下衣冠愛惜春，相從小飲任天真。',64,'全唐诗/poet.song.30000.json','["洛下衣冠愛惜春，相從小飲任天真。", "隨家所有自可樂，爲具更微誰笑貧。", "不待珍羞方下筯，只將佳景便娛賓。", "庾公此興知非淺，藜藿終難繼主人。"]'),
('e81b42db-64e8-4917-80e7-fac96d45ebf8','景仁書云去冬因酒病耳病牙遂不入洛以詩寄呈','司馬光','宋','宋诗','song-poetry','','[]','許昌攜手盡時英，况復新開甲第成。',64,'全唐诗/poet.song.30000.json','["許昌攜手盡時英，况復新開甲第成。", "醉裏都將春作達，老来不向酒藏情。", "齒疏無廢銜杯趣，耳病猶分度曲聲。", "舊友昔遊渾忘却，可憐寂寂洛陽城。"]'),
('553bfa74-ec79-4e78-8bde-984d721393b2','又云新鑄鬴斛與今太府寺尺及權衡若合符契復次前韻','司馬光','宋','宋诗','song-poetry','','[]','裁筩累黍久研精，况復新修鬴斛成。',64,'全唐诗/poet.song.30000.json','["裁筩累黍久研精，况復新修鬴斛成。", "豈校忽微爭口語，本期淳古變人情。", "既言樂律符今尺，但恐簫韶似鄭聲。", "若欲世人俱信服，鳳凰再集潁川城。"]'),
('90e5f71d-b325-4499-aaf1-37297bcd455a','三月二十五日安之以詩二絕見招作真率會光以無從者不及赴依韻和呈  其一','司馬光','宋','宋诗','song-poetry','','[]','真率由来無次第，經旬踰月不爲稀。',32,'全唐诗/poet.song.30000.json','["真率由来無次第，經旬踰月不爲稀。", "藍輿但恨無人舉，坐想紛紛醉落暉。"]'),
('8bbd4d92-9935-4b61-ab70-c44f9120c11a','三月二十五日安之以詩二絕見招作真率會光以無從者不及赴依韻和呈  其二','司馬光','宋','宋诗','song-poetry','','[]','杯盤豐腆勝陶令，園沼繁華減白家。',32,'全唐诗/poet.song.30000.json','["杯盤豐腆勝陶令，園沼繁華減白家。", "惆悵佳辰掩蓬蓽，不陪高會賞鄰花。"]'),
('3f5ec402-5112-417e-bfa5-89a0f00bb463','用安之韻招君從安之正叔不疑二十六日南園爲真率會  其一','司馬光','宋','宋诗','song-poetry','','[]','榆錢零亂柳花飛，枝上紅英漸漸稀。',32,'全唐诗/poet.song.30000.json','["榆錢零亂柳花飛，枝上紅英漸漸稀。", "莫厭銜杯不虚日，須知共力惜春暉。"]'),
('03f92636-c6cb-426d-b180-084338e97148','用安之韻招君從安之正叔不疑二十六日南園爲真率會  其二','司馬光','宋','宋诗','song-poetry','','[]','真率春來頻宴聚，不過東里即西家。',32,'全唐诗/poet.song.30000.json','["真率春來頻宴聚，不過東里即西家。", "小園容易邀嘉客，饌具雖無亦有花。"]'),
('82cc586f-e736-43a1-8e56-e136fe96903f','二十六日作真率會伯康與君從七十八歳安之七十七歳正叔七十四歳不疑七十三歳叔達七十歳光六十五歳合五百一十五歳口號成詩用安之前韻  其一','司馬光','宋','宋诗','song-poetry','','[]','七人五百有餘歳，同醉花前今古稀。',32,'全唐诗/poet.song.30000.json','["七人五百有餘歳，同醉花前今古稀。", "走馬鬥雞非我事，紵衣絲髪且相暉。"]'),
('b4bd9db0-5118-4fd8-9277-b05d2fbbc028','二十六日作真率會伯康與君從七十八歳安之七十七歳正叔七十四歳不疑七十三歳叔達七十歳光六十五歳合五百一十五歳口號成詩用安之前韻  其二','司馬光','宋','宋诗','song-poetry','','[]','經春無事連翩醉，彼此往來能幾家。',32,'全唐诗/poet.song.30000.json','["經春無事連翩醉，彼此往來能幾家。", "切莫辭斟十分酒，儘從他笑滿頭花。"]'),
('8e974c06-2aca-4d6b-af45-30befd9bbcd3','别用韻','司馬光','宋','宋诗','song-poetry','','[]','坐中七叟推年紀，比較前人少幾多。',32,'全唐诗/poet.song.30000.json','["坐中七叟推年紀，比較前人少幾多。", "花似錦紅頭雪白，不遊不飲欲如何。"]'),
('878f347f-f66a-40aa-b529-4808136eca9a','其夕宿獨樂園詰朝將歸賦詩','司馬光','宋','宋诗','song-poetry','','[]','平曉何人汲井華，轆轤聲急散春鴉。',64,'全唐诗/poet.song.30000.json','["平曉何人汲井華，轆轤聲急散春鴉。", "開園更有四五日，映葉尚餘三兩花。", "宿病岑岑猶带酒，無眠耿耿不禁茶。", "自嫌行樂妨年少，遽索藍輿且向家。"]'),
('b1c1d9ba-f6fa-497c-b1f6-c643082341ec','二十七日邀子駿堯夫賞西街諸花','司馬光','宋','宋诗','song-poetry','','[]','今年節物非常晚，春盡西街花尚多。',32,'全唐诗/poet.song.30000.json','["今年節物非常晚，春盡西街花尚多。", "試問二三真率友，小車籃舁肯重過。"]'),
('2e59a05d-5d54-4fde-8e83-728613b66171','呈張子賤','司馬光','宋','宋诗','song-poetry','','[]','近時洛社名真率，簞食壺漿取次遊。',32,'全唐诗/poet.song.30000.json','["近時洛社名真率，簞食壺漿取次遊。", "試問西來老朝散，可能同志便相收。"]'),
('3be49b59-25ff-47df-8a28-2e58e7c70c11','三月三十日微雨偶成詩二十四韻書懷獻留守開府太尉兼呈真率諸公','司馬光','宋','宋诗','song-poetry','','[]','春盡少歡意，昏昏睡思添。',288,'全唐诗/poet.song.30000.json','["春盡少歡意，昏昏睡思添。", "正憂花意索，更用雨聲兼。", "乍語鶯喉澀，慵飛柳絮黏。", "落英紅沒砌，茂草碧侵簾。", "寶相錦鋪架，酴醿雪擁簷。", "沼萍浮鈿靨，林筍露犀尖。", "坐惜光風駛，行愁畏日炎。", "追隨任塵甑，歌笑望霜髯。", "落筆詩情放，飛觥酒令嚴。", "金丹呼勝彩，玉燭擢新籖。", "傲岸冠巾側，淋浪襟袖霑。", "饑仍留瘦馬，歸必待清蟾。", "筋力雖無幾，娛遊亦未厭。", "脫身離簿領，適性得閭閻。", "多病非辭貴，無才豈飬恬。", "清塗誠愧忝，微祿已傷廉。", "日費須三爵，年支仰數縑。", "糇糧粗能足，蓍蔡不煩占。", "河洛今爲盛，圖書昔所潛。", "家家花啓戶，處處酒飄帘。", "温飽資兼愛，安平倚具瞻。", "愚夫猶樂育，下客愈撝謙。", "落拓形骸逸，優遊歳月淹。", "餘生信多幸，狂醉亦無嫌。"]'),
('327b8722-6cde-49a8-86c7-24e0ce2b294a','其日雨中聞姚黄開戲成詩二章呈子駿堯夫  其一','司馬光','宋','宋诗','song-poetry','','[]','穀雨後來花更濃，前時已是玉玲瓏。',32,'全唐诗/poet.song.30000.json','["穀雨後來花更濃，前時已是玉玲瓏。", "客來更說姚黄發，只在街西相第東。"]'),
('b0008d07-0833-49af-baf8-f4ddbd926d28','其日雨中聞姚黄開戲成詩二章呈子駿堯夫  其二','司馬光','宋','宋诗','song-poetry','','[]','小雨留春春未歸，好花雖有恐行稀。',32,'全唐诗/poet.song.30000.json','["小雨留春春未歸，好花雖有恐行稀。", "勸君披取魚蓑去，走看姚黄判濕衣。"]'),
('fe5b3944-7cc2-41f3-a391-d2b40cc674c8','四月十三日立夏呈安之','司馬光','宋','宋诗','song-poetry','','[]','留春春不住，昨夜的然歸。',48,'全唐诗/poet.song.30000.json','["留春春不住，昨夜的然歸。", "歡趣何妨少，閑遊勿怪稀。", "林鶯欣有託，叢蝶悵無依。", "窗下忘懷客，高眠正掩扉。"]'),
('5c7dbad4-08a8-4dec-8ebd-f3afc57cbda0','和子駿洛中書事','司馬光','宋','宋诗','song-poetry','','[]','西都自古繁華地，冠蓋優遊萃五方。',64,'全唐诗/poet.song.30000.json','["西都自古繁華地，冠蓋優遊萃五方。", "比戶清風人種竹，滿川濃綠土宜桑。", "鑿龍山斷開天闕，導洛波回載羽觴。", "况有耆英詩酒樂，問君何處不如唐。"]'),
('622db7f4-a796-4809-8dd6-a674705c9d95','安之令子河陽官舍作蛙樂軒安之有詩寄題輙敢繼和','司馬光','宋','宋诗','song-poetry','','[]','鼓吹娛俗耳，蛙鳴惬雅懷。',48,'全唐诗/poet.song.30000.json','["鼓吹娛俗耳，蛙鳴惬雅懷。", "最宜凉雨歇，更與晚風偕。", "驥子方長騖，雲衢偶未諧。", "功名當努力，留此遺吾儕。"]'),
('102649a2-a353-41ed-a875-deead0363da5','和安之喜雨','司馬光','宋','宋诗','song-poetry','','[]','吁嗟方請雨，潤溽果如占。',72,'全唐诗/poet.song.30000.json','["吁嗟方請雨，潤溽果如占。", "黍稷固有望，來麰亦未嫌。", "聲繁清倦枕，氣冷入疏簾。", "蔓喜龍頭舉，泉驚虎爪添。", "田疇誠最急，花藥不妨兼。", "詩伯才盈斛，聊應費筆尖。"]'),
('7aaf8e6f-6930-42cf-9679-084056dc5ddc','逍遙四章呈欽之堯夫  其一','司馬光','宋','宋诗','song-poetry','','[]','結髪讀經史，疲精非一朝。',48,'全唐诗/poet.song.30000.json','["結髪讀經史，疲精非一朝。", "於今成濩落，所幸得逍遙。", "不韙狂心息，難平客氣消。", "巢林易爲足，竊敢比鷦鷯。"]'),
('1084297c-90a8-4390-af76-1e24ad24d953','逍遙四章呈欽之堯夫  其二','司馬光','宋','宋诗','song-poetry','','[]','閑思宇宙內，何物不由天。',48,'全唐诗/poet.song.30000.json','["閑思宇宙內，何物不由天。", "定分不移易，勞心徒棄捐。", "鵬飛九萬里，松壽一千年。", "斥鷃與朝菌，逍遙亦自然。"]'),
('d77e5837-50d8-478f-ad07-006817fd4c97','逍遙四章呈欽之堯夫  其三','司馬光','宋','宋诗','song-poetry','','[]','閉目念前古，飄然一烘塵。',48,'全唐诗/poet.song.30000.json','["閉目念前古，飄然一烘塵。", "兩儀仍似舊，萬物互爭新。", "軒冕榮何在，簞瓢樂最真。", "衆人俱我笑，我亦笑其人。"]'),
('8c6c59b4-6bdc-4f2e-a878-5e0e61bb9670','逍遙四章呈欽之堯夫  其四','司馬光','宋','宋诗','song-poetry','','[]','六合曠無際，逍遙好縱遊。',48,'全唐诗/poet.song.30000.json','["六合曠無際，逍遙好縱遊。", "放懷同一貫，瞬目即千秋。", "丸遇區臾止，萍隨波浪流。", "所之皆自得，何懼亦何憂。"]'),
('09463ae8-ee71-45cc-aa8b-217983f05184','感物','司馬光','宋','宋诗','song-poetry','','[]','朝看新燕飛，暮聼子規啼。',48,'全唐诗/poet.song.30000.json','["朝看新燕飛，暮聼子規啼。", "尺蠖身藏葉，神龜尾曳泥。", "韝鷹何用掣，櫪馬不當嘶。", "自伐憎狙巧，頽然憂木雞。"]'),
('7eec25de-b6af-4fc6-9cdf-6d8d5d42bbc8','送伯淳監汝州酒','司馬光','宋','宋诗','song-poetry','','[]','惟知負米樂，不覺抱關卑。',24,'全唐诗/poet.song.30000.json','["惟知負米樂，不覺抱關卑。", "出處兩得意，是非皆自知。"]'),
('964c287a-c2a4-4a5b-ae06-f4e0cb254d07','酬安之謝光兄弟見過','司馬光','宋','宋诗','song-poetry','','[]','平時一二日，不見已相思。',48,'全唐诗/poet.song.30000.json','["平時一二日，不見已相思。", "况復閉關久，杳無攜手期。", "清談勝妙藥，高韻敵凉颸。", "愧乏機雲美，虚承青眼知。"]'),
('18e3aa69-e31b-4f0e-8774-7e2474a763c1','酬王安之聞罷真率會','司馬光','宋','宋诗','song-poetry','','[]','閉關寧是率，辭疾似非真。',48,'全唐诗/poet.song.30000.json','["閉關寧是率，辭疾似非真。", "既處譏嘲地，誰爲長厚人。", "虛舟非有意，飄瓦不須嗔。", "此過如何贖，清秋宴席陳。"]'),
('abfd4d98-c160-4048-a197-4bd3aaa12f78','和潞公伏日讌府園示座客','司馬光','宋','宋诗','song-poetry','','[]','盛陽金氣伏，華宇玉樽開。',72,'全唐诗/poet.song.30000.json','["盛陽金氣伏，華宇玉樽開。", "真率除煩禮，耆英集上才。", "炎蒸疑遠避，流景忘西頽。", "幸忝俊遊並，仍慚右席陪。", "蒲葵參執扇，冰果侑傳杯。", "相國方留客，如何務早回。"]'),
('1a463b78-47d3-4bb2-bd6c-e1da993ce574','和子駿新荷','司馬光','宋','宋诗','song-poetry','','[]','懶不窺園久，元非效仲舒。',48,'全唐诗/poet.song.30000.json','["懶不窺園久，元非效仲舒。", "新荷滿沼密，藍舁出門疏。", "借問含煙晚，能勝裛露初。", "愧無魚戲句，弄翰白紛如。"]'),
('d613162d-35fe-4e65-bde8-5e626903f996','司徒開府韓國富公挽辭四首  其一','司馬光','宋','宋诗','song-poetry','','[]','天祐休明祚，時生雋傑臣。',48,'全唐诗/poet.song.30000.json','["天祐休明祚，時生雋傑臣。", "賢科首多士，宰府澤生民。", "煥爛三台正，冲融四海春。", "欲知甄冶力，試問白頭人。"]'),
('24bb259d-4bb6-44f8-a4a3-2b482b9291a4','司徒開府韓國富公挽辭四首  其二','司馬光','宋','宋诗','song-poetry','','[]','松漠驕無信，漁陽廣聚兵。',48,'全唐诗/poet.song.30000.json','["松漠驕無信，漁陽廣聚兵。", "移書侮中國，决意背齊盟。", "直氣輕軺入，英辭左衽驚。", "虜歸烽火滅，宇縣復升平。"]'),
('a6f5f984-8c79-4b06-a9cc-374f46483762','司徒開府韓國富公挽辭四首  其三','司馬光','宋','宋诗','song-poetry','','[]','大吕功名重，鴻毛軒冕輕。',48,'全唐诗/poet.song.30000.json','["大吕功名重，鴻毛軒冕輕。", "閑居客愈盛，暫出市皆傾。", "溟海涵容大，龍門謁見榮。", "謙光儼在目，慟哭望佳城。"]'),
('5fa63d95-75d7-46a5-a05b-65ac0a6c49dd','司徒開府韓國富公挽辭四首  其四','司馬光','宋','宋诗','song-poetry','','[]','杖屨還私第，精誠在本朝。',48,'全唐诗/poet.song.30000.json','["杖屨還私第，精誠在本朝。", "愛君老不懈，憂國沒方昭。", "東閣秋牢落，西芒夜寂寥。", "只應忠亮志，氣運不能消。"]'),
('8928c1dc-b27b-4596-9745-b7e3ca15066a','臧郎中挽歌二首  其一','司馬光','宋','宋诗','song-poetry','','[]','積慶承前烈，呈才會聖時。',48,'全唐诗/poet.song.30000.json','["積慶承前烈，呈才會聖時。", "踐楊朝有籍，治行吏爲師。", "僚友皆親譽，黎民每去思。", "惜哉違世早，志業未全施。"]'),
('688ea6d8-3615-49dc-a546-88267e432186','臧郎中挽歌二首  其二','司馬光','宋','宋诗','song-poetry','','[]','素履存誠厚，虚懷待物真。',48,'全唐诗/poet.song.30000.json','["素履存誠厚，虚懷待物真。", "鄉閭昔相接，朋友世彌親。", "遺札蠅頭細，長阡馬鬛新。", "九原那可作，空復想音塵。"]'),
('d0d0f88f-908a-4857-9074-65dc74c370dc','和子華遊君貺園  其一','司馬光','宋','宋诗','song-poetry','','[]','甲第朱門久不開，春風潛入發江梅。',32,'全唐诗/poet.song.30000.json','["甲第朱門久不開，春風潛入發江梅。", "今朝丞相雙車轍，碾破林間水畔苔。"]'),
('e594403f-015c-4a16-a5d6-16066ee5c06f','和子華遊君貺園  其二','司馬光','宋','宋诗','song-poetry','','[]','小桃似喜相君來，爭發新花繼落梅。',32,'全唐诗/poet.song.30000.json','["小桃似喜相君來，爭發新花繼落梅。", "更仗環溪醒殘酒，沒篙春水綠於苔。"]'),
('581995d8-43c9-4abe-8557-50db8cd73a20','又和上元日遊南園賞梅花','司馬光','宋','宋诗','song-poetry','','[]','梅簇荒臺自可羞，相君愛賞忘宵遊。',32,'全唐诗/poet.song.30000.json','["梅簇荒臺自可羞，相君愛賞忘宵遊。", "未言美實調羮味，且薦清香泛酒甌。"]'),
('dc77ecb6-650b-4869-851e-b4de96b12471','又和','司馬光','宋','宋诗','song-poetry','','[]','中令園陪丞相遊，百分勸酒不須愁。',32,'全唐诗/poet.song.30000.json','["中令園陪丞相遊，百分勸酒不須愁。", "春風陌上醒歸去，只恐更爲桃李羞。"]'),
('22dc473d-a58c-4f3a-9f8a-2539615f3400','又和遊吳氏園二首  其一','司馬光','宋','宋诗','song-poetry','','[]','天氣清和無喘牛，花林爛熳竹林幽。',32,'全唐诗/poet.song.30000.json','["天氣清和無喘牛，花林爛熳竹林幽。", "臨風高詠足爲樂，有勇知方笑仲由。"]'),
('8f1ae22a-d5e2-40a9-b29f-10bfd6ab8c1f','又和遊吳氏園二首  其二','司馬光','宋','宋诗','song-poetry','','[]','名園易主似行郵，美竹高松景自幽。',32,'全唐诗/poet.song.30000.json','["名園易主似行郵，美竹高松景自幽。", "誰信本來天地物，長爲已有固無由。"]'),
('cff1eb52-0c9f-4e96-be22-de307a8e59be','和子駿約遊一二園亭看花遇雨而止','司馬光','宋','宋诗','song-poetry','','[]','行樂及佳時，官閑無所覉。',48,'全唐诗/poet.song.30000.json','["行樂及佳時，官閑無所覉。", "只知花正發，不共雨爲期。", "淺草碧無際，濃雲冷四垂。", "陪遊興未盡，安得不相思。"]'),
('892b751f-65bc-4b80-aa28-d5090b8cd0d7','又即事二章上呈  其一','司馬光','宋','宋诗','song-poetry','','[]','雨不成遊半路歸，逢花值柳倍依依。',32,'全唐诗/poet.song.30000.json','["雨不成遊半路歸，逢花值柳倍依依。", "朝來賴飲三杯酒，醉卧西齋晝掩扉。"]'),
('7a40d111-77ca-4eca-9c09-8fddac9dacc7','又即事二章上呈  其二','司馬光','宋','宋诗','song-poetry','','[]','覺後追思氣味長，歡情愁緒兩俱忘。',32,'全唐诗/poet.song.30000.json','["覺後追思氣味長，歡情愁緒兩俱忘。", "近来方得醉中趣，熟寐沈沈是醉鄉。"]'),
('4ae6e158-9ab3-49c6-89e9-17e3ce2ff66f','明日雨止復招子駿堯夫遊南園  其一','司馬光','宋','宋诗','song-poetry','','[]','昨朝洛北阻遊陪，惆悵中橋半醉回。',32,'全唐诗/poet.song.30000.json','["昨朝洛北阻遊陪，惆悵中橋半醉回。", "潑火既經寒食雨，解酲須撥凍醪醅。"]'),
('1e78a72c-f7be-4cd4-be93-4cb3b97161bc','明日雨止復招子駿堯夫遊南園  其二','司馬光','宋','宋诗','song-poetry','','[]','遙思花寨交横錦，未分春心斗頓灰。',32,'全唐诗/poet.song.30000.json','["遙思花寨交横錦，未分春心斗頓灰。", "更與二三頭白友，試携薄具上高臺。"]'),
('c8b029b8-4147-4ab6-9134-1a2fd614530e','戲呈堯夫','司馬光','宋','宋诗','song-poetry','','[]','近來朝野客，無坐不談禪。',48,'全唐诗/poet.song.30000.json','["近來朝野客，無坐不談禪。", "顧我何爲者，逢人獨懵然。", "羡君詩既好，說佛衆誰先。", "只恐前身是，東都白樂天。"]'),
('c2ba2307-7c4c-4f4d-b2da-d030740a9c7d','聞正叔與客過趙園歡飲戲成小詩','司馬光','宋','宋诗','song-poetry','','[]','吾廬寂寞類荒村，但有林間鳥雀喧。',32,'全唐诗/poet.song.30000.json','["吾廬寂寞類荒村，但有林間鳥雀喧。", "不似楚家多樂事，笙歌拾得醉鄰園。"]'),
('c8634df9-5a43-43c3-9627-f5130e743fa3','和子華應天院行香歸過洛川','司馬光','宋','宋诗','song-poetry','','[]','印節傳呼洛北還，府庭無訟不妨閑。',64,'全唐诗/poet.song.30000.json','["印節傳呼洛北還，府庭無訟不妨閑。", "度橋寒色侵春服，按轡晴光露曉山。", "香穗徘徊凝廣殿，花籃繁會滿通闤。", "自知白雪高難和，忍愧誰能寄我顔。"]'),
('a0fe51c3-612f-4d8b-bcd8-814d58ec0b33','寒食遊南園獨飲','司馬光','宋','宋诗','song-poetry','','[]','寒食良辰無賞心，雜花爛熳柳成陰。',32,'全唐诗/poet.song.30000.json','["寒食良辰無賞心，雜花爛熳柳成陰。", "若非獨酌酬佳景，一日風光直萬金。"]'),
('0ca62dc1-9a86-4b25-b08b-71402fabeb3e','次前韻二首  其一','司馬光','宋','宋诗','song-poetry','','[]','頭白惜春情更深，花間獨醉競分陰。',32,'全唐诗/poet.song.30000.json','["頭白惜春情更深，花間獨醉競分陰。", "泉聲醒耳自可樂，不用歌抛滿袖金。"]'),
('f7f0999f-f922-4c66-8987-2bdeb8856841','次前韻二首  其二','司馬光','宋','宋诗','song-poetry','','[]','南園莫笑獨追尋，明日未知晴與陰。',32,'全唐诗/poet.song.30000.json','["南園莫笑獨追尋，明日未知晴與陰。", "揮手一朝辭逆旅，滿堂安用累千金。"]'),
('100e6f18-cd99-4cb8-9294-abf2fea85267','觀孫兒戲感懷','司馬光','宋','宋诗','song-poetry','','[]','我昔垂髫今白頭，中間萬事水東流。',32,'全唐诗/poet.song.30000.json','["我昔垂髫今白頭，中間萬事水東流。", "此心爭得還如是，戲走階前不識愁。"]'),
('3a300d56-47be-4ac0-b0bc-a72a6a8c872c','陪子華燕醮廳酒半過趙中令園','司馬光','宋','宋诗','song-poetry','','[]','簪裾丞相閣，林沼令君家。',48,'全唐诗/poet.song.30000.json','["簪裾丞相閣，林沼令君家。", "煙曲香尋篆，杯深酒過花。", "霏微燼沈水，馥郁漬榠柤。", "愧乏相如賦，陪遊託後車。"]'),
('a5db5adf-46ff-437a-ba75-1935de8ffb15','和秉國寄子駿堯夫二留臺','司馬光','宋','宋诗','song-poetry','','[]','一臺二妙日追遊，琥珀香醪白玉甌。',32,'全唐诗/poet.song.30000.json','["一臺二妙日追遊，琥珀香醪白玉甌。", "相下不厭賢者意，尚言執友欠龍頭。"]'),
('f71d1748-9f8a-4f92-b490-682e6517be47','和伯常自郢州見寄','司馬光','宋','宋诗','song-poetry','','[]','西郊去歳揖行人，柳暗花濃又一春。',64,'全唐诗/poet.song.30000.json','["西郊去歳揖行人，柳暗花濃又一春。", "坐想高風清入骨，沉吟佳句健生神。", "潺湲杳靄煙波古，散誕逍遙興趣新。", "應笑洛陽車馬道，緇衣未免化紅塵。"]'),
('1457845e-adbc-40cb-ba6d-98afac2c0eeb','和潞公行及白馬寺得留守相公書云名園例惜好花以候同賞詩二章  其一','司馬光','宋','宋诗','song-poetry','','[]','雲漢成章湛露晞，都門宴餞羽觴飛。',32,'全唐诗/poet.song.30000.json','["雲漢成章湛露晞，都門宴餞羽觴飛。", "謝安不復東山去，爭似阿衡得謝歸。"]'),
('b71041d0-68ad-4566-952e-d0eb683bd421','和潞公行及白馬寺得留守相公書云名園例惜好花以候同賞詩二章  其二','司馬光','宋','宋诗','song-poetry','','[]','相國東郊迓帝師，油幢交映碧參差。',32,'全唐诗/poet.song.30000.json','["相國東郊迓帝師，油幢交映碧參差。", "都人共喜安輿到，正是餘花可惜時。"]'),
('7195cd4a-f83b-4d15-b4b9-deedd16f3b4b','和子華喜潞公入覲歸置酒遊諸園賞牡丹','司馬光','宋','宋诗','song-poetry','','[]','介圭成禮下中天，春物雖闌色尚妍。',64,'全唐诗/poet.song.30000.json','["介圭成禮下中天，春物雖闌色尚妍。", "園吏望塵皆闢戶，肩輿回步即開筵。", "波濤凌亂鞾旁錦，風雨縱横撥底絃。", "洛邑衣冠陪後乘，尋花載酒願年年。"]'),
('f983b9af-370b-49bd-b596-2dec5f1af3da','陪致政開府太師留守相公致政內翰燕集輙歌盛美爲三公壽皆用公字爲韻 太師','司馬光','宋','宋诗','song-poetry','','[]','獨佐成康世，高年有畢公。',48,'全唐诗/poet.song.30000.json','["獨佐成康世，高年有畢公。", "神心降維嶽，龜兆告非熊。", "黄閣遵成範，太常書茂功。", "歸來保眉壽，恩禮享優隆。"]'),
('14dafbad-37a8-4fe0-9826-ef5f81287afa','陪致政開府太師留守相公致政內翰燕集輙歌盛美爲三公壽皆用公字爲韻 相公','司馬光','宋','宋诗','song-poetry','','[]','東閣延髦士，西都守别宮。',48,'全唐诗/poet.song.30000.json','["東閣延髦士，西都守别宮。", "不忘如衞武，難老似僖公。", "位貌今雖遠，官僚舊忝同。", "開懷盡卮酒，足以厚時風。"]'),
('07191555-db39-4e8e-be4e-96db1fefc4ce','陪致政開府太師留守相公致政內翰燕集輙歌盛美爲三公壽皆用公字爲韻 內翰','司馬光','宋','宋诗','song-poetry','','[]','眉似高僧秀，顔如童子紅。',48,'全唐诗/poet.song.30000.json','["眉似高僧秀，顔如童子紅。", "忠純汲長孺，高潔夏黄公。", "矯矯遼東鸖，冥冥塞北鴻。", "自誇新酒量，像想百分空。"]'),
('40fe28a9-2393-4836-83ea-c79aab7f4ef9','景仁將歸穎昌輙爲詩二十韻紀贈','司馬光','宋','宋诗','song-poetry','','[]','秀發西南美，挺生河嶽靈。',240,'全唐诗/poet.song.30000.json','["秀發西南美，挺生河嶽靈。", "雕龍蔚文采，老鸖瑩儀形。", "落筆高時雋，飛緌侍帝庭。", "英聲軼雲漢，遠勢擊滄溟。", "苦節專憂國，嘉謀毎據經。", "温雖比圭璧，直不避雷霆。", "道勝軒裳薄，神和氣體寧。", "忠誠懷畎畝，樂事寄林坰。", "藻鑒評隨月，過從德應星。", "苦吟金出礦，確論木銜釘。", "賤子叨流輩，高風仰典刑。", "巨川容滴水，餘景借流螢。", "久别眉俱白，重來眼更青。", "淹留弦與晦，遊集醉還醒。", "有酒須相就，無歌不共聼。", "奇花喧夕市，疊鼓咽春亭。", "揚袂行辭洛，回車去望陘。", "往還天表鴈，離合浪間萍。", "異日期同傳，窮泉約互銘。", "古今難得事，交分保頽齡。"]'),
('da7d2434-8b09-4378-9aaa-b2ef3515d5bd','復用三公燕集韻酬子駿堯夫','司馬光','宋','宋诗','song-poetry','','[]','官閑虚室白，粟飽太倉紅。',48,'全唐诗/poet.song.30000.json','["官閑虚室白，粟飽太倉紅。", "朝夕掃三徑，往來從二公。", "蒹葭徒倚玉，燕雀豈知鴻。", "相遇輙同醉，惟愁樽酒空。"]'),
('6a4d1f10-2b7b-476b-b62d-46e97b81ed2f','和吳朝議同年謝光與景仁同年見過','司馬光','宋','宋诗','song-poetry','','[]','結綬東堂同發策，白頭相值益相親。',64,'全唐诗/poet.song.30000.json','["結綬東堂同發策，白頭相值益相親。", "却思景祐無多日，共見元豐有幾人。", "天下高名歸廣受，古来交道重雷陳。", "謝公身老才方壯，落筆成章字字新。"]'),
('03b69a6d-4a15-4be6-82fb-bd53a5eb7169','伏蒙留守相公賜示陪太師潞公東田宴集詩輙敢屬和','司馬光','宋','宋诗','song-poetry','','[]','舞雩新雨浹公田，水滿東溪上下天。',64,'全唐诗/poet.song.30000.json','["舞雩新雨浹公田，水滿東溪上下天。", "行徑乍迂初見筍，浮舟正好未生蓮。", "絃收裂帛胡琴闋，袖結清風楚舞妍。", "相國火城光滿路，夜歸不假玉蟾圓。"]'),
('aabe13a3-87e7-498a-8c47-50dc5a8129fa','效趙學士體成口號十章獻開府太師  其一','司馬光','宋','宋诗','song-poetry','','[]','都人共喜太師回，比戶爭迎不得催。',32,'全唐诗/poet.song.30000.json','["都人共喜太師回，比戶爭迎不得催。", "正值土樓灘水淺，大家出手挽船来。"]'),
('4ccafe01-f16a-4527-8d4b-11e2eaf5af06','效趙學士體成口號十章獻開府太師  其二','司馬光','宋','宋诗','song-poetry','','[]','東郊車馬走紅塵，城外多於城裏人。',32,'全唐诗/poet.song.30000.json','["東郊車馬走紅塵，城外多於城裏人。", "誰信今朝還政後，過如前歳下車新。"]'),
('e5c344f9-d50e-40c3-a890-f9888de802f6','效趙學士體成口號十章獻開府太師  其三','司馬光','宋','宋诗','song-poetry','','[]','歸来甫可及春殘，丞相頻邀賞牡丹。',32,'全唐诗/poet.song.30000.json','["歸来甫可及春殘，丞相頻邀賞牡丹。", "遠處名園多不到，尊前日獻百餘盤。"]'),
('dbc5cd51-319d-4d65-bdc6-0caccb246119','效趙學士體成口號十章獻開府太師  其四','司馬光','宋','宋诗','song-poetry','','[]','洛陽風俗重繁華，荷擔樵夫亦戴花。',32,'全唐诗/poet.song.30000.json','["洛陽風俗重繁華，荷擔樵夫亦戴花。", "貪看二公同宴會，遊人昏黑忘還家。"]'),
('f8940abf-50d6-4194-ae3e-e8fb4a3846d0','效趙學士體成口號十章獻開府太師  其五','司馬光','宋','宋诗','song-poetry','','[]','公廚敕許釀芳樽，屢喚賓朋醉後園。',32,'全唐诗/poet.song.30000.json','["公廚敕許釀芳樽，屢喚賓朋醉後園。", "謔浪略無名位間，誰人知道太師尊。"]'),
('b59d6182-af1e-41de-9401-1bc1fe260eb7','效趙學士體成口號十章獻開府太師  其六','司馬光','宋','宋诗','song-poetry','','[]','過春稀復到諸園，厭苦終朝鼓吹喧。',32,'全唐诗/poet.song.30000.json','["過春稀復到諸園，厭苦終朝鼓吹喧。", "招得老僧江外至，啜茶揮麈話松軒。"]'),
('a8042dbd-72fd-4286-934a-09a94a67e7b3','效趙學士體成口號十章獻開府太師  其七','司馬光','宋','宋诗','song-poetry','','[]','東田小籍選新聲，歌吹胡琴色色精。',32,'全唐诗/poet.song.30000.json','["東田小籍選新聲，歌吹胡琴色色精。", "客少有時全不用，天然水竹湛餘清。"]'),
('7b3b9aae-063c-465d-960a-3bef5b43f017','效趙學士體成口號十章獻開府太師  其八','司馬光','宋','宋诗','song-poetry','','[]','首夏清和新雨晴，綠莎細軟不妨行。',32,'全唐诗/poet.song.30000.json','["首夏清和新雨晴，綠莎細軟不妨行。", "園夫遮道白何事，梔子花開斑笋生。"]'),
('9ebf710e-eae9-432d-9ece-5e3aca3e5ab8','效趙學士體成口號十章獻開府太師  其九','司馬光','宋','宋诗','song-poetry','','[]','矮帽長絛紫縠衫，朱門深静似重巖。',32,'全唐诗/poet.song.30000.json','["矮帽長絛紫縠衫，朱門深静似重巖。", "莫言永日渾無事，種藥移花一一監。"]'),
('f9e0d278-0186-478c-91a3-fb94644a99e2','效趙學士體成口號十章獻開府太師  其一○','司馬光','宋','宋诗','song-poetry','','[]','八十聰明強徤身，况從壯歳秉鴻鈞。',32,'全唐诗/poet.song.30000.json','["八十聰明強徤身，况從壯歳秉鴻鈞。", "功名富貴古亦有，無事歸来能幾人。"]'),
('7ed3561f-0199-47be-a5cb-dcd4d105cff9','和潞公招堯夫不至','司馬光','宋','宋诗','song-poetry','','[]','東閣樽罍招共飲，後房羅綺約同觀。',32,'全唐诗/poet.song.30000.json','["東閣樽罍招共飲，後房羅綺約同觀。", "既無薊子分身術，須欠車公一座歡。"]'),
('a925c096-ed46-45ed-8fa9-9c93ce72a341','和子華招潞公暑飲','司馬光','宋','宋诗','song-poetry','','[]','朱門近在府園東，杖屨過從跬步中。',64,'全唐诗/poet.song.30000.json','["朱門近在府園東，杖屨過從跬步中。", "避暑連翩投轄宴，析酲蕭灑滿襟風。", "閑来高韻渾如鸖，醉裏朱顔却變童。", "剪燭添香歡未極，但驚銅漏太匆匆。"]'),
('c3f7bc1e-9b67-47ee-9071-3b0dd2fa1f51','再和伯常見寄','司馬光','宋','宋诗','song-poetry','','[]','誅茅宋玉宅邊人，知醉宜城幾甕春。',64,'全唐诗/poet.song.30000.json','["誅茅宋玉宅邊人，知醉宜城幾甕春。", "細雨短蓑漁向市，孤村極浦鼓迎神。", "徧遊七澤身忘倦，更賦千篇意轉新。", "不必滄浪羡清泚，曏来纓上已無塵。"]'),
('d051001e-eae4-4e39-8caf-566936238189','再和秉國約遊石淙','司馬光','宋','宋诗','song-poetry','','[]','上國分攜十五秋，未嘗偶坐捧茶甌。',32,'全唐诗/poet.song.30000.json','["上國分攜十五秋，未嘗偶坐捧茶甌。", "石淙今會須如約，彼此霜毛各滿頭。"]'),
('5a595331-1fb4-4b57-b6ab-92ca371f14de','送堯夫知河中府二首  其一','司馬光','宋','宋诗','song-poetry','','[]','耆老承風舊，絲綸錫命新。',48,'全唐诗/poet.song.30000.json','["耆老承風舊，絲綸錫命新。", "展禽安屢黜，原憲樂常貧。", "執志窮通壹，論交表裏真。", "但祈深自重，膏澤望斯民。"]'),
('a5bd485b-9d46-4ee5-a96f-823abf8cb505','送堯夫知河中府二首  其二','司馬光','宋','宋诗','song-poetry','','[]','河抱城根曲，山侵地勢斜。',48,'全唐诗/poet.song.30000.json','["河抱城根曲，山侵地勢斜。", "周餘古樓觀，舜俗舊人家。", "回首遊從闊，装懷牒訴譁。", "何時重載酒，同醉洛陽花。"]'),
('48546fd3-ad9d-4c1a-84ce-61678b47f77d','席君從於洛城種金橘今秋始結六實以其四獻開府太師招三客以賞之留守相公時賦詩以紀奇事光竊不自揆輙依高韻繼成五章  其一','司馬光','宋','宋诗','song-poetry','','[]','宜春果結洛陽枝，正遇耆明會客時。',32,'全唐诗/poet.song.30000.json','["宜春果結洛陽枝，正遇耆明會客時。", "更引輕舟倚蘆岸，香秔鮮鱠雅相宜。"]'),
('2de73e28-d0be-4c94-a2ff-8825cf51a8ed','席君從於洛城種金橘今秋始結六實以其四獻開府太師招三客以賞之留守相公時賦詩以紀奇事光竊不自揆輙依高韻繼成五章  其二','司馬光','宋','宋诗','song-poetry','','[]','圓小香黄珠顆垂，結成洛邑重霜時。',32,'全唐诗/poet.song.30000.json','["圓小香黄珠顆垂，結成洛邑重霜時。", "相公和氣陶羣物，不是寒溫變土宜。"]'),
('5a96cf3b-79db-46da-8eca-abd91c2c613f','席君從於洛城種金橘今秋始結六實以其四獻開府太師招三客以賞之留守相公時賦詩以紀奇事光竊不自揆輙依高韻繼成五章  其三','司馬光','宋','宋诗','song-poetry','','[]','君從好事不知疲，種子成株凡幾時。',32,'全唐诗/poet.song.30000.json','["君從好事不知疲，種子成株凡幾時。", "摘獻帝師三取二，自嘗兩顆且隨宜。"]'),
('607c2637-1791-4175-993f-ae10ace060e3','席君從於洛城種金橘今秋始結六實以其四獻開府太師招三客以賞之留守相公時賦詩以紀奇事光竊不自揆輙依高韻繼成五章  其四','司馬光','宋','宋诗','song-poetry','','[]','物不須多且賞奇，禦寒相見結庵時。',32,'全唐诗/poet.song.30000.json','["物不須多且賞奇，禦寒相見結庵時。", "江南江北徒虚語，盡信前書是不宜。"]'),
('c125c734-e359-4810-a093-5f9ad3dbf281','席君從於洛城種金橘今秋始結六實以其四獻開府太師招三客以賞之留守相公時賦詩以紀奇事光竊不自揆輙依高韻繼成五章  其五','司馬光','宋','宋诗','song-poetry','','[]','弊居橘亦自南移，愛護栽培費歳時。',32,'全唐诗/poet.song.30000.json','["弊居橘亦自南移，愛護栽培費歳時。", "前此實成酸苦甚，應由與德不相宜。"]'),
('d0ca4b5a-2cc6-49df-ae0f-0cd3509cee1f','和留守相公九月八日與潞公宴趙令園有懷去年與景仁秉國遊賞','司馬光','宋','宋诗','song-poetry','','["\u897f\u6e56"]','今歳台星聚洛中，甘棠前後雨陰濃。',64,'全唐诗/poet.song.30000.json','["今歳台星聚洛中，甘棠前後雨陰濃。", "英辭唱和詩千首，高宴遊陪祿萬鍾。", "木末霜繁花未落，雲間字小鴈相從。", "西湖在望親朋遠，節物那堪處處逢。"]'),
('7a165824-dea3-4928-98ae-0d3f813d8ae9','和留守相公寄酒與景仁','司馬光','宋','宋诗','song-poetry','','[]','想對白衣初滿傾，執杯未飲已詩成。',32,'全唐诗/poet.song.30000.json','["想對白衣初滿傾，執杯未飲已詩成。", "懷賢孤坐悄無語，不是朝来困宿酲。"]'),
('670d54ea-4953-4c6c-89d3-fdcd2829d8bd','和秉國芙蓉五章  其一','司馬光','宋','宋诗','song-poetry','','[]','清曉霜華漫自濃，獨憑愛日飬殘紅。',32,'全唐诗/poet.song.30000.json','["清曉霜華漫自濃，獨憑愛日飬殘紅。", "勸君秉燭須勤賞，閶闔難禁一夜風。"]'),
('971d901c-d58c-425f-824a-f45112bc9946','和秉國芙蓉五章  其二','司馬光','宋','宋诗','song-poetry','','[]','北方稀見誠奇物，筆界輕絲指捻紅。',32,'全唐诗/poet.song.30000.json','["北方稀見誠奇物，筆界輕絲指捻紅。", "楚蜀可憐人不賞，墻根屋角數無窮。"]'),
('c8f609b5-51d6-4845-ac20-259c6f9ba0ed','和秉國芙蓉五章  其三','司馬光','宋','宋诗','song-poetry','','[]','平昔低頭避桃李，英華今發歳云秋。',32,'全唐诗/poet.song.30000.json','["平昔低頭避桃李，英華今發歳云秋。", "盛時已過渾如我，醉舞狂歌插滿頭。"]'),
('f1c5fbfa-7669-4ee5-9153-a5adc5c6292c','和秉國芙蓉五章  其四','司馬光','宋','宋诗','song-poetry','','[]','後時獨立誠難事，猶賴階庭有菊叢。',32,'全唐诗/poet.song.30000.json','["後時獨立誠難事，猶賴階庭有菊叢。", "綽約霜前弄姿態，非如羣木萬株紅。"]'),
('ccb7ffe8-b414-43b8-bf2e-fb84ca8d8772','和秉國芙蓉五章  其五','司馬光','宋','宋诗','song-poetry','','[]','但見涉江求水際，豈知勝木采霜中。',32,'全唐诗/poet.song.30000.json','["但見涉江求水際，豈知勝木采霜中。", "微紅未肯全衰歇，正似酡顔鸖髪翁。"]'),
('b7a7b8b1-4480-4dfe-aba2-88487c95c3fd','安之朝議哀辭二首  其一','司馬光','宋','宋诗','song-poetry','','[]','場屋推聲價，朝紳仰典型。',48,'全唐诗/poet.song.30000.json','["場屋推聲價，朝紳仰典型。", "朱衣老卿列，白首戀親庭。", "舟壑一朝失，泉臺萬古扃。", "音容宛在目，爭免凈飄零。"]'),
('ba70a317-bf92-4ecb-a492-2831d505e9b4','安之朝議哀辭二首  其二','司馬光','宋','宋诗','song-poetry','','[]','樂易春陽暖，孤高秋氣清。',48,'全唐诗/poet.song.30000.json','["樂易春陽暖，孤高秋氣清。", "老惟知自適，貧不問爲生。", "京兆開阡貴，延陵題墓榮。", "如何帝師筆，純孝紀名卿。"]'),
('062a5804-2a93-472d-96fe-0273fafc9d25','和堯夫見寄  其一','司馬光','宋','宋诗','song-poetry','','[]','志趣苦難合，倀倀何所依。',48,'全唐诗/poet.song.30000.json','["志趣苦難合，倀倀何所依。", "逢君始相照，知我信爲稀。", "忽報除書下，徒瞻征蓋飛。", "相思千里遠，洛浦又春歸。"]'),
('b9056a2d-d577-4ef2-a0b5-4169392c9308','和堯夫見寄  其二','司馬光','宋','宋诗','song-poetry','','[]','仁政如慈父，蒲人得所依。',48,'全唐诗/poet.song.30000.json','["仁政如慈父，蒲人得所依。", "教條前後接，風迹古今稀。", "試郡纔書最，還朝必奮飛。", "西臺舊班列，猶望繡衣歸。"]'),
('e7060128-99d8-4587-883d-124aebb6bd7f','華嚴真師以詩見貺聊成二章紀其趣尚  其一','司馬光','宋','宋诗','song-poetry','','[]','知足隨緣處處安，一身溫飽不爲難。',32,'全唐诗/poet.song.30000.json','["知足隨緣處處安，一身溫飽不爲難。", "禪房窄小纔容榻，此外從他世界寛。"]'),
('5a5a120a-dd21-4ca4-b521-42c2fe8d3c03','華嚴真師以詩見貺聊成二章紀其趣尚  其二','司馬光','宋','宋诗','song-poetry','','[]','素髪青眸七十餘，未嘗遊學只安居。',32,'全唐诗/poet.song.30000.json','["素髪青眸七十餘，未嘗遊學只安居。", "旁無几杖身輕健，應爲心閑得自如。"]'),
('b634438b-c729-4ece-bb40-b4158140ed00','和子華過王帥家見梅花盛開呈君實子駿兼簡堯夫','司馬光','宋','宋诗','song-poetry','','[]','去年與客盡清歡，今日重来立馬看。',32,'全唐诗/poet.song.30000.json','["去年與客盡清歡，今日重来立馬看。", "猶是攜觴同醉在，只愁風雨横相干。"]'),
('1e7eb2c8-38fa-4d6d-b759-38280f462133','和張伯常賀遷資政','司馬光','宋','宋诗','song-poetry','','[]','不駕使車開漢關，不棲巖穴鍊金丹。',64,'全唐诗/poet.song.30000.json','["不駕使車開漢關，不棲巖穴鍊金丹。", "豈無開徑三人友，分著垂緌五寸冠。", "坐飽太倉猶自愧，謬躋秘殿益難安。", "願同野老嬉堯壤，長守先生苜蓿盤。"]'),
('022a0c54-caaa-46c2-ae9b-a78e4355f097','又書一絕戲呈','司馬光','宋','宋诗','song-poetry','','[]','伯常遠自郢中回，喜與愁心相繼来。',32,'全唐诗/poet.song.30000.json','["伯常遠自郢中回，喜與愁心相繼来。", "幸得蒹葭依玉樹，愁將瓦礫報瓊瑰。"]'),
('7b449e98-040e-4083-a281-2ec2b929f369','又和南園真率會見贈','司馬光','宋','宋诗','song-poetry','','[]','白頭難入少年場，林下相招莫笑狂。',64,'全唐诗/poet.song.30000.json','["白頭難入少年場，林下相招莫笑狂。", "綠篠影侵棋局暗，黄梅花漬酒卮香。", "任真自愧殽羞薄，假寐初便枕簞凉。", "酬應詩豪困牽率，從来懶放似稽康。"]'),
('f9170f37-432b-4fc7-994e-82c5f89ec01e','春日思景仁','司馬光','宋','宋诗','song-poetry','','[]','去歳洛城中，嬉遊處處同。',48,'全唐诗/poet.song.30000.json','["去歳洛城中，嬉遊處處同。", "從離崿嶺北，常夢潩泉東。", "草遶春街碧，花繁夕市紅。", "臨風默惆悵，想像白眉翁。"]'),
('29a3d07c-ebda-406d-8c08-6fc712bbed65','神宗皇帝挽詞五首  其一','司馬光','宋','宋诗','song-poetry','','[]','決事神明速，任人金石堅。',48,'全唐诗/poet.song.30000.json','["決事神明速，任人金石堅。", "天機先兆朕，聖度藴淵泉。", "仁義生知性，恩威獨化權。", "乾坤無毁息，長與大名傳。"]'),
('ea8e89dd-d04a-4fc4-9755-945fe6eaa40e','神宗皇帝挽詞五首  其二','司馬光','宋','宋诗','song-poetry','','[]','聽政涉中昃，觀書達夜分。',48,'全唐诗/poet.song.30000.json','["聽政涉中昃，觀書達夜分。", "周王忘自逸，漢祖不知勤。", "棣萼因心友，雲章落筆文。", "它年紬石室，光大繼皇墳。"]'),
('4c6d293a-371e-43de-b50e-106563915140','神宗皇帝挽詞五首  其三','司馬光','宋','宋诗','song-poetry','','[]','至德成無象，徽名避不居。',48,'全唐诗/poet.song.30000.json','["至德成無象，徽名避不居。", "期門弋獵絕，步輦宴遊疏。", "錢列金釭暗，兵嚴武帳虚。", "蓬莱日晏仗，猶望駕宮車。"]'),
('ebc1ffaa-e116-4dc5-808c-e9014ac676eb','神宗皇帝挽詞五首  其四','司馬光','宋','宋诗','song-poetry','','[]','鼇禁叨承詔，金華侍執經。',48,'全唐诗/poet.song.30000.json','["鼇禁叨承詔，金華侍執經。", "微生輕草芥，聖澤闊滄溟。", "鹿性安林野，葵心注闕庭。", "堯雲不可望，白首涕飄零。"]'),
('31844d15-a465-470a-98c4-d3ab7b939af6','神宗皇帝挽詞五首  其五','司馬光','宋','宋诗','song-poetry','','[]','式道清行馬，靈輴下陛簾。',48,'全唐诗/poet.song.30000.json','["式道清行馬，靈輴下陛簾。", "雲奔同軓集，雨泣兆民瞻。", "石闕蒼煙暝，松門白露霑。", "載弓徒隕絕，無計附龍髯。"]'),
('9ce8eeeb-688d-419a-8437-7a35ccf64b58','北京留守王太師挽歌詞二首  其一','司馬光','宋','宋诗','song-poetry','','[]','盧肇時推重，終軍衆共賢。',48,'全唐诗/poet.song.30000.json','["盧肇時推重，終軍衆共賢。", "何如奪標日，未及弃繻年。", "官歷清塗徧，名居美事先。", "人間福有五，視履豈非全。"]'),
('0fb4e5b7-eee7-4213-9858-e49df24ce044','北京留守王太師挽歌詞二首  其二','司馬光','宋','宋诗','song-poetry','','[]','昔日程文士，中間侍坐賓。',48,'全唐诗/poet.song.30000.json','["昔日程文士，中間侍坐賓。", "遊陪慚晚輩，待遇過它人。", "方嘆龍門遠，俄驚馬鬛新。", "西園行樂處，引領但霑巾。"]'),
('cc40067e-c2e8-43d1-b558-369d67f4a35f','超然臺寄子瞻學士','司馬光','宋','宋诗','song-poetry','','[]','使君仁智心，濟以忠義膽。',144,'全唐诗/poet.song.30000.json','["使君仁智心，濟以忠義膽。", "嬰兒手自撫，猛虎鬚可攬。", "出牧爲龔黄，廷議乃陵黯。", "萬鍾何所加，甔石何所减。", "用此始優游，當官免阿諂。", "曏時守高密，民安吏手斂。", "乘閑爲小臺，節物得周覽。", "容膝常有餘，縱目皆不掩。", "山川遠布張，花卉近綴點。", "筵賓殽核旅，燕居兵衛儼。", "比之在陋巷，爲樂亦何歉。", "可笑夸者愚，中天猶慘慘。"]'),
('48916295-e676-4e51-bb65-08943d241184','今古路行','司馬光','宋','宋诗','song-poetry','','[]','出門道路多，縱横不我測。',216,'全唐诗/poet.song.30000.json','["出門道路多，縱横不我測。", "我今欲遠行，須問曾行客。", "徐徐逢路人，咨問青松側。", "客曰君何往，答曰遊京邑。", "客乃指要路，而言行有益。", "古路雖大道，不如今路直。", "但行今人路，猶如假羽翼。", "彼客别我去，獨自踟躕立。", "爲見今古路，無乃須差忒。", "今路足輪蹄，古路饒荆棘。", "欲行今人路，恐背古人迹。", "擬行古人路，今人笑迂僻。", "又擬不出門，奈有饑寒逼。", "哀哀於此情，悠悠蒼天色。", "不避今人嫌，路須行古陌。", "古陌雖然遠，且保無厥失。", "勉哉自勉哉，前古難知識。", "不復見楊朱，萬古凝愁魄。"]'),
('07cc466e-ea43-4958-b98b-3f77961ffcbe','憶同尋上陽故宮路','司馬光','宋','宋诗','song-poetry','','[]','上陽門外雲連草，車馬遙遙往來道。',64,'全唐诗/poet.song.30000.json','["上陽門外雲連草，車馬遙遙往來道。", "昔王遊豫幾何年，今人豈識當時好。", "明珠翠羽已成塵，道上行人幾番老。", "當時秋天落宮槐，今此婆娑皆合抱。"]'),
('4d6cd7bc-b705-42d5-8405-8cce4aefb779','和陳殿丞芍藥','司馬光','宋','宋诗','song-poetry','','[]','化工餘巧惜春殘，更發濃芳繼牡丹。',64,'全唐诗/poet.song.30000.json','["化工餘巧惜春殘，更發濃芳繼牡丹。", "檀點藏心殷勝纈，異香迎鼻酷如蘭。", "瓊樓窈窕仙家宅，雲葉低垂醉裏冠。", "自有殊功存藥錄，不當獨取鄭詩看。"]'),
('572655de-b40f-4f20-9147-be5f3c8b97a2','到任明年旨罷官有作','司馬光','宋','宋诗','song-poetry','','[]','恬然如一夢，分竹守長安。',48,'全唐诗/poet.song.30000.json','["恬然如一夢，分竹守長安。", "去日冰猶壯，歸時花未闌。", "風光經目少，惠愛及民難。", "可惜終南色，臨行子細看。"]'),
('90ee3a0f-2ffe-4bec-8d07-801d425ae497','和景文議交絕句','司馬光','宋','宋诗','song-poetry','','[]','邇來友義漸隳頽，直諒多聞貴不回。',32,'全唐诗/poet.song.30000.json','["邇來友義漸隳頽，直諒多聞貴不回。", "勢利相交何足道，已知餘耳愧陳雷。"]'),
('e2d58285-f481-4aa0-b311-1fe3d6a1e3c5','御宴送李宣徽知真定府口號','司馬光','宋','宋诗','song-poetry','','[]','匈奴舊畏李將軍，今日重來幾代孫。',64,'全唐诗/poet.song.30000.json','["匈奴舊畏李將軍，今日重來幾代孫。", "旗尾飄揚山燒裂，馬啼騰踏塞塵昏。", "降王稽顙朝南闕，天子垂衣御北門。", "幕府事閑刁斗靜，碧潭佳景日開樽。"]'),
('167b2250-b471-4a3c-8534-ba1d5c7e8ed3','慶文公八十會口號','司馬光','宋','宋诗','song-poetry','','[]','元勛茂德古無倫，海內高閑第一人。',64,'全唐诗/poet.song.30000.json','["元勛茂德古無倫，海內高閑第一人。", "台席已酬調鼎志，磻溪還作釣魚身。", "師臣首冠三旌貴，歲曆行開九十新。", "願過期頤躋上壽，飛觴四十有餘春。"]'),
('1409bc46-771c-4675-ba3b-fd6f10fbb9be','別一章改韻同五詩呈堯夫','司馬光','宋','宋诗','song-poetry','','[]','家雖在城闕，蕭瑟似山阿。',48,'全唐诗/poet.song.30000.json','["家雖在城闕，蕭瑟似山阿。", "遠去名利窟，自稱安樂窩。", "雲歸白石洞，鶴立碧松柯。", "得喪非吾事，何須更寤歌。"]'),
('398c24b3-8d47-43fd-a06c-66eefed412e8','和堯夫先生相招遊夏圃','司馬光','宋','宋诗','song-poetry','','[]','野迥秋光滿，逕微朝露寒。',24,'全唐诗/poet.song.30000.json','["野迥秋光滿，逕微朝露寒。", "登高與行遠，餘力尚桓桓。"]'),
('be28cde8-b181-4f53-8d9d-187b7f88f9cb','酬堯夫招看牡丹  其一','司馬光','宋','宋诗','song-poetry','','[]','君家牡丹深淺紅，二十四枝爲一叢。',32,'全唐诗/poet.song.30000.json','["君家牡丹深淺紅，二十四枝爲一叢。", "不唯春光占七八，才華自是詩人雄。"]'),
('bcbfa562-6611-4af8-86d7-0e66f5c1e043','酬堯夫招看牡丹  其二','司馬光','宋','宋诗','song-poetry','','[]','君家牡丹今盛開，二十四枝爲一栽。',32,'全唐诗/poet.song.30000.json','["君家牡丹今盛開，二十四枝爲一栽。", "主人果然青眼待，正忙亦須偷暇來。"]'),
('fbfec9b9-bc13-4969-9821-7f42643b60b3','走筆和君錫堯夫','司馬光','宋','宋诗','song-poetry','','[]','先生洛社坐忘機，大尹朝天去佐時。',32,'全唐诗/poet.song.30000.json','["先生洛社坐忘機，大尹朝天去佐時。", "今日梅花浮別酒，青雲早晚重來披。"]'),
('fa3fe825-4096-4a4a-804e-77a25c5d024a','和堯夫首尾吟','司馬光','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，安樂窩中無所爲。',64,'全唐诗/poet.song.30000.json','["堯夫非是愛吟詩，安樂窩中無所爲。", "古道白頭無外用，今時青眼幾人知。", "嵩山洛水長相見，秋月春風不失期。", "筋力雖衰才思壯，遞年比較未嘗虧。"]'),
('3ea91fbb-e87f-4c26-9762-4b06a8786f61','居洛初夏作','司馬光','宋','宋诗','song-poetry','','["\u590f\u5929", "\u548f\u7269", "\u5199\u666f", "\u82b1", "\u548f\u7269\u8bd7", "\u8a00\u5fd7"]','四月清和雨乍晴，南山當戶轉分明。',32,'全唐诗/poet.song.30000.json','["四月清和雨乍晴，南山當戶轉分明。", "更無柳絮隨風起，惟有葵花向日傾。"]'),
('6a952afd-88c4-462a-94a6-de2fb3660395','集句詩','司馬光','宋','宋诗','song-poetry','','[]','年去年來來去忙，暫偷閑臥老僧床。',32,'全唐诗/poet.song.30000.json','["年去年來來去忙，暫偷閑臥老僧床。", "驚回一覺游仙夢，又逐流鶯過短牆。"]'),
('028e3bc3-a27b-4fb2-97b2-b87319c031d1','雙竹','司馬光','宋','宋诗','song-poetry','','[]','但有歲寒心，兩三竿也足。',24,'全唐诗/poet.song.30000.json','["但有歲寒心，兩三竿也足。", "虬騰雙角直，鯨噴兩鬚長。"]'),
('4980ebfd-4dfe-41bd-b244-3e3737f3cf01','御筵送李宣徽知真定府','司馬光','宋','宋诗','song-poetry','','[]','秋風蕭瑟引華旌，祖宴高張出斗城。',64,'全唐诗/poet.song.30000.json','["秋風蕭瑟引華旌，祖宴高張出斗城。", "玉饌芳菲羅百鐵，繡衣照耀擁千兵。", "驪歌未闋長楊苑，騎吹先臨細柳營。", "雨露醲恩何以報，沙場不惜樹功名。"]'),
('e6ef683c-a1dc-47dc-9269-bb2162df3500','睢陽五老圖','司馬光','宋','宋诗','song-poetry','','[]','圖謀已就樂時閑，曉向田園喜脫冠。',64,'全唐诗/poet.song.30000.json','["圖謀已就樂時閑，曉向田園喜脫冠。", "心志不灰猶有策，星長還在尚無桓。", "朝陽鳴鳳身輕暖，赴壑剛蛇齒健寒。", "儀表珍藏傳不朽，每於清士敬持看。"]'),
('29f7fbeb-9864-4edf-b417-1090d40f8a3a','悼靜照堂僧','司馬光','宋','宋诗','song-poetry','','[]','寶閣灰寒靜照新，馬啼從此踏京塵。',64,'全唐诗/poet.song.30000.json','["寶閣灰寒靜照新，馬啼從此踏京塵。", "金門乞得詩千首，蕭寺歸時老一身。", "弟子去來渾領袖，交朋存歿半簪紳。", "西風又剪梧桐葉，不見蒲團舊主人。"]'),
('9dc851be-71cd-4d41-8113-f229ad4ff31d','次韻謝杜祁公借觀五老圖','司馬光','宋','宋诗','song-poetry','','[]','脫遺軒冕就安閑，笑傲丘園縱倒冠。',64,'全唐诗/poet.song.30000.json','["脫遺軒冕就安閑，笑傲丘園縱倒冠。", "白髮憂民雖種種，丹心許國尚桓桓。", "鴻冥得路高難慕，松老無風韻自寒。", "聞說優遊多唱和，新篇何惜畫圖看。"]'),
('44de3199-2929-48e0-9dd7-7ac238d57f0c','句  其一','司馬光','宋','宋诗','song-poetry','','[]','清茶淡話難逢友，濁歌狂歌易得朋。',16,'全唐诗/poet.song.30000.json','["清茶淡話難逢友，濁歌狂歌易得朋。"]'),
('c5eb10c4-90d8-4dfd-9a32-7ef2281a679e','句  其二','司馬光','宋','宋诗','song-poetry','','[]','不肯那錢買珠翠，任教堆插階前菊。',16,'全唐诗/poet.song.30000.json','["不肯那錢買珠翠，任教堆插階前菊。"]'),
('dca6d512-67c9-4eb4-9651-b9902e4e85e9','句  其三','司馬光','宋','宋诗','song-poetry','','[]','藏鬮新度臘，習舞競裁衣。',12,'全唐诗/poet.song.30000.json','["藏鬮新度臘，習舞競裁衣。"]'),
('c1bd879d-8e83-4405-9d05-11270f696af8','句  其四','司馬光','宋','宋诗','song-poetry','','[]','不知藏在何人手，卻向尊前鬥弄拳。',16,'全唐诗/poet.song.30000.json','["不知藏在何人手，卻向尊前鬥弄拳。"]'),
('21626b08-76de-4619-a1d5-5acf77073a30','句  其五','司馬光','宋','宋诗','song-poetry','','[]','一朝雲路果然登，姓名亞等呼先輩。',16,'全唐诗/poet.song.30000.json','["一朝雲路果然登，姓名亞等呼先輩。"]'),
('a88a23f0-4d27-4808-a1c2-748d6cf1a159','句  其六','司馬光','宋','宋诗','song-poetry','','[]','初時被目爲迂叟，近日蒙呼作隱人。',16,'全唐诗/poet.song.30000.json','["初時被目爲迂叟，近日蒙呼作隱人。"]'),
('e32b3b17-2ae2-42de-9a93-543330530185','句  其七','司馬光','宋','宋诗','song-poetry','','[]','蟬聲若喚人。',6,'全唐诗/poet.song.30000.json','["蟬聲若喚人。"]'),
('42c8cd93-d373-46e3-8ec1-0df107088f0b','句  其八','司馬光','宋','宋诗','song-poetry','','[]','薄梗任飄流。',6,'全唐诗/poet.song.30000.json','["薄梗任飄流。"]'),
('9160ebbe-f55d-4e5d-97eb-034999bae1e8','句  其九','司馬光','宋','宋诗','song-poetry','','[]','霜花錯節開。',6,'全唐诗/poet.song.30000.json','["霜花錯節開。"]'),
('3cb66fef-cbb6-49d8-b86d-f320c88220e6','句  其一○','司馬光','宋','宋诗','song-poetry','','[]','猶將談笑對風塵。',8,'全唐诗/poet.song.30000.json','["猶將談笑對風塵。"]'),
('69e6d19e-fa0e-4fa4-b81f-853cda52f895','句  其一一','司馬光','宋','宋诗','song-poetry','','[]','雨濕蓼花千穗紅。',8,'全唐诗/poet.song.30000.json','["雨濕蓼花千穗紅。"]'),
('f50076e3-dbbc-4dc3-bf89-892232a83c69','雜興三首  其一','鮮于侁','宋','宋诗','song-poetry','','[]','幽居觀物變，天道固盈虗。',60,'全唐诗/poet.song.30000.json','["幽居觀物變，天道固盈虗。", "炎取日方熾，微陰一已生。", "涼風動野草，桃李先飄零。", "蜩螗集高柳，絡緯響空庭。", "愁心獨耿耿，宵夢竟難成。"]'),
('dc5aed95-d893-4554-99ae-8de39e8f29bf','雜興三首  其二','鮮于侁','宋','宋诗','song-poetry','','[]','一氣斡元造，爲功未嘗煩。',60,'全唐诗/poet.song.30000.json','["一氣斡元造，爲功未嘗煩。", "羣生自委化，天地亦何言。", "鳬脛不可增，楮葉不可鐫。", "欲益固爲損，勞心非自然。", "不見平陽侯，醇酒聊終年。"]'),
('e7687181-4b8b-4bef-a609-ff08e37d8b16','雜興三首  其三','鮮于侁','宋','宋诗','song-poetry','','[]','三王貴養老，取重在乞言。',60,'全唐诗/poet.song.30000.json','["三王貴養老，取重在乞言。", "酒醴副佳餚，黄髪斯皤然。", "朝廷本忠厚，風俗亦變遷。", "豈意漢道微，侍中惟少年。", "耆舊無備問，李公所以難。"]'),
('e5dfc468-665c-4e35-932f-a62380dee42f','新堂夜坐月色皎然由連理亭信步庭中徘徊久之因爲五言一首','鮮于侁','宋','宋诗','song-poetry','','[]','秋風動微涼，天雨新霽後。',96,'全唐诗/poet.song.30000.json','["秋風動微涼，天雨新霽後。", "閒齋獨隱几，明月在高柳。", "振衣步庭下，顥氣入襟袖。", "天空雲漢明，隱約辨列宿。", "蒼蒼松檜上，零露飛欲流。", "脱葉滿閒園，繁華迨衰朽。", "清宵望蟾彩，宜付一杯酒。", "多病謝樽罍，城頭轉寒漏。"]'),
('9223e7dc-51d9-4733-9d64-a022f968201e','九誦 堯祠','鮮于侁','宋','宋诗','song-poetry','','[]','車轔轔兮廟堧，鼓坎坎兮祠下。',126,'全唐诗/poet.song.30000.json','["車轔轔兮廟堧，鼓坎坎兮祠下。", "竽琴兮並奏，潔時修兮虔祠事。", "瑤華爲饌兮沆瀣爲漿，象籩玉豆兮金鼎煇煌。", "海珍野蔌兮雜錯而致誠。", "神之來兮風雨蕭蕭，前驅於畢兮上有招搖。", "羽林爲衛兮虹霓爲旗，鳯凰左右兮擾伏蛟螭。", "神之降兮金輿，靈欣欣兮肸蠁。", "德難名兮覆燾，千萬年兮不忘。"]'),
('186617f3-f4a4-485e-a02f-d8d913923fb4','九誦 舜祠','鮮于侁','宋','宋诗','song-poetry','','[]','道歷山兮逶蛇，思古人兮感歎。',136,'全唐诗/poet.song.30000.json','["道歷山兮逶蛇，思古人兮感歎。", "並儲胥兮肅止，仰曾雲兮晻曖。", "獸何鳴兮林中，鳥何悲兮山上。", "木何爲兮不剪，草何爲兮茂暢。", "帝之神兮在天，帝之德兮在人。", "物具兮四海，心精兮一純。", "采秀實兮山間，摘其毛兮澗底。", "玉醴湛兮瓊茅，希修雜兮蘭茝。", "樂備兮九奏，鳯舞兮儀韶。", "人駿奔兮如在，君卒享兮神交。"]'),
('2cafe9f7-eea5-446e-b6df-78e683429a82','九誦 周公','鮮于侁','宋','宋诗','song-poetry','','[]','噫嗟兮文公，巋然兮秘宇。',228,'全唐诗/poet.song.30000.json','["噫嗟兮文公，巋然兮秘宇。", "悵王室兮多難，獨勤勞兮左右。", "四國流言兮冲人不知，東征問罪兮慆慆不歸。", "大電以風兮天威震驚，弁啓金縢兮衮衣有光。", "公之心兮大成文武，公之子兮建侯啓土。", "山川兮附庸，奄鳬繹兮龜蒙。", "萬子孫兮承祀，億兆人兮仰止。", "惟天子之歎嗟兮不復見於寤寐。", "何莽新之假攝兮文奸言而欺一世，造作詭故而戕劉兮亦亟殄宗而絕嗣。", "公之聖而德協天兮何妄人之輒自擬，俾其顛而不終兮天實表公衷而警後。", "肅進拜於廟堂兮宜奉時之牲酒。", "鼓鐘兮在宮，琴瑟兮在堂。", "神之格兮樂享，民欣欣兮不忘。"]'),
('17e81222-6dd1-4080-a3e1-e87fd13c488e','九誦 孔子','鮮于侁','宋','宋诗','song-poetry','','[]','曲阜兮遺墟，先師兮闕里。',248,'全唐诗/poet.song.30000.json','["曲阜兮遺墟，先師兮闕里。", "神彷彿兮如在，涕潺湲兮不已。", "窮天地兮一人，掲日月而照臨。", "生無萬乘之位兮三千之徒心服而四來。", "嗟愚陋之不明兮乃商賜之爲疑，羌紛紛其妄作兮悖道違義而弗自知。", "顧六藝之折衷兮取捨縱横而協於道，後世苟輕肆於胸臆兮必遽貽於詬病。", "三綱立而五教明兮實治世之宏矩，履厚地而戴高天兮胡一日之可捨，宜萬齡之廟貌兮春秋不乏其時祀。", "合仁義以爲冠兮結忠信而爲佩，集道德以爲裳兮服文章而爲带。", "列籩豆爲左右兮蘋藻牲牢而潔肥，酌玉醴以爲酒兮錯瓊瑤而爲粢。", "升堂而北面兮望冕旒之巍巍，惟神明之降鑒兮洞精神其來歆。"]'),
('2f664807-005c-490c-b00d-f39014552a2e','九誦 嶽神','鮮于侁','宋','宋诗','song-poetry','','[]','雲蓊蔚兮山之巓，瞻嶽靈兮望青天。',214,'全唐诗/poet.song.30000.json','["雲蓊蔚兮山之巓，瞻嶽靈兮望青天。", "嶄巖崷崪兮磅礴無垠，巄嵸嵂勃兮寧一以爲仁。", "草木雜而羅生兮人不可名，鳥獸蕃而走集兮虞不能知。", "因高錯事兮道此躋陛，登岱勒成兮胡爲而七十二君。", "齊余心兮不外，高余冠兮甚偉。", "擷芳杜兮爲衣，掇紫芝兮作佩。", "柏實兮松華，石髓兮蘭英。", "蕙肴陳兮玉案，明水湛兮清尊。", "誠拳拳兮不解，寐接神兮怳若有言。", "嵩高峻極兮生甫與申，周道將明兮宣以中興。", "水旱不常兮蟲螟以災，稼穡卒荒兮民生流離。", "勞來安集兮之子之功，祐此下民兮寧遺神羞。"]'),
('2adb733d-9d5b-4152-b98c-cf7e45b69c3c','九誦 河伯','鮮于侁','宋','宋诗','song-poetry','','[]','清秋方初兮霪雨降而無時，舊坊弗治兮河水泛濫而爲災。',171,'全唐诗/poet.song.30000.json','["清秋方初兮霪雨降而無時，舊坊弗治兮河水泛濫而爲災。", "潏汨沸渭兮澎湃奔波而霈來，崩騰覆溺兮夫豈河伯之不仁。", "汗漫千里兮蕩然室閭，耄稚驚號兮丘冢爲家。", "蛟螭憤怒兮魚鼈縱横，黿鼉馳騖兮鳬鶩飛翔。", "皇天無親兮視聽以民，五序參差兮咎極以滋。", "聖惟唐堯兮固遭横流，臣有舜禹兮輿心所依。", "禦災拯溺兮九叙可歌，四凶遂去兮二人以陞。", "天地平成兮海隅蒙福，白馬玉璧兮非神之欲。"]'),
('6e75acd1-3dae-4071-b5a3-b81e16213470','九誦 箕子','鮮于侁','宋','宋诗','song-poetry','','[]','偉夫子之正諒兮適遭世以離尤，悼祖宗之累積兮大命顛而逢憂。',207,'全唐诗/poet.song.30000.json','["偉夫子之正諒兮適遭世以離尤，悼祖宗之累積兮大命顛而逢憂。", "忠良屏遠兮讒諛寖昌，神龜在塗兮虺蟒升堂。", "紫鸞笯置兮鴆羽飛揚，騶虞潛遯兮豺虎縱横。", "江籬鉏割兮鈎吻日滋，芳荃不御兮蔓草難圖。", "比干剖心兮天子佯狂，蒙以正兮大明其傷。", "靈修不察兮國以云亡，舊邦維新兮武功以成。", "囚奴釋辱兮作賓於王，九疇演繹兮大法以彰。", "五事欽明兮君道日隆，彝倫攸叙兮庻政其凝。", "朝鮮分封兮夷貊化行，傳國中山兮蕃子以孫。", "廟貎有嚴兮祀典攸存，歲時奉事兮斯千萬年。"]'),
('fb9e0f38-35aa-434c-b7fc-fe5678f7cf89','九誦 微子','鮮于侁','宋','宋诗','song-poetry','','[]','肇公孫之璇源兮玄鳥降而生商，並禹稷之聖賢兮實惟桓撥之王。',199,'全唐诗/poet.song.30000.json','["肇公孫之璇源兮玄鳥降而生商，並禹稷之聖賢兮實惟桓撥之王。", "歷媯姒之世數兮道日躋於武湯，始伐罪於仇餉兮人怨咨而徯來。", "顧寛仁之宜民兮天俾式于九圍，諒除殘而代虐兮猶云德之有慚。", "賴燕翼於孫謀兮治克舉於三宗，老成不怨於不以兮隱處不傷於厄窮。", "世四十有六而下衰兮豈天命之將隳，寔遭家之不嗣兮顧麗色之惟微。", "念社稷之顛傾兮七廟無所憑依，帝眷在於有周兮抱祭器而焉歸。", "雖白馬之見廟兮聊血食於商丘，偉夫子一言兮誠有取於三仁。"]'),
('737bd2cb-dfe9-4e1a-a162-d84ef6e0455c','九誦 雙廟','鮮于侁','宋','宋诗','song-poetry','','[]','旄頭光芒兮戎馬馳，海水沸蕩兮鯨鯢飛。',236,'全唐诗/poet.song.30000.json','["旄頭光芒兮戎馬馳，海水沸蕩兮鯨鯢飛。", "煙塵蔽日兮殺氣昏，金鼓轟天兮山岳奔。", "小國不守兮大國顛傾，王侯戮辱兮虵豕肆行。", "二公仗義兮捍賊睢陽，析骸易子兮併力小城。", "勢窮力殫兮外無救兵，亡身徇國兮寧屈虎狼。", "仰天視日兮氣以揚揚，衣纓不絕兮貌如平生。", "旅遊馳驅兮歷此舊都，致詞雙廟兮涕泗不收。", "惟忠與孝兮死義爲尤，遭世擾擾兮適履其憂。", "訏謀顛置兮邊將怙功，尾大權移兮三鎮握兵。", "忠賢在野兮讒邪肆意，女謁內用兮戚臣外圯。", "紀綱日紊兮典刑日弛，胎禍階亂兮誰執其咎。", "義士没身兮沈冤莫置，猗歟二公兮行人歔欷。"]'),
('2ae46691-8d2a-4bc8-a804-28815611d72b','涪江風月','鮮于侁','宋','宋诗','song-poetry','','[]','涪江風月爲誰清，莫向涪翁問姓名。',32,'全唐诗/poet.song.30000.json','["涪江風月爲誰清，莫向涪翁問姓名。", "萬古涪江流不盡，漁磯月似舊時明。"]'),
('79c4cf9f-79ba-47fe-a021-a68e337fbaad','賦新繁周表權如詔亭','鮮于侁','宋','宋诗','song-poetry','','[]','楹宇當年誰教育，榜題今日侈恩章。',64,'全唐诗/poet.song.30000.json','["楹宇當年誰教育，榜題今日侈恩章。", "詩書有道傳家法，綸綍無私及義方。", "肯構新基人共羨，萬趍子舍自生光。", "喧闐里閈容千騎，盡看承顔拜壽觴。"]'),
('22724889-a6c5-49e0-a1e3-2167e98a8ba3','揚州','鮮于侁','宋','宋诗','song-poetry','','[]','金山一拳石，出髻如溟漲。',24,'全唐诗/poet.song.30000.json','["金山一拳石，出髻如溟漲。", "天外辨兩潮，江南分列嶂。"]'),
('a3ba4eca-69db-4935-80e8-603747077c11','寶峰亭','鮮于侁','宋','宋诗','song-poetry','','[]','舟航日上下，車馬不少閑。',24,'全唐诗/poet.song.30000.json','["舟航日上下，車馬不少閑。", "近邑湊商賈，遠峰自雲煙。"]'),
('3707837a-0b74-4521-a13a-b60fe03da845','會景堂','鮮于侁','宋','宋诗','song-poetry','','[]','金城環雉堞，雲屋瞰闤闠。',24,'全唐诗/poet.song.30000.json','["金城環雉堞，雲屋瞰闤闠。", "雙林聳江右，九隴覘天外。"]'),
('0fb5fb8f-d041-47ca-b075-13eea8038d80','巴江','鮮于侁','宋','宋诗','song-poetry','','[]','三川會合遶城下，巴字體勢何盤盤。',32,'全唐诗/poet.song.30000.json','["三川會合遶城下，巴字體勢何盤盤。", "卻疑天工勅水帝，戲寫鳥迹傾波瀾。"]'),
('7ee6b16c-2cb8-4be6-ad29-8290d96aef34','和司馬君實安之以詩二絕見招作真率會光以無從者不及赴依韻和呈','鮮于侁','宋','宋诗','song-poetry','','[]','羹藜寂寞天隨子，換酒風流賀季真。',64,'全唐诗/poet.song.30000.json','["羹藜寂寞天隨子，換酒風流賀季真。", "淡水論交自忘味，道腴充實不知貧。", "萬錢縱侈輕豪貴，三壽優遊萃燕賓。", "奔走每憐饒俗狀，謫官猶作會中人。"]'),
('d17bc072-7ef0-4fc6-94ae-24ee3d580d5c','遊金山','鮮于侁','宋','宋诗','song-poetry','','[]','蓬萊三神山，橫絕巨鰲背。',215,'全唐诗/poet.song.30000.json','["蓬萊三神山，橫絕巨鰲背。", "鰲傾海水動，一峰失所在。", "飛大江中，盤礡幾千載。", "化爲金山居，龍象錯朱貝。", "夙昔愛山水，江湖不暫忘。", "君前或剖竹，匏繫古維揚。", "隱然絕勝地，旦旦遙相望。", "不意二君子，招攜一葦航。", "高攀躡雲梯，闊視皦溟漲。", "潮來隱天地，萬里捲白浪。", "波清雲漢凈，澄澈迷下上。", "更深月正中，山影杳無象。", "蛟鼉四面穴，形勢三洲壯。", "融結既難窮，丹青殊莫狀。", "蘇侯韻高遠，邵子雅趨尚。", "奇觀極無邊，幽等端未放。", "浮生閱流水，清晨造方丈。", "畢景趣言歸，侵星搖兩槳。"]'),
('4d8e1372-31ff-4dd9-984e-0ebbfaf7abd0','揚州后土祠瓊花','鮮于侁','宋','宋诗','song-poetry','','[]','百蘤天下多，瓊花天上稀。',96,'全唐诗/poet.song.30000.json','["百蘤天下多，瓊花天上稀。", "結根託靈祠，地著不可移。", "八蓓冠羣芳，一株攢萬枝。", "孤生淮海上，晚秀清和時。", "攜賞偶佳辰，暗香盈酒卮。", "傾都走廟下，愛玩如調饑。", "皦月正交光，薰風正離披。", "惟應神仙人，收拾繁英歸。"]'),
('b82a55bb-da27-44c5-a486-93da5f0434ec','錦屏山','鮮于侁','宋','宋诗','song-poetry','','[]','分命叮嚀詔旨寬，晝歸聊憩錦屏山。',63,'全唐诗/poet.song.30000.json','["分命叮嚀詔旨寬，晝歸聊憩錦屏山。", "寺門一路煙霞外，邑屋千家紫翠間。", "城山鼓鼙催日暮，雨桃李報春還。", "江流此去朝宗急，遠迹何時遂賜環。"]'),
('7ca359c9-e1c1-41ff-a435-319178c1f39d','大劍山','鮮于侁','宋','宋诗','song-poetry','','[]','武侯渭水屯兵日，司馬秦中閑壘時。',64,'全唐诗/poet.song.30000.json','["武侯渭水屯兵日，司馬秦中閑壘時。", "遠業自能興漢室，重門何事守坤維。", "劉吳遡峽終摧敵，鍾鄧緣崖亦濟師。", "自古存亡關付託，誰言雙劍繫安危。"]'),
('a86add77-b344-4a4f-8817-f2a0cb89100d','題靈巖','鮮于侁','宋','宋诗','song-poetry','','[]','馬煩箠策車馳轂，終歲塵勞常碌碌。',177,'全唐诗/poet.song.30000.json','["馬煩箠策車馳轂，終歲塵勞常碌碌。", "喜聞巖寺在山中，路轉清溪入幽谷。", "乍行山口疑洞天，窮深一上翻平田。", "千層臺殿隱林木，四面石壁生雲煙。", "山僧迎門笑相揖，爲立場祖師存德迹。", "屈指于今八百年，已在西來達摩前。", "鶴鳴飛止黄金地，錫杖湧起清涼泉。", "境稱尚絕名天下，天台石橋乃其亞。", "千峰不改歲寒時，一水最憐秋月夜。", "半生遊學頗艱辛，且向空山老此身。", "也知方丈安禪處，解笑東西南北人。"]'),
('fb949fc4-d8ab-43a5-8a58-a6e93ec90e4a','遊靈巖','鮮于侁','宋','宋诗','song-poetry','','[]','千峰環郡宇，二水遶城堞。',252,'全唐诗/poet.song.30000.json','["千峰環郡宇，二水遶城堞。", "每憐山水佳，況復開巖穴。", "川流數里近，放棹攀巀嵲。", "靈巖駭神化，環陰數畝闊。", "何人營佛祠，棟宇殆天設。", "前軒瞰溪山，眺聽心耳豁。", "徑穿巨石下，碧玉聳高節。", "涓流瀉石谼，玉乳甘且潔。", "其東乃小巖，洞戶敞深徹。", "嵌巖見石柱，任重立精鐵。", "昔人遇真仙，相攜觀金闕。", "川平聽雞犬，始覺人世別。", "屈曲沿清溪，桃花正開發。", "塵緣念鄉縣，歸思若弦涉。", "寤寐瞬息間，巖扉已嚴鐍。", "時遷等陵谷，事勝存圖牒。", "獨有蒼江流，清霄鑒明月。", "予來秋之季，氣象頗凄切。", "草木自變衰，山花常復活。", "青暉沃賞適，異境差勝絕。", "薄暮上歸艎，依然望林樾。"]'),
('eb880fa5-2062-47df-9a8f-9f35fecbb26d','洋州三十景 冰池','鮮于侁','宋','宋诗','song-poetry','','[]','東西橫塘裏，積疊崑嶺玉。',24,'全唐诗/poet.song.30000.json','["東西橫塘裏，積疊崑嶺玉。", "潛鱗知幾何，還待春風觸。"]'),
('f7ad18db-7ddc-45f8-baba-5e4292b39332','洋州三十景 書軒','鮮于侁','宋','宋诗','song-poetry','','[]','朱門謝俗客，幽齋敘友人。',24,'全唐诗/poet.song.30000.json','["朱門謝俗客，幽齋敘友人。", "澄瀾鑒止水，高節看叢筠。"]'),
('b461b577-e5a0-4800-a4c9-1709d51bdb74','洋州三十景 披錦亭','鮮于侁','宋','宋诗','song-poetry','','[]','春歸閬風家，功入天匠手。',24,'全唐诗/poet.song.30000.json','["春歸閬風家，功入天匠手。", "能將五色雲，點綴當戶牖。"]'),
('f3ca00c9-f54a-4971-adf5-eed79d75c3b3','洋州三十景 橫湖','鮮于侁','宋','宋诗','song-poetry','','[]','三冬修竹色，六月芙蕖風。',24,'全唐诗/poet.song.30000.json','["三冬修竹色，六月芙蕖風。", "軒窗復起處，盡入菱花中。"]'),
('6e69fec2-7572-4110-8cc8-8dd9dd3ed271','洋州三十景 湖橋','鮮于侁','宋','宋诗','song-poetry','','[]','千峰起華陽，一水連天漢。',24,'全唐诗/poet.song.30000.json','["千峰起華陽，一水連天漢。", "初月正沉鈎，隱然飛兩岸。"]'),
('ef0dfae3-14c8-4f17-9333-f77e5fe2c573','洋州三十景 望雲樓','鮮于侁','宋','宋诗','song-poetry','','[]','雲山日在眼，飛觀復看雲。',24,'全唐诗/poet.song.30000.json','["雲山日在眼，飛觀復看雲。", "願似崇朝雨，飄揚靜世氛。"]'),
('3c09c942-00d3-41fc-a011-fc81a67dd42e','洋州三十景 待月臺','鮮于侁','宋','宋诗','song-poetry','','[]','臺高上霄漢，人遠絕囂紛。',24,'全唐诗/poet.song.30000.json','["臺高上霄漢，人遠絕囂紛。", "秋中午夜靜，萬里無纖雲。"]'),
('320c9ed0-59e5-47af-b287-f3626c67b1e9','洋州三十景 二樂榭','鮮于侁','宋','宋诗','song-poetry','','[]','琴躋積翠外，絺結穹隆間。',24,'全唐诗/poet.song.30000.json','["琴躋積翠外，絺結穹隆間。", "軒檻最佳處，四顧惟江山。"]'),
('a13bd214-14ba-42a3-922e-9a791e51de15','洋州三十景 灙泉亭','鮮于侁','宋','宋诗','song-poetry','','[]','泉聲日琮琤，泉水深浩渺。',24,'全唐诗/poet.song.30000.json','["泉聲日琮琤，泉水深浩渺。", "可愛主人心，亭中狎鷗鳥。"]'),
('697ceb6d-33a6-4b51-ad1a-f9133d552cdd','洋州三十景 吏隱亭','鮮于侁','宋','宋诗','song-poetry','','[]','心休忘物我，道勝一軒靜。',24,'全唐诗/poet.song.30000.json','["心休忘物我，道勝一軒靜。", "隱几度朝晡，可嗟人畏影。"]'),
