('5de36452-1fcd-4250-8b09-1fd0b5d6f40d','嘉祐寺留別丕上人','皮公弼','宋','宋诗','song-poetry','','[]','兩年無惠及編氓，蜀道天難六月行。',32,'全唐诗/poet.song.30000.json','["兩年無惠及編氓，蜀道天難六月行。", "深羨高僧捐世累，竹風湖處聽泉聲。"]'),
('742e31bb-322b-493a-bbad-4da3a4c589a9','句','皮公弼','宋','宋诗','song-poetry','','[]','壁山老守似僧家，無酒無歌歲華。',15,'全唐诗/poet.song.30000.json','["壁山老守似僧家，無酒無歌歲華。"]'),
('f1b376ee-c47f-451d-88d9-d643f85ddb1a','和趙閱道游海雲山','蘇宷','宋','宋诗','song-poetry','','[]','笙歌揭虛閣，帷幕匝春池。',48,'全唐诗/poet.song.30000.json','["笙歌揭虛閣，帷幕匝春池。", "且與民同樂，都忘天一涯。", "舊游嗟倏忽，故步喜追隨。", "陌上人如堵，歸鞍莫載馳。"]'),
('6a40f7e8-edf5-4697-8b92-ce7365e50737','送程給事知越州','姚原道','宋','宋诗','song-poetry','','[]','共登龍榜早翱翔，青瑣黄扉佐有唐。',64,'全唐诗/poet.song.30000.json','["共登龍榜早翱翔，青瑣黄扉佐有唐。", "金印隔江開督府，月娥環席勸飛觴。", "皋夔勛鼎先三事，杭越詩筒第一章。", "不比當年元與白，錦衣易地鎮仙鄉。"]'),
('ebc6e87b-f5a2-40ca-83fd-307d12d21094','句','孫侔','宋','宋诗','song-poetry','','[]','更起粉牆高百尺，莫令牆外俗人看。',16,'全唐诗/poet.song.30000.json','["更起粉牆高百尺，莫令牆外俗人看。"]'),
('3d55e1f7-9687-4998-b6d1-b6667bfaa03a','子夏山','趙瞻','宋','宋诗','song-poetry','','[]','山因先師成令名，人心仰止懸青冥。',160,'全唐诗/poet.song.30000.json','["山因先師成令名，人心仰止懸青冥。", "文侯北面款山扄，石室至今猶南傾。", "直松萬林天籟聲，長材大棟資連甍。", "溪泉四出照骨清，潤物功溥民罔争。", "朝兮新雲澤根莖，暮兮和風發勾萌。", "山川氣稟天地英，民何知爲夫子靈。", "魏最稱治由師經，晉俗自是多諸生。", "時尚辭華取未精，皓首學行徒修明。", "非無神降弼王庭，國朝當議平文衡。", "斯文未喪吾道亨，商之傳授今可行。"]'),
('fed614ee-eaee-4739-95bc-caacea4c36af','比干臺','趙瞻','宋','宋诗','song-poetry','','[]','九閽大壞一木支，勢知不可誠不欺。',240,'全唐诗/poet.song.30000.json','["九閽大壞一木支，勢知不可誠不欺。", "商之三仁異所歸，死諌不欲狂囚爲。", "賢哉萬世忠臣師，比干而已前其誰。", "諌不當顯何所持，忠必愛君無拂辭。", "帝舜載賡歌康隳，風雅比興陳盛衰。", "君賢臣聖流書詩，光華榮輝同葳蕤。", "扶起不欲憂顛危，剖心血頸鼎鑊糜。", "此意不獨在一時，死者一傳星日垂。", "猶有佞人乘其機，順正逢惡稱諷規。", "甘言好語解人頤，如鼷食角寝不觜。", "聰明蔽密蔀莫知，微干之節世亦疑。", "章華非不窮峩巍，姑蘇一同宗社移。", "名與土滅埽無遺，但爲世鑒那足譏。", "兹臺巍巍存遺基，尚覺清風灑肝脾。", "妖狐狡兔不敢依，飛沙落日予心悲。"]'),
('c797bc0d-aaf0-4c7a-9f92-9c0ebae384d7','魏文侯城','趙瞻','宋','宋诗','song-poetry','','[]','曰自戰國争雄來，何城不荒爲壘培。',160,'全唐诗/poet.song.30000.json','["曰自戰國争雄來，何城不荒爲壘培。", "治亂興廢詎足哀，矧無名號寒扵灰。", "晉壤剖裂分家陪，魏至文侯功業恢。", "三師經術王迹開，五臣禦侮强敵摧。", "況有成子相君才，吳起将兵亦偉哉。", "內諮禮樂古典該，外强師旅騰風雷。", "足尊天子朝靈臺，烏用此城高崔嵬。", "城之峻矣維其頽，宮之廣矣今蒿萊。", "黍離興難悲邅回，如侯萬國徒塵埃。", "一時火熾俄燼煨，惟有陋俗知營財。"]'),
('8e342ab8-6650-4fb6-859c-b56cab1f0994','鶴鳴古洞','趙瞻','宋','宋诗','song-poetry','','[]','山勢嵳峩接遠峰，九皋鶴淚徹長空。',64,'全唐诗/poet.song.30000.json','["山勢嵳峩接遠峰，九皋鶴淚徹長空。", "清音彷彿蒼松外，疏影依稀皓月中。", "石洞雲封仙去後，桑田世換水流同。", "登臨厭聽黄鸝語，弄巧綿蠻噪碧叢。"]'),
('a6d96edf-35c4-4117-aaf7-0c5389957802','文湖漁唱','趙瞻','宋','宋诗','song-poetry','','[]','湖光瀲灧泛蓮荷，款乃漁郎慣此過。',64,'全唐诗/poet.song.30000.json','["湖光瀲灧泛蓮荷，款乃漁郎慣此過。", "笛韻吹殘紅蓼岸，櫓聲搖出錦鱗窩。", "狂歌明月閒愁少，放浪扁舟適興多。", "蓴菜鱸魚供一醉，掉頭歸去卧煙蓑。"]'),
('d5f49e3a-3bde-49bf-8836-c8d92fdf7528','句','趙瞻','宋','宋诗','song-poetry','','[]','天猶月倉廥，三十六峰中。',12,'全唐诗/poet.song.30000.json','["天猶月倉廥，三十六峰中。"]'),
('419dee11-7acb-44b1-a834-a38fd03f7de8','崇法寺','韓縝','宋','宋诗','song-poetry','','[]','久聞雲際山，中有古招提。',288,'全唐诗/poet.song.30000.json','["久聞雲際山，中有古招提。", "新秋喜遠覽，銳意窮攀躋。", "出郭值微雨，涼風曉萋萋。", "陂陀越大嶺，沙路凈無泥。", "野沃稻田秀，耒耜沿溝畦。", "登岑復入谷，漸過西山西。", "舉首望華屋，雙岸鬰相攜。", "虛橋駕煙靄，峻闥排虹霓。", "下馬踏危級，褰裳涉修梯。", "超然層閣外，仰視穹蒼低。", "俯眺亦何有，森森喬木齊。", "喧囂從吏語，嘲唽驚禽啼。", "既飯復搜討，林間得幽蹊。", "巖阿訪靈迹，大士常高棲。", "古殿蝕苔蘚，丹青暗塵㙠。", "俯身踐危蹬，側足緣深溪。", "老樹陰潭黑，風修辭蟬嘶。", "懸泉洗陰壁，瑩色如玻瓈。", "佳觀誠可戀，遲留懼顛擠。", "捫蘿出天險，始免魂神睽。", "緩步淩巀嵲，雙旌隨杖藜。", "回瞻花雨地，已被煙雲迷。", "頓轡下平陸，晴川留馬蹄。", "新篁映碧宇，野寺臨長堤。"]'),
('a990d84f-f01a-4353-9e54-fe03c6db1101','遊賈氏南園','韓縝','宋','宋诗','song-poetry','','[]','江堤楊柳碧毿毿，閑訪名園郡郭南。',64,'全唐诗/poet.song.30000.json','["江堤楊柳碧毿毿，閑訪名園郡郭南。", "壠麥生齊知雨足，海棠開遍覺春酣。", "門前幽徑通芳蕙，竹裏虛亭對遠嵐。", "風物有情應笑我，不攜歌酒只清談。"]'),
('6fb47550-4eed-4d50-8f94-9ba28eb41107','庚子八月八日再遊東山寺','韓縝','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','蜀師當日戍黄金，此地由來險阻深。',64,'全唐诗/poet.song.30000.json','["蜀師當日戍黄金，此地由來險阻深。", "漾水東流自紆直，泰山北望正嶔崟。", "涼風肅物初秋意，膏澤愆期旦晝陰。", "同是天涯未歸客，荒煙斜日正登臨。"]'),
('7499c1cb-6ea8-4e04-8486-50b9f713413a','遊東山寺','韓縝','宋','宋诗','song-poetry','','[]','久有東林約，因乘暇日游。',266,'全唐诗/poet.song.30000.json','["久有東林約，因乘暇日游。", "眼明初出郭，神王欲凌秋。", "野曠鶱孤隼，江清颺遠鷗。", "近山青嶂合，多稼綠雲浮。", "雞犬聲相接，溝塍水亂流。", "度橋喧從騎，環樹轉鳴騶。", "問俗驚堯壤，尋僧到沃洲。", "深沈開寶闥，磅礴𨋗華輈。", "像設嚴珠殿，經聲隱絳幬。", "仰看香剎直，徐步畫展廊修。", "遇物皆周覽，逢軒即少留。", "前庭初顯豁，後徑轉深幽。", "野嶺蒼筠麗，霜楓赤葉稠。", "隔牆聞好鳥，循沼玩游儵。", "翠榦椶纔剝，紅芒稻半收。", "凌虛登陛總之，匝境對岑樓。", "暗谷藏危棧，平沙際別州。", "川原同聚沫，身世劇浮鷗。", "回首飄鄉思，臨尊浣客愁。", "清閑資善奕，決勝在冥搜。", "影動穰直表，風生曲逆籌。", "歸鞍不敢緩，斜日照文楸。"]'),
('0e2439f3-7ed2-46f5-b11f-7e6e1840a2f7','句  其一','韓縝','宋','宋诗','song-poetry','','[]','君因未報身何有，且寄扁舟夢想中。',16,'全唐诗/poet.song.30000.json','["君因未報身何有，且寄扁舟夢想中。"]'),
('5e898937-5299-41fe-b3be-e56f9ac3b7d4','句  其二','韓縝','宋','宋诗','song-poetry','','[]','唐蒙諭巴蜀，通道至卭僰。',24,'全唐诗/poet.song.30000.json','["唐蒙諭巴蜀，通道至卭僰。", "列郡徼西南，夷居半巖壁。"]'),
('b65374b2-c12c-4c41-927b-d741dca42811','句  其三','韓縝','宋','宋诗','song-poetry','','[]','劍外吾能說，山川大抵同。',36,'全唐诗/poet.song.30000.json','["劍外吾能說，山川大抵同。", "君行在巴徼，民俗半夷風。", "火田租賦薄，鹽井歲時豐。"]'),
('2249ffc1-2f8a-40cf-aff5-39216a8a8931','句  其四','韓縝','宋','宋诗','song-poetry','','[]','地里輿星直，江流漢水通。',12,'全唐诗/poet.song.30000.json','["地里輿星直，江流漢水通。"]'),
('49d76284-3476-4529-8fbb-3004db3a0745','王大令移需巖王隱居手植木樨於郡庭賦詩以贈和黄通判韻','方蘋','宋','宋诗','song-poetry','','[]','分將翠色來雩邑，翛爾清風植府庭。',32,'全唐诗/poet.song.30000.json','["分將翠色來雩邑，翛爾清風植府庭。", "先生高臥何由見，想在漁州弄紫萍。"]'),
('1706d96c-afe1-4425-b7ac-3ad64d6147f7','送程給事知越州','王晳','宋','宋诗','song-poetry','','[]','冰顔黑髪未應衰，巨艦高旌使府威。',64,'全唐诗/poet.song.30000.json','["冰顔黑髪未應衰，巨艦高旌使府威。", "瑣闥領藩承嘏去，繡衣過郡買臣歸。", "湖山勝迹吟毫健，風月良辰宴斝飛。", "金榜弟兄同舍長，老年相別重依依。"]'),
('99e20b34-7d14-405f-85c0-666b601c569f','句  其一','王晳','宋','宋诗','song-poetry','','[]','當利江頭最僻州，懷人惟是數登樓。',16,'全唐诗/poet.song.30000.json','["當利江頭最僻州，懷人惟是數登樓。"]'),
('e5b56c6e-a7af-40f3-816f-0c17974c1bc0','句  其二','王晳','宋','宋诗','song-poetry','','["\u592a\u6e56"]','西風晴日過姑蘇，左瞰松江右太湖。',16,'全唐诗/poet.song.30000.json','["西風晴日過姑蘇，左瞰松江右太湖。"]'),
('b0227498-6130-43a0-bb10-b355d6ae11f2','遊日山','馬良器','宋','宋诗','song-poetry','','[]','雲外朝陽照古臺，千巖宿霧一時開。',32,'全唐诗/poet.song.30000.json','["雲外朝陽照古臺，千巖宿霧一時開。", "使君久負登臨約，今日朱轓特地來。"]'),
('165d4e40-27a8-4582-b02a-6b875fc2f0a5','惠山齋中聽雨','李詳','宋','宋诗','song-poetry','','[]','雲冷銀蟾遯，香寒寶篆遲。',48,'全唐诗/poet.song.30000.json','["雲冷銀蟾遯，香寒寶篆遲。", "輕雷新破夢，好雨故知時。", "池荇陰抽带，山茶暗展旗。", "空階聞夜響，楚客起題詩。"]'),
('6f3604a3-dbfa-4f7c-89e1-2dbd5020e523','麻姑山','許抗','宋','宋诗','song-poetry','','[]','數里岧嶢落日西，更高高處種靈芝。',64,'全唐诗/poet.song.30000.json','["數里岧嶢落日西，更高高處種靈芝。", "危風受雪春歸晚，怪石留雲雨到遲。", "仙鹿避人眠淺徑，野禽窺果啄殘枝。", "待應俗格消磨盡，重建瑤臺舊路岐。"]'),
('62da06e8-39a2-42ed-9be1-c6acb8b51b74','西池清暉亭','許抗','宋','宋诗','song-poetry','','[]','亭號清暉闞碧漣，半連村落半神仙。',32,'全唐诗/poet.song.30000.json','["亭號清暉闞碧漣，半連村落半神仙。", "青山剩得雲間日，明月饒分水底天。"]'),
('ee82477b-67f1-4a8c-b1d6-349864d32fd7','讀唐中興頌','許抗','宋','宋诗','song-poetry','','[]','周雅久不復，楚騷方獨鳴。',108,'全唐诗/poet.song.30000.json','["周雅久不復，楚騷方獨鳴。", "淫哇弄氣態，□我瀟湘清。", "二公好奇古，大節□時□。", "□崖勒唐頌，字字瓊□英。", "□雲借體勢，水石生光精。", "浯溪僻□地，自爾聞正聲。", "□傳□□夏，孰賡燕然銘。", "弦歌入商魯，永與人鬼聽。", "江流或可竭，此文如日星。"]'),
('d0c50836-6b12-4811-acd6-f2f436bf582d','任僊公臺','石賡','宋','宋诗','song-poetry','','[]','衰年脚手倦躋攀，今日憑高一解顔。',64,'全唐诗/poet.song.30000.json','["衰年脚手倦躋攀，今日憑高一解顔。", "驅得江山來目下，化將樓殿出雲間。", "真人煉藥仙都近，釋子焚香佛界閑。", "塵事數地寧易得，后歌須盡夕陽還。"]'),
('df193617-d07b-40a4-9a03-a67f00a02348','岳陽樓觀洞庭','石賡','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','洞庭白波如雪山，九月顛風了作寒。',128,'全唐诗/poet.song.30000.json','["洞庭白波如雪山，九月顛風了作寒。", "乾坤蕩沃漫無際，岳陽樓中方好看。", "居人習慣占天色，短艇高檣絕行迹。", "一點君山乍有無，魚龍作壞三閭宅。", "樓上觀湖壯思生，巴陵酒熟香出瓶。", "傾壺快飲爲君盡，醉殺謫仙詩始成。", "二年持節臨荆部，扁舟此地常來去。", "今日憑高覺膽驚，歸歟莫與風濤過。"]'),
('5ab2ee45-bf76-45eb-9ac1-5ae73b02cb39','送程給事知越州','石麟之','宋','宋诗','song-poetry','','[]','鹿轓龍節上恩華，衣繡先歸士論嘉。',64,'全唐诗/poet.song.30000.json','["鹿轓龍節上恩華，衣繡先歸士論嘉。", "瑣闥暫虛元老席，蓬萊還屬侍臣家。", "旌旗天上浮文鷁，鼓角江頭擁將牙。", "東越又新南越治，到時歌詠已諠譁。"]'),
('4d83600e-13c7-45b0-be2c-de46e11c0b52','茅山續志','張頡','宋','宋诗','song-poetry','','[]','步虛聲起繞玄雲，石乳煙銷夜半分。',32,'全唐诗/poet.song.30000.json','["步虛聲起繞玄雲，石乳煙銷夜半分。", "怪得瑤笙吹鶴過，碧壇夜醮玉宸君。"]'),
('dd3dc558-9fdf-4d51-b075-2946db4ec8a5','寄答張五丈夔明府','張頡','宋','宋诗','song-poetry','','[]','舊令龍溪有去思，移家喜與土風宜。',64,'全唐诗/poet.song.30000.json','["舊令龍溪有去思，移家喜與土風宜。", "人傳張籍妙樂府，我識王維真畫師。", "火米夏收畬稻早，海椒春放瘴花遲。", "客查不到天無雁，賴有輶軒可寄詩。"]'),
('20b63930-10c7-435e-a860-112bf6d91839','攝山訪隱者','張頡','宋','宋诗','song-poetry','','[]','路繞蒼山石掛藤，結廬深入白雲層。',32,'全唐诗/poet.song.30000.json','["路繞蒼山石掛藤，結廬深入白雲層。", "泉鳴便隔人間世，采藥知從何處僧。"]'),
('28b75fd2-90cb-43ad-813b-7ffb4d0b5f67','送程給事知越州','晏知止','宋','宋诗','song-poetry','','[]','遍歷侯藩治績高，瀛州瑣闥奉思褒。',64,'全唐诗/poet.song.30000.json','["遍歷侯藩治績高，瀛州瑣闥奉思褒。", "麟符又入千巖境，鷁艦還乘八月濤。", "田賴鑑湖常歲美，客遊梅市有人豪。", "從來夢錦耽佳句，應接江山豈憚勞。"]'),
('588abe31-9cc0-428a-9eee-c88c05bd9b9b','孫氏池亭','俞瑊','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','壁介山水間，幽棲愧尸祿。',288,'全唐诗/poet.song.30000.json','["壁介山水間，幽棲愧尸祿。", "眠食行坐處，山光水聲足。", "嗟我心未厭，出郊搜勝躅。", "嘗聞隱者居，未爲人所目。", "素商適丁序，天空老林麓。", "飛鞭走崇岡，惟恐到不速。", "捫蘿出孤險，果得煙霞谷。", "神仙何玄怪，刻劃乾坤腹。", "囊括幽絕景，所謂天下獨。", "門前白石溪，丁當潄寒玉。", "山泉落雲頭，漫漫泛餘綠。", "靜聽宿烏吟，閑看浮鷗浴。", "萬古仇池穴，何日此鐫築。", "欲探龍頷珠，潭深怯獰毒。", "瀑布想匡廬，香山葺茅屋。", "松窗風浪搖，石徑苔蘚覆。", "樓藏未見書，園挺耐寒木。", "清風誰共延，牆頭萬箇竹。", "造化曲盡情，遠引空江束。", "陰寂窟蛟蜃，雨雹生晴燠。", "孫氏何代賢，據此傲浮俗。", "崖留五君詩，塵埋不可讀。", "殷勤補訛缺，磨寫筆屢禿。", "開亭追古蹤，仙遊一朝復。"]'),
('55dfe7ab-c108-40b2-aa21-217cbbee5024','中山別墅','俞瑊','宋','宋诗','song-poetry','','[]','村居何所樂，我愛讀書堂。',48,'全唐诗/poet.song.30000.json','["村居何所樂，我愛讀書堂。", "階草侵窗潤，瓶花落硯香。", "憑欄看水活，出岫笑雲忙。", "野客時相過，聯吟坐夕陽。"]'),
('7c77367a-f645-497e-bc15-2122907a2cff','句','俞瑊','宋','宋诗','song-poetry','','[]','壁山僻陋戶口少，兩衙之外惟高眠。',16,'全唐诗/poet.song.30000.json','["壁山僻陋戶口少，兩衙之外惟高眠。"]'),
('a8fac100-8b65-41cb-867b-6594abe8abe5','宮詞  其一','張公庠','宋','宋诗','song-poetry','','[]','學士經筵論古今，花塼日上兩三尋。',32,'全唐诗/poet.song.30000.json','["學士經筵論古今，花塼日上兩三尋。", "天顔有喜人知否，認得唐虞用意深。"]'),
('cf6e9e2c-d414-4660-85b7-61f11c6ca549','宮詞  其二','張公庠','宋','宋诗','song-poetry','','[]','朱字衙香伴玉鑪，丁丁蓮漏月來初。',32,'全唐诗/poet.song.30000.json','["朱字衙香伴玉鑪，丁丁蓮漏月來初。", "交龍畫燭搖紅影，準擬君王夜讀書。"]'),
('5ca4a8c6-3c06-4c7f-a83b-3da0c9e11605','宮詞  其三','張公庠','宋','宋诗','song-poetry','','[]','秘閣新開別殿西，玉蟾蜍對玉狻猊。',32,'全唐诗/poet.song.30000.json','["秘閣新開別殿西，玉蟾蜍對玉狻猊。", "奏書未愜君王意，內省夫人看御批。"]'),
('39673312-d5f7-4eb8-af0b-e01d229a2bcc','宮詞  其四','張公庠','宋','宋诗','song-poetry','','[]','宿麥葳蕤綠未迴，惡風惟解卷塵埃。',32,'全唐诗/poet.song.30000.json','["宿麥葳蕤綠未迴，惡風惟解卷塵埃。", "平明瑞雪深三尺，萬歲聲中賀表來。"]'),
('cbe114ee-034d-40aa-8822-6117a34b8933','宮詞  其五','張公庠','宋','宋诗','song-poetry','','[]','玉虛新殿勢巑岏，誰見壺中日月閑。',32,'全唐诗/poet.song.30000.json','["玉虛新殿勢巑岏，誰見壺中日月閑。", "消盡曉霞無一縷，數聲清磬落人間。"]'),
('f64b356e-9cf5-4027-9ef9-1f864c1047cf','宮詞  其六','張公庠','宋','宋诗','song-poetry','','[]','八月金莖露有華，晨曦纔上散餘霞。',32,'全唐诗/poet.song.30000.json','["八月金莖露有華，晨曦纔上散餘霞。", "朱書十字黄封酒，先賜王公執政家。"]'),
('453548e0-7933-4f74-8d13-6d527dbea13c','宮詞  其七','張公庠','宋','宋诗','song-poetry','','[]','月落銀臺初勘契，一聲金鎖禁門開。',32,'全唐诗/poet.song.30000.json','["月落銀臺初勘契，一聲金鎖禁門開。", "千官聳轡爭朝路，騶士籠街宰相來。"]'),
('919bc965-3409-4063-bbb9-8c6f4a600b87','宮詞  其八','張公庠','宋','宋诗','song-poetry','','[]','晨光初動閣門開，百辟匆匆避路回。',32,'全唐诗/poet.song.30000.json','["晨光初動閣門開，百辟匆匆避路回。", "千步畫廊敲杖子，朱衣雙引相公來。"]'),
('62e09fa8-3640-41a6-bd95-2ed69109765e','宮詞  其九','張公庠','宋','宋诗','song-poetry','','[]','赫日炎風晝鼓遲，中官宣問到黄扉。',32,'全唐诗/poet.song.30000.json','["赫日炎風晝鼓遲，中官宣問到黄扉。", "傳呼宰相槐街靜，青蓋搖搖未午歸。"]'),
('1d4ed1bd-6b2d-4a3d-a839-c44e75674562','宮詞  其一○','張公庠','宋','宋诗','song-poetry','','[]','北斗回杓欲建寅，宮嬪排備立春時。',32,'全唐诗/poet.song.30000.json','["北斗回杓欲建寅，宮嬪排備立春時。", "鐫花貼子留題處，只待金鑾學士詩。"]'),
('9f0bb6b2-9025-42db-bc31-03138af344a2','宮詞  其一一','張公庠','宋','宋诗','song-poetry','','[]','年華先到未央宮，嬉賞班班四序中。',32,'全唐诗/poet.song.30000.json','["年華先到未央宮，嬉賞班班四序中。", "瀟灑梅花元耐雪，輕狂柳絮不嫌風。"]'),
('2bd488a1-86c0-4319-a67f-e211f0dc3bc6','宮詞  其一二','張公庠','宋','宋诗','song-poetry','','[]','御苑名花約萬栽，芳心俱願日華來。',32,'全唐诗/poet.song.30000.json','["御苑名花約萬栽，芳心俱願日華來。", "春風已暖梅先綻，長恨江南冒雪開。"]'),
('d3d71fd6-1d25-4569-951f-98da29b1dfa7','宮詞  其一三','張公庠','宋','宋诗','song-poetry','','[]','仙籞梅開淡淡春，夜來微雨滲輕塵。',32,'全唐诗/poet.song.30000.json','["仙籞梅開淡淡春，夜來微雨滲輕塵。", "風和日暖難凋落，不怕倚樓吹笛人。"]'),
('6e8f1d9a-a0ba-4f6e-98e1-a8b9b3f065b8','宮詞  其一四','張公庠','宋','宋诗','song-poetry','','[]','曉霧溟濛似有無，半殘紅燭動金鋪。',32,'全唐诗/poet.song.30000.json','["曉霧溟濛似有無，半殘紅燭動金鋪。", "黄鶯不語梨花上，錯認徐熙舊畫圖。"]'),
('8723cf76-1a32-4ee9-9e67-14bb57d73abf','宮詞  其一五','張公庠','宋','宋诗','song-poetry','','[]','四部韶音進玉卮，千官傾望柘黄衣。',32,'全唐诗/poet.song.30000.json','["四部韶音進玉卮，千官傾望柘黄衣。", "舞頭再拜金階遠，畫鼓連催卷隊歸。"]'),
('4c2faac8-c0c6-47bc-a753-7be6ddc5f5d4','宮詞  其一六','張公庠','宋','宋诗','song-poetry','','[]','二月猶寒未有雷，江梅纔謝小桃開。',32,'全唐诗/poet.song.30000.json','["二月猶寒未有雷，江梅纔謝小桃開。", "宮娥不放珠簾下，待得東風送燕歸。"]'),
('b4defe97-ba59-4a82-8624-01f44a719383','宮詞  其一七','張公庠','宋','宋诗','song-poetry','','[]','盡道今來花信遲，凌晨宮女探春歸。',32,'全唐诗/poet.song.30000.json','["盡道今來花信遲，凌晨宮女探春歸。", "寒梅一朵金槃小，已有清香拂御衣。"]'),
('8bd2eaac-fe90-4ade-a563-773ac2327a41','宮詞  其一八','張公庠','宋','宋诗','song-poetry','','[]','池北池南柳對黄，翠華游幸晝初長。',32,'全唐诗/poet.song.30000.json','["池北池南柳對黄，翠華游幸晝初長。", "宮娥從駕知多少，十里朱輪半日香。"]'),
('067e0225-b4dd-4b08-b27d-8f794d61ccd7','宮詞  其一九','張公庠','宋','宋诗','song-poetry','','[]','御柳絲長掛玉欄，不須惆悵百花殘。',32,'全唐诗/poet.song.30000.json','["御柳絲長掛玉欄，不須惆悵百花殘。", "還知三月春雖晚，好從金輿看牡丹。"]'),
('ccaea30b-ef37-4c47-bc43-4fecb224f3fa','宮詞  其二○','張公庠','宋','宋诗','song-poetry','','[]','過苑中官排辦時，江梅初綻兩三枝。',32,'全唐诗/poet.song.30000.json','["過苑中官排辦時，江梅初綻兩三枝。", "春寒呵手晨妝罷，簾外人催從駕遲。"]'),
('4ac7c48c-0b4d-44f8-ad83-93f951013634','宮詞  其二一','張公庠','宋','宋诗','song-poetry','','[]','共惜流芳甚擲梭，初移夏琯已清和。',32,'全唐诗/poet.song.30000.json','["共惜流芳甚擲梭，初移夏琯已清和。", "百花飛盡酴醾發，留得春光數日多。"]'),
('c66f44f0-ca92-436f-ba0a-83a695792c58','宮詞  其二二','張公庠','宋','宋诗','song-poetry','','[]','端禮門開班已齊，金莖雙立動晨暉。',32,'全唐诗/poet.song.30000.json','["端禮門開班已齊，金莖雙立動晨暉。", "君王欲上逍遙輦，玉指纖纖整御衣。"]'),
('4603473d-25d6-46e6-a312-cdeb3ef245a2','宮詞  其二三','張公庠','宋','宋诗','song-poetry','','[]','三月韶妍賞牡丹，更宜疏雨濕闌干。',32,'全唐诗/poet.song.30000.json','["三月韶妍賞牡丹，更宜疏雨濕闌干。", "隔簾催喚陪春設，不道新妝粉未乾。"]'),
('803111dc-b382-4a31-91a8-fa17797bb09c','宮詞  其二四','張公庠','宋','宋诗','song-poetry','','[]','再坐千官花滿頭，御香煙上紫雲樓。',32,'全唐诗/poet.song.30000.json','["再坐千官花滿頭，御香煙上紫雲樓。", "萬人同向青霄望，鼓笛聲中度彩毬。"]'),
('fa5606b4-180a-45eb-b2d4-c414cb608cef','宮詞  其二五','張公庠','宋','宋诗','song-poetry','','[]','禁掖人閑小小風，彈棋圍坐柳陰中。',32,'全唐诗/poet.song.30000.json','["禁掖人閑小小風，彈棋圍坐柳陰中。", "正憐美酒杯中綠，又嘆飛花席上紅。"]'),
('a9d19ba6-bfc4-4584-b7a3-c5832eb370d8','宮詞  其二六','張公庠','宋','宋诗','song-poetry','','[]','仙韶一部選輕盈，獨得君王記姓名。',32,'全唐诗/poet.song.30000.json','["仙韶一部選輕盈，獨得君王記姓名。", "中使忽來催侍宴，匆匆不許暫調笙。"]'),
('bce16b2c-4ee2-4ab7-8b79-14323e3af7ac','宮詞  其二七','張公庠','宋','宋诗','song-poetry','','[]','選進良家備六宮，仙姿時得本從容。',32,'全唐诗/poet.song.30000.json','["選進良家備六宮，仙姿時得本從容。", "由來真色生人世，不在巫山十二峰。"]'),
('49a95ef1-f82f-42f6-9e00-4b2187c42614','宮詞  其二八','張公庠','宋','宋诗','song-poetry','','[]','影娥池面碧溶溶，蕩槳佳人夕照中。',32,'全唐诗/poet.song.30000.json','["影娥池面碧溶溶，蕩槳佳人夕照中。", "雲髻不饒荷葉綠，羅裙未減石榴紅。"]'),
('d24b05f7-d158-4550-bba0-f5e5821c87d6','宮詞  其二九','張公庠','宋','宋诗','song-poetry','','[]','後苑宸遊炎日長，宮中彊半坐回廊。',32,'全唐诗/poet.song.30000.json','["後苑宸遊炎日長，宮中彊半坐回廊。", "鵁鶄鸂鶒銀塘靜，楊柳梧桐水殿香。"]'),
('4f542750-4579-4839-9521-c3feb145a93d','宮詞  其三○','張公庠','宋','宋诗','song-poetry','','[]','清秋皓月正嬋娟，的歷華星亦徧天。',32,'全唐诗/poet.song.30000.json','["清秋皓月正嬋娟，的歷華星亦徧天。", "欲上層樓須穩步，不同平地有金蓮。"]'),
('7fff041d-993d-497a-b637-ea453a6f7892','宮詞  其三一','張公庠','宋','宋诗','song-poetry','','[]','承露雙盤插碧空，樓臺更在月明中。',32,'全唐诗/poet.song.30000.json','["承露雙盤插碧空，樓臺更在月明中。", "何人傳得花奴曲，羯鼓聲高滿六宮。"]'),
('2ac4f44a-b4c6-4deb-b133-16d1ffba4236','宮詞  其三二','張公庠','宋','宋诗','song-poetry','','[]','萬字闌幹菊半開，更憐清露點莓苔。',32,'全唐诗/poet.song.30000.json','["萬字闌幹菊半開，更憐清露點莓苔。", "仙韶使副呈新譜，得旨重陽侍宴來。"]'),
('a02bd605-0e02-4518-935d-a4a10cdb99cd','宮詞  其三三','張公庠','宋','宋诗','song-poetry','','[]','翩翩紅葉舞霜秋，紫禁人閑約勝遊。',32,'全唐诗/poet.song.30000.json','["翩翩紅葉舞霜秋，紫禁人閑約勝遊。", "手把金英思泛酒，登高還上去年樓。"]'),
('916cd59e-8afb-49d8-a9ad-1ec6bc78f98d','宮詞  其三四','張公庠','宋','宋诗','song-poetry','','[]','清旦宮中候上番，銀潢輕淡玉鈎殘。',32,'全唐诗/poet.song.30000.json','["清旦宮中候上番，銀潢輕淡玉鈎殘。", "山茶破萼江梅發，盡倚朱欄不避寒。"]'),
('f4f67bc2-fa6e-4543-a0d8-4ec5d790e216','宮詞  其三五','張公庠','宋','宋诗','song-poetry','','[]','治道精深日講求，唐虞功德本優游。',32,'全唐诗/poet.song.30000.json','["治道精深日講求，唐虞功德本優游。", "欲知兆姓千官意，萬歲常瞻十二旒。"]'),
('637a479d-423d-4c26-8916-0c1a1ef8636c','宮詞  其三六','張公庠','宋','宋诗','song-poetry','','[]','顯謨延閣照西清，玉軸牙籤各有名。',32,'全唐诗/poet.song.30000.json','["顯謨延閣照西清，玉軸牙籤各有名。", "聖略秘機貽萬世，君王垂拱致昇平。"]'),
('2fda1215-498a-416e-8d4a-70cb5798e370','宮詞  其三七','張公庠','宋','宋诗','song-poetry','','[]','月上觚稜進鑰初，持更衛士匝千廬。',32,'全唐诗/poet.song.30000.json','["月上觚稜進鑰初，持更衛士匝千廬。", "動筒忽自銀臺人，把燭君王看捷書。"]'),
('0146a511-22e7-4a76-9d6a-e13e9fbbac83','宮詞  其三八','張公庠','宋','宋诗','song-poetry','','[]','玉堂催下葳蕤鎖，除授唯容學士知。',32,'全唐诗/poet.song.30000.json','["玉堂催下葳蕤鎖，除授唯容學士知。", "丞相捧麻宣讀了，百僚欣愜拜丹墀。"]'),
('52240e2b-1396-4706-94e5-b4b3c0ce596e','宮詞  其三九','張公庠','宋','宋诗','song-poetry','','[]','天語放朝春雨急，濃雲偏傍禁城低。',32,'全唐诗/poet.song.30000.json','["天語放朝春雨急，濃雲偏傍禁城低。", "喧呼萬馬爭歸路，落絮飛花半作泥。"]'),
('34d6c006-5b75-48a3-a301-b5cb1676304f','宮詞  其四○','張公庠','宋','宋诗','song-poetry','','[]','清曉傳宣賜御題，日華初動露華晞。',32,'全唐诗/poet.song.30000.json','["清曉傳宣賜御題，日華初動露華晞。", "集英殿上天香散，飛入千人白紵衣。"]'),
('d2706557-fba3-4682-b765-3c2e077cd513','宮詞  其四一','張公庠','宋','宋诗','song-poetry','','[]','過臘愆陽隴麥低，御封香合奉精祈。',32,'全唐诗/poet.song.30000.json','["過臘愆陽隴麥低，御封香合奉精祈。", "君王曉入凝華殿，遠近樓臺看雪飛。"]'),
('4e1dadc7-d76c-4602-8b8d-22e084002d4e','宮詞  其四二','張公庠','宋','宋诗','song-poetry','','[]','閶闔門開曉色回，禁塗迢遞接銀臺。',32,'全唐诗/poet.song.30000.json','["閶闔門開曉色回，禁塗迢遞接銀臺。", "華簪簇簇呼班後，黄傘亭亭過殿來。"]'),
('9c4bad59-6808-4ae1-aa16-7edfce1630bb','宮詞  其四三','張公庠','宋','宋诗','song-poetry','','[]','六宮稱賀各依班，慶誕遙瞻紫氣間。',32,'全唐诗/poet.song.30000.json','["六宮稱賀各依班，慶誕遙瞻紫氣間。", "中貴推排龍喜宴，大臣分奏兩郊壇。"]'),
('62d3f049-8ccd-4a80-9486-135316d54b1d','宮詞  其四四','張公庠','宋','宋诗','song-poetry','','[]','月澹中官放鑰回，倚雲宮殿掖門開。',32,'全唐诗/poet.song.30000.json','["月澹中官放鑰回，倚雲宮殿掖門開。", "綵床百步黄羅帕，于闐名王進玉來。"]'),
('9df0cfdb-5327-424d-a86b-1950bd9845db','宮詞  其四五','張公庠','宋','宋诗','song-poetry','','[]','上番宮女捲簾時，閃閃寒鴉拂曉啼。',32,'全唐诗/poet.song.30000.json','["上番宮女捲簾時，閃閃寒鴉拂曉啼。", "纔索赭迎催進輦，紫宸門外報班齊。"]'),
('7a804942-e1c7-49dc-bcc3-98c8b515c8dd','宮詞  其四六','張公庠','宋','宋诗','song-poetry','','[]','度臘深宮暖未回，半天金碧照樓臺。',32,'全唐诗/poet.song.30000.json','["度臘深宮暖未回，半天金碧照樓臺。", "百花須待東風發，只有寒梅傲雪開。"]'),
('264278a2-5c5e-4cd1-976f-055ed888c07d','宮詞  其四七','張公庠','宋','宋诗','song-poetry','','[]','過社餘寒迤邐消，東風送暖燕營巢。',32,'全唐诗/poet.song.30000.json','["過社餘寒迤邐消，東風送暖燕營巢。", "皇都春色宜登覽，十二樓高出柳梢。"]'),
('450522f3-5043-41ac-8a91-6e3b1b7f3ae6','宮詞  其四八','張公庠','宋','宋诗','song-poetry','','[]','仙籞春妍奉宴嬉，樓臺偏與柳梢宜。',32,'全唐诗/poet.song.30000.json','["仙籞春妍奉宴嬉，樓臺偏與柳梢宜。", "鳴鞘聲入千花去，黄傘低斜步步移。"]'),
('de98e576-9f8a-41e1-a258-7fbe792577a0','宮詞  其四九','張公庠','宋','宋诗','song-poetry','','[]','已過清明侍宴稀，綠窗春睡縐羅衣。',32,'全唐诗/poet.song.30000.json','["已過清明侍宴稀，綠窗春睡縐羅衣。", "殘紅併逐狂風去，只有桐花不解飛。"]'),
('bd41e3fb-0a8b-4a31-b16b-94bd5b6df875','宮詞  其五○','張公庠','宋','宋诗','song-poetry','','[]','百花成錦柳飛綿，纔度清明上巳前。',32,'全唐诗/poet.song.30000.json','["百花成錦柳飛綿，纔度清明上巳前。", "繡蓋徐徐紅日永，六宮遊幸不鳴鞭。"]'),
('3b0d38e1-2289-467f-b093-857a1a1514f1','宮詞  其五一','張公庠','宋','宋诗','song-poetry','','[]','鸞帳薰衣賜御香，花陰未動日初長。',32,'全唐诗/poet.song.30000.json','["鸞帳薰衣賜御香，花陰未動日初長。", "人閑相約尋芳去，春困不禁千步廊。"]'),
('e8a54913-7a0d-4ad9-9122-d6ac4d53becb','宮詞  其五二','張公庠','宋','宋诗','song-poetry','','[]','欲下金階翦牡丹，夜來風雨怯輕寒。',32,'全唐诗/poet.song.30000.json','["欲下金階翦牡丹，夜來風雨怯輕寒。", "腰如束素天然細，不爲傷春带自寬。"]'),
('30911a6e-2829-4635-b5e2-78bbaea9e236','宮詞  其五三','張公庠','宋','宋诗','song-poetry','','[]','楊花飛去落誰家，紫禁人閑惜歲華。',32,'全唐诗/poet.song.30000.json','["楊花飛去落誰家，紫禁人閑惜歲華。", "謾向園林覓春色，折殘枝上兩三花。"]'),
('a0d97450-0769-4b60-80c8-70fdf6c19b90','宮詞  其五四','張公庠','宋','宋诗','song-poetry','','[]','紅芳漸少綠陰多，留得韶光滿內家。',32,'全唐诗/poet.song.30000.json','["紅芳漸少綠陰多，留得韶光滿內家。", "不用金鑪添麝炷，深閨剩掛木香花。"]'),
('61945a74-b7bb-4d25-8de4-57e4249b3786','宮詞  其五五','張公庠','宋','宋诗','song-poetry','','[]','銀漢橫斜近建章，九重深靜閉蘭房。',32,'全唐诗/poet.song.30000.json','["銀漢橫斜近建章，九重深靜閉蘭房。", "六更未覺晨光動，自是仙家日月長。"]'),
('343b19ac-a00a-4f91-9014-6a89553367e4','宮詞  其五六','張公庠','宋','宋诗','song-poetry','','[]','倦飲情懷春晼晚，宮槐新葉未成陰。',32,'全唐诗/poet.song.30000.json','["倦飲情懷春晼晚，宮槐新葉未成陰。", "和風習習簾簾捲，輕絮翩翩院院深。"]'),
('5e6f659a-b30c-4ccd-bf12-f27c60d33162','宮詞  其五七','張公庠','宋','宋诗','song-poetry','','[]','西苑池臺駕幸時，內家朱轂盡陪隨。',32,'全唐诗/poet.song.30000.json','["西苑池臺駕幸時，內家朱轂盡陪隨。", "滿宮學士多題詠，不減詞臣應制時。"]'),
('ce2c0560-18ec-4897-a0b5-eeaedd0b56a0','宮詞  其五八','張公庠','宋','宋诗','song-poetry','','[]','萱草初長花未開，共知青帝領春回。',32,'全唐诗/poet.song.30000.json','["萱草初長花未開，共知青帝領春回。", "珠簾卷上瓊鈎穩，不礙薰風滿殿來。"]'),
('9c1162d4-4752-4eba-95cf-6930cb69babf','宮詞  其五九','張公庠','宋','宋诗','song-poetry','','[]','浴蘭佳節共歡娛，亭午香飛鵲尾鑪。',32,'全唐诗/poet.song.30000.json','["浴蘭佳節共歡娛，亭午香飛鵲尾鑪。", "萬里開疆元不戰，金匳猶進辟兵符。"]'),
('80d1a8d8-0eb9-446b-a8cf-41befe7f5e41','宮詞  其六○','張公庠','宋','宋诗','song-poetry','','[]','曉漏初傳第一籌，碧霄零露滴清秋。',32,'全唐诗/poet.song.30000.json','["曉漏初傳第一籌，碧霄零露滴清秋。", "常娥收拾金波盡，不向鴛鴦瓦上流。"]'),
('8fd3d118-a8c8-486c-8844-479d97f6b060','宮詞  其六一','張公庠','宋','宋诗','song-poetry','','[]','霞散雲消無一毫，四垂天幕露華高。',32,'全唐诗/poet.song.30000.json','["霞散雲消無一毫，四垂天幕露華高。", "蘭閨妝罷移紅燭，金斗溫溫熨御袍。"]'),
('eb857a58-6e39-4e7b-b2aa-408ac907ad54','宮詞  其六二','張公庠','宋','宋诗','song-poetry','','[]','菊吐金英媚晚秋，紫宸朝退幸西樓。',32,'全唐诗/poet.song.30000.json','["菊吐金英媚晚秋，紫宸朝退幸西樓。", "內家排設珠簾捲，鐵網珊珊十二鈎。"]'),
('f308e820-af3a-4845-916d-0ba60e44d8e8','宮詞  其六三','張公庠','宋','宋诗','song-poetry','','[]','殘暉未落兩三竿，放散笙歌晚思閑。',32,'全唐诗/poet.song.30000.json','["殘暉未落兩三竿，放散笙歌晚思閑。", "暫上層樓聊一望，紅塵多處是人間。"]'),
('960af214-e02f-4aa9-a957-bca1b7292355','宮詞  其六四','張公庠','宋','宋诗','song-poetry','','[]','殿琯吹灰報載陽，內家相慶互飛觴。',32,'全唐诗/poet.song.30000.json','["殿琯吹灰報載陽，內家相慶互飛觴。", "繡工未必能終日，晝景誰知一線長。"]'),
('b86cf40e-f075-4e8e-a370-3d1d509eef24','宮詞  其六五','張公庠','宋','宋诗','song-poetry','','[]','交直歸來繡幙開，紅爐互勸辟寒杯。',32,'全唐诗/poet.song.30000.json','["交直歸來繡幙開，紅爐互勸辟寒杯。", "誰知飛雪輕狂意，倒學佳人舞袖回。"]'),
('5d92b924-7c8a-4f5f-a562-6d803e93a04f','宮詞  其六六','張公庠','宋','宋诗','song-poetry','','[]','黄羅雙幅裹除書，新拜昭容稱意無。',32,'全唐诗/poet.song.30000.json','["黄羅雙幅裹除書，新拜昭容稱意無。", "真色不勞施粉黛，香閨虛掛十眉圖。"]'),
('95d450c5-0190-401b-8b8b-aeb050167553','宮詞  其六七','張公庠','宋','宋诗','song-poetry','','[]','佳人唯是惜韶年，嬾向紅窗理管弦。',32,'全唐诗/poet.song.30000.json','["佳人唯是惜韶年，嬾向紅窗理管弦。", "錦席安排胡蝶局，深宮不忌賭金錢。"]'),
('a503e3a6-1456-4880-827d-2b307edc6f14','宮詞  其六八','張公庠','宋','宋诗','song-poetry','','[]','長樂疏鐘常送月，靈和垂柳只從風。',32,'全唐诗/poet.song.30000.json','["長樂疏鐘常送月，靈和垂柳只從風。", "還知天上人難老，顔色年年不減紅。"]'),
('51fb674c-28fc-45bb-8306-fbf7df3f4da9','宮詞  其六九','張公庠','宋','宋诗','song-poetry','','[]','聖主憂勤覽萬機，日高前殿步輿歸。',32,'全唐诗/poet.song.30000.json','["聖主憂勤覽萬機，日高前殿步輿歸。", "太官進膳傳呼速，御合翩翩入禁扉。"]'),
('e79f01f8-2f82-43ff-958c-00e623c5a556','宮詞  其七○','張公庠','宋','宋诗','song-poetry','','[]','誕聖嘉辰卜萬年，壽觴初進起爐煙。',32,'全唐诗/poet.song.30000.json','["誕聖嘉辰卜萬年，壽觴初進起爐煙。", "仙韶纔奏齊天曲，三十六宮人盡傳。"]'),
('43cb7df3-c868-4fe6-8e95-c62d31425cef','宮詞  其七一','張公庠','宋','宋诗','song-poetry','','[]','繡幙盤龍四面開，清和時候已春回。',32,'全唐诗/poet.song.30000.json','["繡幙盤龍四面開，清和時候已春回。", "五弦調暢宸衷樂，坐覺薰風萬里來。"]'),
('8bb571d9-863b-4f46-bc32-e0e7759c2297','宮詞  其七二','張公庠','宋','宋诗','song-poetry','','[]','學士承宣到玉堂，中官鎖院月侵廊。',32,'全唐诗/poet.song.30000.json','["學士承宣到玉堂，中官鎖院月侵廊。", "白麻誕告千官喜，皇子初封一字王。"]'),
('f98bcdb4-5882-4068-bd78-d9a5c698f6df','宮詞  其七三','張公庠','宋','宋诗','song-poetry','','[]','自昔豐穰爲上瑞，萬箱騰頌奏君前。',32,'全唐诗/poet.song.30000.json','["自昔豐穰爲上瑞，萬箱騰頌奏君前。", "史臣螭陛聞宣付，日曆先書大有年。"]'),
('46390de4-1a4c-4344-9b9e-99a60672e79c','宮詞  其七四','張公庠','宋','宋诗','song-poetry','','[]','自古詩人詠具瞻，官儀丞相獨尊嚴。',32,'全唐诗/poet.song.30000.json','["自古詩人詠具瞻，官儀丞相獨尊嚴。", "三衙扣杖一聲喏，只是朱衣略揭簾。"]'),
('ee0ecdb3-f538-4734-a40f-830b1fd69765','宮詞  其七五','張公庠','宋','宋诗','song-poetry','','[]','太皡祠壇數級紅，青旂搖曳日朦朧。',32,'全唐诗/poet.song.30000.json','["太皡祠壇數級紅，青旂搖曳日朦朧。", "人間未覺東風至，先入宜春小院中。"]'),
('13450847-6e2d-4139-adb9-395feb0223af','宮詞  其七六','張公庠','宋','宋诗','song-poetry','','[]','小宴輕陰挑菜時，才人來進賞春詩。',32,'全唐诗/poet.song.30000.json','["小宴輕陰挑菜時，才人來進賞春詩。", "翔鸞臺下梅先萼，射鴨池邊柳未絲。"]'),
('d46f3a83-777b-4378-90f1-7ac2c6c263a9','宮詞  其七七','張公庠','宋','宋诗','song-poetry','','[]','宜春苑傍夾城東，從駕宮嬪樂亦同。',32,'全唐诗/poet.song.30000.json','["宜春苑傍夾城東，從駕宮嬪樂亦同。", "偶會不須張錦幕，遊人已在百花中。"]'),
('0f1fe763-c66d-4638-918c-6b995fb26fcc','宮詞  其七八','張公庠','宋','宋诗','song-poetry','','[]','西苑春深奉翠華，朱欄千萬護珍葩。',32,'全唐诗/poet.song.30000.json','["西苑春深奉翠華，朱欄千萬護珍葩。", "不如直上紅樓去，盡見瓊林十里花。"]'),
('c79a8632-1ebd-4d6a-9799-ccde7a878ce8','宮詞  其七九','張公庠','宋','宋诗','song-poetry','','[]','柳放金絲搭矮槐，御溝清影見樓臺。',32,'全唐诗/poet.song.30000.json','["柳放金絲搭矮槐，御溝清影見樓臺。", "落花流出宮城去，不似武陵容客來。"]'),
('bac2afa8-9065-4f5e-9d4d-1fef5e4492c1','宮詞  其八○','張公庠','宋','宋诗','song-poetry','','[]','踏青來往殊無倦，鬥草輸贏且少休。',32,'全唐诗/poet.song.30000.json','["踏青來往殊無倦，鬥草輸贏且少休。", "更上瓊樓三十級，待看春色滿皇州。"]'),
('1014b439-4fbb-4c4a-9939-8d478cd24fa5','宮詞  其八一','張公庠','宋','宋诗','song-poetry','','[]','冉冉殘暉畫閣西，宮人行樂戀芳時。',32,'全唐诗/poet.song.30000.json','["冉冉殘暉畫閣西，宮人行樂戀芳時。", "遙聞索輦開黄繖，不盡花前半局棋。"]'),
('24e11269-9f99-42d0-b6fc-7c712e8dab86','宮詞  其八二','張公庠','宋','宋诗','song-poetry','','[]','雨罷莓苔聊點砌，風停楊柳暫藏樓。',32,'全唐诗/poet.song.30000.json','["雨罷莓苔聊點砌，風停楊柳暫藏樓。", "明朝同奉昭陽宴，左右分明試彩毬。"]'),
('3456205b-a78a-43da-aa78-37127fef27be','宮詞  其八三','張公庠','宋','宋诗','song-poetry','','[]','倦飲人閑春欲回，日華多處五雲開。',32,'全唐诗/poet.song.30000.json','["倦飲人閑春欲回，日華多處五雲開。", "楊花滿地東風轉，半作輕毬袞袞來。"]'),
('b5a498c6-c0bc-4445-a496-80b961af1fb6','宮詞  其八四','張公庠','宋','宋诗','song-poetry','','[]','鬧紫繁紅裹綠枝，一番風雨盡離披。',32,'全唐诗/poet.song.30000.json','["鬧紫繁紅裹綠枝，一番風雨盡離披。", "瑞香獨占深閨暖，簾外春寒都不知。"]'),
('7faf35f7-8692-426b-802f-dd2d6955302a','宮詞  其八五','張公庠','宋','宋诗','song-poetry','','[]','掖庭初選即知名，新學吹簫數曲成。',32,'全唐诗/poet.song.30000.json','["掖庭初選即知名，新學吹簫數曲成。", "天上仙姝元不識，人間安得詠傾城。"]'),
('440ebeec-22c5-4c79-8d84-c79f603ab722','宮詞  其八六','張公庠','宋','宋诗','song-poetry','','[]','禁園春去偶同行，杏子垂垂葉底青。',32,'全唐诗/poet.song.30000.json','["禁園春去偶同行，杏子垂垂葉底青。", "燒酒初嘗人樂飲，綠槐陰下倒銀瓶。"]'),
('47a8f38f-0dea-49fb-a896-720e91b9f6f5','宮詞  其八七','張公庠','宋','宋诗','song-poetry','','[]','東君回馭已春殘，紅日長時人意閑。',32,'全唐诗/poet.song.30000.json','["東君回馭已春殘，紅日長時人意閑。", "玉鼻琵琶聲正急，更憐鶯語亦綿蠻。"]'),
('e26ef332-471d-4c41-93a5-1bae4325bca1','宮詞  其八八','張公庠','宋','宋诗','song-poetry','','[]','牡丹花品最爲尊，內苑栽培特地繁。',32,'全唐诗/poet.song.30000.json','["牡丹花品最爲尊，內苑栽培特地繁。", "宮女多情看未足，不離雕檻到黄昏。"]'),
('cffe8079-a368-4e91-8de3-206adc8ca52b','宮詞  其八九','張公庠','宋','宋诗','song-poetry','','[]','碧瓦鴛鴦勢欲飛，禁門深靜日遲遲。',32,'全唐诗/poet.song.30000.json','["碧瓦鴛鴦勢欲飛，禁門深靜日遲遲。", "玉簫吹遍新傳譜，坐看黄鸝數換枝。"]'),
('9b966afc-6fa5-45b2-a00b-2ffafb7f5985','宮詞  其九○','張公庠','宋','宋诗','song-poetry','','[]','上林隨駕賞芳辰，曲賜黄封臘味醇。',32,'全唐诗/poet.song.30000.json','["上林隨駕賞芳辰，曲賜黄封臘味醇。", "供帳不須勞幕士，垂楊爲蓋草爲茵。"]'),
('c374aece-0b60-479e-a755-b04525b53fdf','宮詞  其九一','張公庠','宋','宋诗','song-poetry','','[]','南交司令已清和，滿殿薰風日未斜。',32,'全唐诗/poet.song.30000.json','["南交司令已清和，滿殿薰風日未斜。", "院院迎涼簾盡捲，金槃初賜御園瓜。"]'),
('6a59058c-88ab-4103-973f-c8c837ab8d57','宮詞  其九二','張公庠','宋','宋诗','song-poetry','','[]','天津一望碧泱泱，宮女移舟逐晚涼。',32,'全唐诗/poet.song.30000.json','["天津一望碧泱泱，宮女移舟逐晚涼。", "只見平波紅影動，不知蓮艷間新妝。"]'),
('92de2d68-ef7d-4558-831f-26a56e0f6b8e','宮詞  其九三','張公庠','宋','宋诗','song-poetry','','[]','月華浮動上階稜，侍宴歸來掩繡屏。',32,'全唐诗/poet.song.30000.json','["月華浮動上階稜，侍宴歸來掩繡屏。", "子夜酒醒蘭燭暗，碧紗窗外度流螢。"]'),
('925d7973-04a4-46f1-a589-32a2ca2ef745','宮詞  其九四','張公庠','宋','宋诗','song-poetry','','[]','雪罷嚴寒殆不禁，紫宸朝退禁門深。',32,'全唐诗/poet.song.30000.json','["雪罷嚴寒殆不禁，紫宸朝退禁門深。", "君恩委曲人知否，數盞香醪抵百金。"]'),
('b3c9734d-1c6a-48b6-96f1-290410e4add7','宮詞  其九五','張公庠','宋','宋诗','song-poetry','','[]','宴起昭陽索輦時，鑪香偏上赭紅衣。',32,'全唐诗/poet.song.30000.json','["宴起昭陽索輦時，鑪香偏上赭紅衣。", "金門玉砌明如晝，宮女三千把燭歸。"]'),
('8b1758d4-ffe7-41d0-b363-74ba1d9dd83f','宮詞  其九六','張公庠','宋','宋诗','song-poetry','','[]','夾城西畔小毬場，彩仗彎彎人對行。',32,'全唐诗/poet.song.30000.json','["夾城西畔小毬場，彩仗彎彎人對行。", "一樣驊騮三百疋，金羈更伴綠遊韁。"]'),
('cb606300-6dcb-4574-8418-3c1594a58590','宮詞  其九七','張公庠','宋','宋诗','song-poetry','','[]','中使傳呼喜復忙，盡催歌舞到昭陽。',32,'全唐诗/poet.song.30000.json','["中使傳呼喜復忙，盡催歌舞到昭陽。", "薰爐煙穗須臾散，無奈衣輕不受香。"]'),
('020cd2b9-1179-403e-b733-7e2876c31432','宮詞  其九八','張公庠','宋','宋诗','song-poetry','','[]','自勻輕黛怯春寒，巧畫雙眉稱綠鬟。',32,'全唐诗/poet.song.30000.json','["自勻輕黛怯春寒，巧畫雙眉稱綠鬟。", "樓上遠山隨指見，檻中新月對人彎。"]'),
('da9a7081-0126-43a3-bd37-306a4b37f967','宮詞  其九九','張公庠','宋','宋诗','song-poetry','','[]','綺袖時宜不甚寬，自拈刀尺勘雙鸞。',32,'全唐诗/poet.song.30000.json','["綺袖時宜不甚寬，自拈刀尺勘雙鸞。", "錦茵拂掠春宵靜，怯見飛蛾傍燭盤。"]'),
('7dd44183-a282-4152-a4f0-594d37d8392c','宮詞  其一○○','張公庠','宋','宋诗','song-poetry','','[]','朝退人歸亞禁扃，金吾收仗暫縱橫。',32,'全唐诗/poet.song.30000.json','["朝退人歸亞禁扃，金吾收仗暫縱橫。", "諸郎入省鳴騶鬧，低帽揚鞭一字行。"]'),
('203a0f6f-40f8-4081-b31f-b8a50c4a04e1','遊白鶴山','張公庠','宋','宋诗','song-poetry','','[]','初眠宮柳未成陰，馬上聊爲擁鼻吟。',64,'全唐诗/poet.song.30000.json','["初眠宮柳未成陰，馬上聊爲擁鼻吟。", "遠宦情懷消壯志，好花時節負歸心。", "別離長恨人南北，會合休辭酒淺深。", "欲把春愁閑抖擻，亂山高處一登臨。"]'),
('57d97a1d-9338-4dfd-bdb0-aa53b03d58f5','郡齋宴坐','張公庠','宋','宋诗','song-poetry','','[]','爲州容散誕，真慰野人情。',48,'全唐诗/poet.song.30000.json','["爲州容散誕，真慰野人情。", "撼膝禪初悟，搖頭句未成。", "試香秋院靜，鬥墨午窗明。", "已有東歸計，柴扉掩姓名。"]'),
('43014744-328c-49e6-8c79-ec0184b0672b','晚春途中','張公庠','宋','宋诗','song-poetry','','[]','一年春事又成空，擁鼻微吟半醉中。',32,'全唐诗/poet.song.30000.json','["一年春事又成空，擁鼻微吟半醉中。", "夾路桃花風雨過，馬啼無處避殘紅。"]'),
('f6781982-ce42-49e8-b243-8e177e2f628f','壽昌寺','毛國華','宋','宋诗','song-poetry','','[]','寶構非無地，洪濤信有因。',48,'全唐诗/poet.song.30000.json','["寶構非無地，洪濤信有因。", "一朝開古井，三佛現金身。", "敕賜皇恩重，成功佛日新。", "喜看龍象集，全仗法中人。"]'),
('6a262821-eb52-4357-b3d6-19d97323298d','歲暮呈王介甫平甫','朱明之','宋','宋诗','song-poetry','','[]','歲暮遠爲客，一身歸計深。',48,'全唐诗/poet.song.30000.json','["歲暮遠爲客，一身歸計深。", "塵沙日翳翳，雨雪夜陰陰。", "喜色開南信，悲懷動北琴。", "感時須寂寞，何獨少陵心。"]'),
('bcd73bdf-65d5-4b28-89cb-ed19d086aa55','塵土呈介甫','朱明之','宋','宋诗','song-poetry','','[]','塵土紛紛起處微，祇隨風力亂噓吹。',64,'全唐诗/poet.song.30000.json','["塵土紛紛起處微，祇隨風力亂噓吹。", "高張白霧橫宮闕，低引輕雲暗路歧。", "坐客昏蒙歸耳目，行人斑白上鬚眉。", "誰知霶霈天飛雨，洗滌輕浮會有時。"]'),
('7f62915d-12b5-4dec-b85c-91e42a00f6b6','羈旅呈王介甫','朱明之','宋','宋诗','song-poetry','','[]','羈旅迫歲晚，班毛混滿簪。',48,'全唐诗/poet.song.30000.json','["羈旅迫歲晚，班毛混滿簪。", "遊無果下馬，坐乏囊中金。", "塵漲風聲滿，天昏雪氣深。", "幸聞清論數，竟日解悲吟。"]'),
('ca490fb7-7b2a-44e5-a4f6-5462f30aac0d','次韻介甫懷舒州山水見示之什','朱明之','宋','宋诗','song-poetry','','[]','皖上相逢昔少留，登樓隱几聽鳴鳩。',64,'全唐诗/poet.song.30000.json','["皖上相逢昔少留，登樓隱几聽鳴鳩。", "山峰游處今何在，溪水流來此有不。", "就食四方甘不繫，爲生一世信長浮。", "共知局促京沙裏，回首當時始覺羞。"]'),
('fa3cf2b8-b73a-4237-8019-79b538033fa5','因憶灊樓讀書之樂呈介甫','朱明之','宋','宋诗','song-poetry','','[]','憶昨灊樓幸久留，乾坤談罷論雎鳩。',64,'全唐诗/poet.song.30000.json','["憶昨灊樓幸久留，乾坤談罷論雎鳩。", "它時已恨相從少，此日能忘共學不。", "南去溪山隨夢斷，北來身世若雲浮。", "行藏願與君同道，祇恐蹉跎我獨羞。"]'),
('71cfd4a2-5179-4927-858f-45b4587fdf5d','寄王荆公憶江陰','朱明之','宋','宋诗','song-poetry','','[]','城上城隍古鏡中，城邊山色翠屏風。',64,'全唐诗/poet.song.30000.json','["城上城隍古鏡中，城邊山色翠屏風。", "魚蝦接海隨時足，稻米連湖逐歲豐。", "太伯人民堪教育，春申溝港可疏通。", "朱輪天使從君欲，異日能忘笑語同。"]'),
('8c89be21-cdb4-4183-bb1c-d9394cbd2784','題招提院靜照堂','吳申','宋','宋诗','song-poetry','','[]','高檐飛遠發輝光，向此心源默坐忘。',64,'全唐诗/poet.song.30000.json','["高檐飛遠發輝光，向此心源默坐忘。", "豈憶布金拋舊地，便隨飛錫起新堂。", "竹間野鴿聽齋鼓，湖上遊人繫夜航。", "卻懊未能攀勝境，東南雲下欲騰翔。"]'),
('72aeb87a-75d5-4d3d-a39a-63038a95590c','留題碧落洞','連希元','宋','宋诗','song-poetry','','[]','神仙誰道杳難窮，老俗相傳住此宮。',64,'全唐诗/poet.song.30000.json','["神仙誰道杳難窮，老俗相傳住此宮。", "山裂舊分三島洞，羽飛曾馭九天風。", "玉爲雙闕無塵到，雲作丹梯有路通。", "誰問稚川何處在，儼然金竈列壺中。"]'),
('b8f3f29c-8263-4346-8faa-9b0dfaa64627','題雲華御室','連希元','宋','宋诗','song-poetry','','[]','洞天東去號雲華，便是仙人舊隱家。',32,'全唐诗/poet.song.30000.json','["洞天東去號雲華，便是仙人舊隱家。", "堪笑僞劉真俗骨，卻將泥土葬丹砂。"]'),
('73a3ea0d-060c-4da2-81ab-15aac166a25e','送程給事知越州','郎淑','宋','宋诗','song-poetry','','[]','三朝藩屏寵光頻，四紀清名動搢紳。',64,'全唐诗/poet.song.30000.json','["三朝藩屏寵光頻，四紀清名動搢紳。", "肯效懷章驚邸吏，獨能持節屈戎人。", "千巖秀氣歸華藻，五嶺殊功簡紫宸。", "他日會居衡石地，荆州雖老實臺臣。"]'),
('b9ec1faf-95f5-41fa-9387-8ee0406298f9','牡丹  其一','李山甫','宋','宋诗','song-poetry','','[]','邀勒春風不早開，衆芳飄後上樓臺。',64,'全唐诗/poet.song.30000.json','["邀勒春風不早開，衆芳飄後上樓臺。", "數苞仙艷火中出，一片異香天上來。", "曉露精神妖欲動，暮煙情態恨成堆。", "知君已解相輕薄，斜倚欄桿首重回。"]'),
('b32cb9d6-9a32-4412-9431-49655c2361f7','牡丹  其二','李山甫','宋','宋诗','song-poetry','','[]','嫚黄妖紫間輕紅，穀雨初晴早景中。',64,'全唐诗/poet.song.30000.json','["嫚黄妖紫間輕紅，穀雨初晴早景中。", "靜女不言還愛日，彩雲無定只隨風。", "爐煙坐覺沈檀薄，妝面行看曉黛空。", "此別又須經歲月，酒闌把燭繞芳叢。"]'),
('fd81f897-133d-48b9-9f90-ed7dc82bfc80','題瑞相寺','李山甫','宋','宋诗','song-poetry','','[]','路入禪關僻，僧迎取衲披。',48,'全唐诗/poet.song.30000.json','["路入禪關僻，僧迎取衲披。", "自憐重到此，還憶舊遊時。", "泉石清虛境，松筠古老姿。", "問師從此別，鶴駕幾回知。"]'),
('404a903b-020d-490b-b6c7-827de7ab7de0','同知縣東公彥遊章山寺','李山甫','宋','宋诗','song-poetry','','[]','想見尋幽到此山，詩成珠玉笑談間。',64,'全唐诗/poet.song.30000.json','["想見尋幽到此山，詩成珠玉笑談間。", "蓮花社裏千年約，柏子香中半日閑。", "寂歷松窗連遠籟，縈紆竹徑斷荒灣。", "琴堂吏散簾垂晝，舁筍何妨數往還。"]'),
('867567b5-e069-490c-a790-aacd62bd1b3d','慧光寺  其一','李山甫','宋','宋诗','song-poetry','','[]','夢遊山寺有餘清，邂逅來遊卻自驚。',32,'全唐诗/poet.song.30000.json','["夢遊山寺有餘清，邂逅來遊卻自驚。", "珍重秋風知客意，又吹好夢到江亭。"]'),
('977986af-091b-44c0-9de9-529bd35e6f6f','慧光寺  其二','李山甫','宋','宋诗','song-poetry','','[]','僧堂拂拭舊時塵，鶯老花殘五換春。',32,'全唐诗/poet.song.30000.json','["僧堂拂拭舊時塵，鶯老花殘五換春。", "四海干戈如鼎沸，山中猶有太平人。"]'),
('8e2ab8d2-f4e8-4a84-a0f0-cf7b7e935967','和王漕使逵遊麻姑山','李山甫','宋','宋诗','song-poetry','','[]','鈴閣清虛刺史閑，廉車因得訪仙山。',64,'全唐诗/poet.song.30000.json','["鈴閣清虛刺史閑，廉車因得訪仙山。", "旌旂飄緲煙霞外，冠蓋追隨水石間。", "丹井寂寥終古在，鸞驂悵望幾時還。", "從來謝史留詩筆，今日遺風尚可攀。"]'),
('b8fa7bd7-53b5-4355-97d0-b49b392953a8','禪窟寺','李山甫','宋','宋诗','song-poetry','','[]','遲日濃花午，閑雲小陰天。',48,'全唐诗/poet.song.30000.json','["遲日濃花午，閑雲小陰天。", "半巖春洞水，萬片晚林煙。", "慚愧華巓客，來分紫府仙。", "倚窗山竹夜，風溜響朱絃。"]'),
('99dabf8b-765c-4e3e-84b9-ba078482d744','句  其一','李山甫','宋','宋诗','song-poetry','','[]','多謝灞陵隄上柳，與人頭上拂塵埃。',16,'全唐诗/poet.song.30000.json','["多謝灞陵隄上柳，與人頭上拂塵埃。"]'),
('984052ff-7366-4436-9531-85f313f04336','句  其二','李山甫','宋','宋诗','song-poetry','','[]','世上幾時曾好古。',8,'全唐诗/poet.song.30000.json','["世上幾時曾好古。"]'),
('4873b0b2-7de2-4367-9d20-9d6791430387','雙林院','李敷','宋','宋诗','song-poetry','','[]','雙林高寺秀峰環，我欲題爲小徑山。',32,'全唐诗/poet.song.30000.json','["雙林高寺秀峰環，我欲題爲小徑山。", "炎月一遊神骨爽，天風相送出松關。"]'),
('9c69f026-0475-4a5e-bd5d-fafed406ef98','挽老蘇先生  其一','姚闢','宋','宋诗','song-poetry','','[]','持筆游從已五年，忽嗟精魄去茫然。',64,'全唐诗/poet.song.30000.json','["持筆游從已五年，忽嗟精魄去茫然。", "茂陵未訪相如藁，宣室曾知賈誼賢。", "薤露有歌凄曉月，絳紗無主蔽寒煙。", "平生事業文公誌，應試鄉人白玉鐫。"]'),
('5ed0feae-2192-4c13-bc2a-fb635dc79642','挽老蘇先生  其二','姚闢','宋','宋诗','song-poetry','','[]','羈旅都門十載中，轉頭浮宦已成空。',64,'全唐诗/poet.song.30000.json','["羈旅都門十載中，轉頭浮宦已成空。", "青衫暫寄文安籍，白社長留處士風。", "萬里雲山歸故國，一帆江月照疏篷。", "世間窮達何須校，只有聲名是至公。"]'),
('c6e030c6-d8ff-4981-8e81-d2bd10bf1c2e','望文脊懷瞿硎先生','姚闢','宋','宋诗','song-poetry','','[]','文脊山中姓已逃，江城爭美少微高。',64,'全唐诗/poet.song.30000.json','["文脊山中姓已逃，江城爭美少微高。", "應知司馬來窺鼎，便學秦人去種桃。", "海上音書斷鴻雁，洞中吟嘯伴猿猱。", "鹿裘誰識先生志，卻把虛詞倚伏滔。"]'),
('6cdc78ee-48a7-46f3-b474-999448bbb2af','漣漪洞','姚闢','宋','宋诗','song-poetry','','[]','五門高險勢摩天，洞底清冷瀉碧漣。',64,'全唐诗/poet.song.30000.json','["五門高險勢摩天，洞底清冷瀉碧漣。", "蘋藻魚遊知暮雨，薜蘿人去鎖寒煙。", "山櫻已熟垂朱實，巖竹新抽露玉鞭。", "只恐遊人歸馬急，野僧何惜白雲眠。"]'),
('3a2021af-4f7a-4dbc-9350-c8dd9a9fa921','遊山門呈知府大卿','姚闢','宋','宋诗','song-poetry','','[]','春風到宛陵，太守遇康樂。',288,'全唐诗/poet.song.30000.json','["春風到宛陵，太守遇康樂。", "隱几坐高齋，清風媚林壑。", "語我諸峰巒，道人古棲託。", "幽潛遠江漢，秀聳類衡霍。", "一日贐我遊，大府輟高幕。", "命車載酒醪，行人飭巾櫜。", "藍輿渡前溪，野飯即高閣。", "笑著烏紗巾，行背青山郭。", "嵇呂重契舊，皮陸索酬酢。", "幽花弄紫翠，鳴琴唱宮角。", "靈氣浮融融，蒸風紛漠漠。", "晚宿黄渡館，泉聲自伊洛。", "溪童學流觴，盤花遞清酌。", "歸火破昏街，擁衾聞夜柝。", "詰朝振衣坐，繅車厭啼𪈴。", "東壁有舊詩，三賢據安作。", "筆迹既訛謬，塵版復皴皵。", "伊人已黄泉，來者誰丹雘。", "徐徐到山門，青蒼洗昏膜。", "兩山擘大道，造化自櫜籥。", "綠蔕凌空飛，江雲半天落。", "二巖與四洞，靈仙舊淹泊。", "丹安今不歸，雙門失扃鑰。", "雲髓凝爲乳，石柱垂如鐸。"]'),
('26cca302-8fd8-4fbe-93d4-be82a0769808','靈巖','姚闢','宋','宋诗','song-poetry','','[]','泉石平生性所耽，謝公延我到東南。',64,'全唐诗/poet.song.30000.json','["泉石平生性所耽，謝公延我到東南。", "紅蓮幕下煩佳客，文脊山中訪舊巖。", "剪竹掃花尋鳥道，捫蘿隨衲問龍潭。", "圖經未盡幽潛事，待向仙家起玉函。"]'),
('c5d5a76d-51a0-4d59-905e-16cd73f67969','句  其一','姚闢','宋','宋诗','song-poetry','','[]','京洛黄塵久倦遊，一官來寄海邊州。',16,'全唐诗/poet.song.30000.json','["京洛黄塵久倦遊，一官來寄海邊州。"]'),
('c9df6c02-8288-4bc0-b4a3-ed8967c90409','句  其二','姚闢','宋','宋诗','song-poetry','','[]','初日光回天尚暝，暮潮聲落地先秋。',16,'全唐诗/poet.song.30000.json','["初日光回天尚暝，暮潮聲落地先秋。"]'),
('3564c949-b6c6-4a64-9d42-32fc49273a27','句  其三','姚闢','宋','宋诗','song-poetry','','[]','潮撣子亂峰橫几席，沙填重險變桑蔴。',17,'全唐诗/poet.song.30000.json','["潮撣子亂峰橫几席，沙填重險變桑蔴。"]'),
('bece8f87-198b-4ff7-b59d-5375adb86e17','送程給事知越州','黄默','宋','宋诗','song-poetry','','[]','會稽山水古來雄，內史新除捧詔東。',64,'全唐诗/poet.song.30000.json','["會稽山水古來雄，內史新除捧詔東。", "何藉扁舟追范蠡，更將一釣問任公。", "久諳偃息藩垣樂，未試調和鼎鼐功。", "日食萬錢誰吝惜，不知蓬島屬詩翁。"]'),
('d5be7203-08fc-4b04-bf4d-c022162ee994','遊羅浮','林俛','宋','宋诗','song-poetry','','[]','此日鵝城第一山，我來登覽足清歡。',64,'全唐诗/poet.song.30000.json','["此日鵝城第一山，我來登覽足清歡。", "心灰久不作春夢，食淡何須輟晚餐。", "寶積山中多佛剎，藥槽峰外是仙壇。", "憑誰爲扣葛翁訣，乞與當年九轉丹。"]'),
('23b6b647-15bb-4efc-b297-90fd9efe273e','彩雲軒','林俛','宋','宋诗','song-poetry','','[]','滄海揚塵已幾回，麻姑緩步此峰來。',64,'全唐诗/poet.song.30000.json','["滄海揚塵已幾回，麻姑緩步此峰來。", "綵雲縹緲聞仙樂，綠篆淋漓鎖翠苔。", "仙境長留閑日月，飛仙宜號小蓬萊。", "鳳簫鶴馭還相待，名籍今應在玉臺。"]'),
('c9d1533e-ed73-4340-9607-f44a1981bffd','題梅仙山','陳闡','宋','宋诗','song-poetry','','[]','先生吏隱寄南昌，千里來尋物外鄉。',64,'全唐诗/poet.song.30000.json','["先生吏隱寄南昌，千里來尋物外鄉。", "汲水尚憐春井渫，藏丹猶發夜壇光。", "鶴歸華表人何在，犬吠雲深日自長。", "我擬重來訪遺迹，手搘笻杖少徜徉。"]'),
('7da15130-2d8f-4043-abb1-fd89efb6f815','鳬鷖亭','關景仁','宋','宋诗','song-poetry','','[]','古有鳬鷖詩，喜物遊太平。',192,'全唐诗/poet.song.30000.json','["古有鳬鷖詩，喜物遊太平。", "今見鳬鷖樂，爲作鳬鷖亭。", "夜安洲渚棲，晝無羅網驚。", "羣嬉固儔匹，適意相飛鳴。", "春風藻荇稠，夜雨波瀾清。", "特以王澤深，遂此微物生。", "飛甍枕秦臺，繚繞寒蕪城。", "俯目瞰清泚，日羨鳬鷖情。", "自惟縣令暇，朝夕親編氓。", "土瘠民半餒，役頻民少寧。", "嗟爾多蹙迫，豈與鳬鷖並。", "我心徒爾嗟，奈何存典刑。", "爾勞憫以恕，爾重移之輕。", "庶幾皆有樂，共戴君聰明。", "民安令亦暇，臨流解塵纓。", "卒歲可歸去，白髮南山耕。"]'),
('fec62c94-0981-4f5e-932a-f228532ae98d','贈小蘇','關景仁','宋','宋诗','song-poetry','','[]','昔日聞蘇小，今朝見小蘇。',24,'全唐诗/poet.song.30000.json','["昔日聞蘇小，今朝見小蘇。", "未知蘇小貌，得似小蘇無。"]'),
('e9a84902-67dd-476d-86d5-4c804fd0c9f8','枕流軒','關希聲','宋','宋诗','song-poetry','','[]','山出太虛外，溪流千古高。',48,'全唐诗/poet.song.30000.json','["山出太虛外，溪流千古高。", "臨窗喧客枕，洗耳濺僧袍。", "夜月氣猶凜，秋風聲更豪。", "二年遊賞劇，欲別首頻搔。"]'),
('c9042599-76dd-4ed7-8e4b-0489dc2ceb7b','醉眠亭','關景山','宋','宋诗','song-poetry','','[]','杜老顛狂尋酒伴，經旬只走出空床。',64,'全唐诗/poet.song.30000.json','["杜老顛狂尋酒伴，經旬只走出空床。", "輸君縱飲還高臥，長有生涯作醉鄉。", "貧饒北海杯中物，靜勝長安市上眠。", "亂地春風吹不醒，功成合與酒爲仙。"]'),
('b8fefb0f-4a5f-4648-928f-0b18e6b130e7','登雄州北門樓','蔣概','宋','宋诗','song-poetry','','[]','壯士未酬志，乘秋感慨多。',48,'全唐诗/poet.song.30000.json','["壯士未酬志，乘秋感慨多。", "幽燕新種落，唐漢舊關河。", "塞月沉青塚，邊聲入暮河。", "如何得萬騎，玉壘夜經過。"]'),
('e1db2bbc-0717-4450-96c3-2af76237403b','句','李宗孟','宋','宋诗','song-poetry','','[]','空遺費仙跡，不見庾公遊。',24,'全唐诗/poet.song.30000.json','["空遺費仙跡，不見庾公遊。", "草木皆新色，江山餘故愁。"]'),
('f43f3475-2a9a-41fe-979e-16fa30ea2fb5','歸四明','胡幽貞','宋','宋诗','song-poetry','','[]','海色連四明，仙舟去容易。',24,'全唐诗/poet.song.30000.json','["海色連四明，仙舟去容易。", "天籍豈輒問，不是卑朝士。"]'),
('27eeecb6-0985-487b-9430-2f076976c08f','聞龍學平昔曾遊潁川西湖有詩以寄之','張徽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','河勢橫斜带地形，碧油具旆昔常經。',64,'全唐诗/poet.song.30000.json','["河勢橫斜带地形，碧油具旆昔常經。", "驛名未改風塵黑，碑字猶存雨蘚青。", "薦福園林僧杳渺，擷芳洲渚續娉婷。", "汝南一值賢人降，分野于今占德星。"]'),
('8bc7e50c-763b-4104-9161-839c1d86beb0','送龍學和寄王元之郎中','張徽','宋','宋诗','song-poetry','','[]','未持雙節去朝元，玉陛猶虛侍從班。',64,'全唐诗/poet.song.30000.json','["未持雙節去朝元，玉陛猶虛侍從班。", "龜洛舊遊天直上，雞林新句海中間。", "品流有日歸陶冶，隱逸無時奉宴閑。", "鶴馭仙游何處所，軒皇冠劍在橋山。"]'),
('92d039f4-bbbe-4f9e-a7ce-8374cbbc0839','送程給事知越州','張徽','宋','宋诗','song-poetry','','[]','瑣闈官接鳳凰巢，藹藹青雲器業高。',64,'全唐诗/poet.song.30000.json','["瑣闈官接鳳凰巢，藹藹青雲器業高。", "一代後先書惠化，三朝中外主風騷。", "阜安廣粵新城郭，懾伏幽燕舊節旄。", "元相臺樓何處是，蓬萊山壓海波濤。"]'),
('3f6d8703-cd0f-4bf6-a7a0-2db3c9e46080','鳳山閣','張徽','宋','宋诗','song-poetry','','[]','舉頭何處認京華，鳳閣層層出亂霞。',64,'全唐诗/poet.song.30000.json','["舉頭何處認京華，鳳閣層層出亂霞。", "山勢轉來雙徑曲，水聲分去一川斜。", "丹青隱映林間焙，黑白微茫石上畬。", "遇興每須窮日夕，檻邊修竹砌邊花。"]'),
('a9538e94-b501-4c6f-a84a-7582d1139963','惠應廟','張徽','宋','宋诗','song-poetry','','[]','一家終日在樓臺，弈局斜兼畫卷開。',64,'全唐诗/poet.song.30000.json','["一家終日在樓臺，弈局斜兼畫卷開。", "幽鳥影穿紅燭去，寒蟾光落素琴來。", "釣絲暮惹蘋間浪，篆石春浮蘚上埃。", "三數寺通溪畔路，好尋僧借度時盃。"]'),
('53795158-03c0-470b-bae9-89732cab759f','伏承君儀使君郎中寵示佳什謹次嚴韻','張徽','宋','宋诗','song-poetry','','[]','飛鳥影穿紅燭去，寒蟾光落素琴來。',33,'全唐诗/poet.song.30000.json','["飛鳥影穿紅燭去，寒蟾光落素琴來。", "三數寺通溪畔路，好從僧僧借渡時杯。"]'),
('1a60726b-0ac9-4710-b7d1-fc1174fe8431','宿猿洞和程師孟韻','張徽','宋','宋诗','song-poetry','','[]','月上高臺雲半屏，洞門休喚夕陽扃。',32,'全唐诗/poet.song.30000.json','["月上高臺雲半屏，洞門休喚夕陽扃。", "巍冠不整跏趺坐，秋楮斕斑數點星。"]'),
('799dd8de-5054-4b5f-9071-1678ffeb05c3','宿猿洞','張徽','宋','宋诗','song-poetry','','[]','洞天虛寂翠屏欹，心迹蕭然萬物齊。',32,'全唐诗/poet.song.30000.json','["洞天虛寂翠屏欹，心迹蕭然萬物齊。", "無奈宿猿嫌宿客，夜深猶擁亂雲啼。"]'),
('2f13fea8-a2fc-49cf-a906-0d6f4f81d0c3','宿猿洞再和程師孟韻','張徽','宋','宋诗','song-poetry','','[]','入林休顧小猿驚，壽酒交持石外亭。',64,'全唐诗/poet.song.30000.json','["入林休顧小猿驚，壽酒交持石外亭。", "刺史尊崇上卿月，主人高隱少微星。", "只因避雨投松蓋，屢爲障風夾檜屏。", "笑語林猿能解意，往來應不限巖扃。"]'),
('cf80aec0-3fb8-471b-a428-e46419d8b51f','句  其一','張徽','宋','宋诗','song-poetry','','[]','雲蒸洞穴秋成雨，泉落庭除夏結冰。',16,'全唐诗/poet.song.30000.json','["雲蒸洞穴秋成雨，泉落庭除夏結冰。"]'),
('12c7c44b-b141-47ee-8c98-e20a75527082','句  其二','張徽','宋','宋诗','song-poetry','','[]','曉塔影分山店北，暮鐘聲落海門西。',16,'全唐诗/poet.song.30000.json','["曉塔影分山店北，暮鐘聲落海門西。"]'),
('75697739-64ba-49bd-a111-01b31e08d227','題倅廳吏隱堂','趙衆','宋','宋诗','song-poetry','','[]','滿耳江聲滿目山，此身疑不在人寰。',32,'全唐诗/poet.song.30000.json','["滿耳江聲滿目山，此身疑不在人寰。", "民含古意村村靜，吏束刑書日日閑。"]'),
('bd5fae07-52b7-4fd3-8a35-d6aaa5861609','句  其一','趙世昌','宋','宋诗','song-poetry','','[]','綠珠樓下志惆悵，宋玉牆頭又別離。',16,'全唐诗/poet.song.30000.json','["綠珠樓下志惆悵，宋玉牆頭又別離。"]'),
('4a6425bc-5c97-414a-a5a6-b0b8c2125ce0','句  其二','趙世昌','宋','宋诗','song-poetry','','[]','一條橫截紅塵斷，幾曲遙通紫禁深。',16,'全唐诗/poet.song.30000.json','["一條橫截紅塵斷，幾曲遙通紫禁深。"]'),
('e36945de-28ac-498f-b49f-fe308616cd58','飛騎橋','李育','宋','宋诗','song-poetry','','[]','魏人野戰如鷹揚，吳人水戰如龍驤。',128,'全唐诗/poet.song.30000.json','["魏人野戰如鷹揚，吳人水戰如龍驤。", "氣吞魏王惟吳王，建旗敢到新城旁。", "霸主身當萬夫敵，麾下倉皇無羽翼。", "途窮事變接短兵，生死之間不容息。", "馬奔津橋橋半撤，洶洶有聲如地裂。", "蛟怒橫飛秋水空，鶚驚徑度秋雲缺。", "奮迅金羈汗霑臆，濟主艱難天借力。", "艱難始是報主時，平日主君須愛惜。"]'),
('7e984491-3c3f-4c29-941e-6b1b19f7f8e7','君子行','張載','宋','宋诗','song-poetry','','[]','君子防未然，見幾天地先。',60,'全唐诗/poet.song.30000.json','["君子防未然，見幾天地先。", "開物象未形，弭灾憂患前。", "公旦立無方，不恤流言喧。", "將聖見亂人，天厭懲孤偏。", "竊攘豈予思，瓜李安足論。"]'),
('67715513-10bc-46d8-9240-53514ad563de','送蘇修撰赴闕四首  其一','張載','宋','宋诗','song-poetry','','[]','秦弊於今未息肩，高蕭從此法相沿。',32,'全唐诗/poet.song.30000.json','["秦弊於今未息肩，高蕭從此法相沿。", "生無定業田疆壞，赤子存亡任自然。"]'),
('3f1d1cdf-9e5d-47f4-a194-e28247d94e79','送蘇修撰赴闕四首  其二','張載','宋','宋诗','song-poetry','','[]','道大寧容小不同，顓愚何敢與機通。',32,'全唐诗/poet.song.30000.json','["道大寧容小不同，顓愚何敢與機通。", "井疆師律三王事，請議成功器業中。"]'),
('d728e45e-0378-4240-bfb3-420df5daeb88','送蘇修撰赴闕四首  其三','張載','宋','宋诗','song-poetry','','[]','闔闢天機未始休，袗衣胝足兩何求。',32,'全唐诗/poet.song.30000.json','["闔闢天機未始休，袗衣胝足兩何求。", "巍巍只爲蒼生事，彼美何嘗與九州。"]'),
('37a449e3-242f-4aa5-b581-37aecad1701d','送蘇修撰赴闕四首  其四','張載','宋','宋诗','song-poetry','','[]','出異歸同禹與顔，未分黄閣與青山。',32,'全唐诗/poet.song.30000.json','["出異歸同禹與顔，未分黄閣與青山。", "事機爽忽秋毫上，聊驗天心語默間。"]'),
('f30a4899-a718-491b-b083-8d19f8196194','别館中諸公','張載','宋','宋诗','song-poetry','','[]','九天宮殿鬱岧嶤，碧瓦參差逼絳霄。',32,'全唐诗/poet.song.30000.json','["九天宮殿鬱岧嶤，碧瓦參差逼絳霄。", "藜藿野心雖萬里，不無忠戀向清朝。"]'),
('ad48f4f1-72b6-4b51-974c-802a9491f1af','聖心','張載','宋','宋诗','song-poetry','','[]','聖心難用淺心求，聖學須專禮法修。',32,'全唐诗/poet.song.30000.json','["聖心難用淺心求，聖學須專禮法修。", "千五百年無孔子，盡因通變老優游。"]'),
('9e11f751-f5b5-4c2b-a47e-86df3cad5e8f','老大','張載','宋','宋诗','song-poetry','','[]','老大心思久退消，倒巾終日面岧嶤。',32,'全唐诗/poet.song.30000.json','["老大心思久退消，倒巾終日面岧嶤。", "六年無限詩書樂，一種難忘是本朝。"]'),
('86c0c3fa-1c60-4332-80a0-c951ccbc4398','有喪','張載','宋','宋诗','song-poetry','','[]','有喪不免道終非，少爲親嫌老爲衰。',32,'全唐诗/poet.song.30000.json','["有喪不免道終非，少爲親嫌老爲衰。", "舉世只知隆考妣，切思不見我心悲。"]'),
('fea2b6b7-105d-4e97-9de4-6a5147240b73','土牀','張載','宋','宋诗','song-poetry','','[]','土牀煙足紬衾暖，瓦釡泉乾豆粥新。',32,'全唐诗/poet.song.30000.json','["土牀煙足紬衾暖，瓦釡泉乾豆粥新。", "萬事不思溫飽外，漫然清世一閒人。"]'),
('87c5af4f-a898-43ee-8c6d-8cab77b9127c','芭蕉','張載','宋','宋诗','song-poetry','','[]','芭蕉心盡展新枝，新卷新心暗已隨。',32,'全唐诗/poet.song.30000.json','["芭蕉心盡展新枝，新卷新心暗已隨。", "願學新心養新德，旋隨新葉起新知。"]'),
('bf2b46e0-f93c-4e7a-b7ac-f47ac0e86ed7','貝母','張載','宋','宋诗','song-poetry','','[]','貝母階前蔓百尋，雙桐盤繞葉森森。',32,'全唐诗/poet.song.30000.json','["貝母階前蔓百尋，雙桐盤繞葉森森。", "剛強顧我蹉跎甚，時欲低柔警寸心。"]'),
('ef2a4db8-8b4f-4428-a582-e76f017260d1','題解詩後','張載','宋','宋诗','song-poetry','','[]','置心平易始通詩，逆志從容自解頥。',32,'全唐诗/poet.song.30000.json','["置心平易始通詩，逆志從容自解頥。", "文害可嗟高叟固，十年聊用勉經師。"]'),
('1a0df2fe-cf00-4aec-b6cd-89e5b0911b32','詩上堯夫先生兼寄伯淳正叔  其一','張載','宋','宋诗','song-poetry','','[]','先生高臥洛城中，洛邑簪纓幸所同。',32,'全唐诗/poet.song.30000.json','["先生高臥洛城中，洛邑簪纓幸所同。", "顧我成年清渭上，並遊無侶又春風。"]'),
('8fd1575c-1985-4890-8a21-eb6395592150','詩上堯夫先生兼寄伯淳正叔  其二','張載','宋','宋诗','song-poetry','','[]','病肺支離恰十春，病深樽俎久埃塵。',32,'全唐诗/poet.song.30000.json','["病肺支離恰十春，病深樽俎久埃塵。", "人憐舊病新年減，不道新添別病深。"]'),
('014be760-5561-4e11-89f5-b56933aa6efa','別後寄呂子進','張載','宋','宋诗','song-poetry','','[]','籬鷃雲鵬各有程，匆匆相別未忘情。',32,'全唐诗/poet.song.30000.json','["籬鷃雲鵬各有程，匆匆相別未忘情。", "恨君不在篷籠底，共聽蕭蕭夜雨聲。"]'),
('5e51b6cc-9c5f-4e64-b63a-29fc4756ce4e','夢中','張載','宋','宋诗','song-poetry','','[]','楚峽雲嬌宋玉愁，月明溪凈印銀鈎。',32,'全唐诗/poet.song.30000.json','["楚峽雲嬌宋玉愁，月明溪凈印銀鈎。", "襄王定是思前夢，又抱霞衾上玉樓。"]'),
('a36ca8ed-314c-4a81-8ac2-f6394ebdf808','遊山寺','張載','宋','宋诗','song-poetry','','[]','凍僕堆堆依竈燎，山僧草草具盤飧。',32,'全唐诗/poet.song.30000.json','["凍僕堆堆依竈燎，山僧草草具盤飧。", "井丹已厭嘗葱葉，庾亭何勞惜薤根。"]'),
('75148c7c-3208-4339-9a46-0708b2040f6e','八翁吟十首  其一','張載','宋','宋诗','song-poetry','','[]','步虛聲裏八奇翁，八奇須信古英雄。',32,'全唐诗/poet.song.30000.json','["步虛聲裏八奇翁，八奇須信古英雄。", "賓朋未散山翁醉，聽歌同入醉鄉中。"]'),
('bb2d0c96-0955-4787-9d81-2ae975c26b17','八翁吟十首  其二','張載','宋','宋诗','song-poetry','','[]','傅巖巖下築巖翁，幽通心與帝心通。',32,'全唐诗/poet.song.30000.json','["傅巖巖下築巖翁，幽通心與帝心通。", "憂勤未感思賢夢，相霖何日見成功。"]'),
('936daa83-3f12-4692-8dc2-9d50ad4835f7','八翁吟十首  其三','張載','宋','宋诗','song-poetry','','[]','磻溪溪畔釣魚翁，濯纓溪水聽溪松。',32,'全唐诗/poet.song.30000.json','["磻溪溪畔釣魚翁，濯纓溪水聽溪松。", "龜猷未告非熊兆，漁簑堪笑老龍鍾。"]'),
('8819e8bb-1493-42ee-b3e5-8319d03602b7','八翁吟十首  其四','張載','宋','宋诗','song-poetry','','[]','老原原上卜年翁，感天功業地天聰。',32,'全唐诗/poet.song.30000.json','["老原原上卜年翁，感天功業地天聰。", "流言未信成王悟，悟成全得起禾風。"]'),
('eca52f0b-e4d4-4270-992c-e2443cf2991a','八翁吟十首  其五','張載','宋','宋诗','song-poetry','','[]','龜山山下感麟翁，麟翁知己幾時逢。',32,'全唐诗/poet.song.30000.json','["龜山山下感麟翁，麟翁知己幾時逢。", "自從顔孟希蹤後，幾人今日更希蹤。"]'),
('ac05ad04-6ee7-4c24-9932-76623cf3a532','八翁吟十首  其六','張載','宋','宋诗','song-poetry','','[]','青牛西去伯陽翁，當年夫子嘆猶龍。',32,'全唐诗/poet.song.30000.json','["青牛西去伯陽翁，當年夫子嘆猶龍。", "立言爲恐真風喪，豈知言立喪真風。"]'),
('8cbb99ab-4ae0-4272-b305-c80d8a8e2d08','八翁吟十首  其七','張載','宋','宋诗','song-poetry','','[]','寓言豪誕漆園翁，夸談名理浩無窮。',32,'全唐诗/poet.song.30000.json','["寓言豪誕漆園翁，夸談名理浩無窮。", "早知懸解人間世，爭知懸解不言中。"]'),
('d8a199ab-47c6-4b61-83fb-7fb568f28cd4','八翁吟十首  其八','張載','宋','宋诗','song-poetry','','[]','一身無礙竺乾翁，遍圓身世戒身同。',32,'全唐诗/poet.song.30000.json','["一身無礙竺乾翁，遍圓身世戒身同。", "船師從我乘桴去，頑空中與指真空。"]'),
('9cc86e80-e275-4c2e-af87-9e000a835864','八翁吟十首  其九','張載','宋','宋诗','song-poetry','','[]','褒斜谷口臥龍翁，量如江海風如虹。',32,'全唐诗/poet.song.30000.json','["褒斜谷口臥龍翁，量如江海風如虹。", "不應三顧逢先主，至今千載慕冥鴻。"]'),
('b01f81f9-1da2-4e9e-bced-f0b614d571b3','八翁吟十首  其一○','張載','宋','宋诗','song-poetry','','[]','籃輿多病八吟翁，雲賓溪叟恣游從。',32,'全唐诗/poet.song.30000.json','["籃輿多病八吟翁，雲賓溪叟恣游從。", "清時無事青山醉，青山仍醉最青峰。"]'),
('ec038d85-3526-4f91-907f-ef67da77711b','克己復禮','張載','宋','宋诗','song-poetry','','[]','克己工夫未肯加，吝驕封閉縮如蝸。',32,'全唐诗/poet.song.30000.json','["克己工夫未肯加，吝驕封閉縮如蝸。", "試於中夜深思省，剖破藩籬即大家。"]'),
('70f6cc4d-2dc4-495f-8f8b-bd93aacc2516','葛覃解','張載','宋','宋诗','song-poetry','','[]','葛蔓青長谷長遷，女工興念憶歸安。',32,'全唐诗/poet.song.30000.json','["葛蔓青長谷長遷，女工興念憶歸安。", "不將貴盛驕門族，容使親心得盡歡。"]'),
('442f998e-81ca-443d-991e-1e074b781a1d','卷耳解','張載','宋','宋诗','song-poetry','','[]','閨閫誠難與國防，默嗟徒御困高岡。',32,'全唐诗/poet.song.30000.json','["閨閫誠難與國防，默嗟徒御困高岡。", "觥罍欲解痡瘏恨，采耳元因備酒漿。"]'),
('c45127a7-24a9-403d-9485-cec04d06ba5a','詩一首','張載','宋','宋诗','song-poetry','','[]','學易窮源未到時，便將虛寂眇心思。',32,'全唐诗/poet.song.30000.json','["學易窮源未到時，便將虛寂眇心思。", "宛如童子攻詞賦，用即無差問不知。"]'),
('4b534cb5-13d1-4768-b026-c4819d4f4274','絕句','張載','宋','宋诗','song-poetry','','[]','兩山南北雨冥冥，四牖東西萬木青。',32,'全唐诗/poet.song.30000.json','["兩山南北雨冥冥，四牖東西萬木青。", "面似骷髏頭似雪，後生誰與屬遺經。"]'),
('ce13caff-9cfe-4ff6-8bf8-ee7afee9cf87','古樂府 短歌行','張載','宋','宋诗','song-poetry','','[]','靈旗指，不庭方，大風泱泱天外揚。',52,'全唐诗/poet.song.30000.json','["靈旗指，不庭方，大風泱泱天外揚。", "短簫歌，歌愷康。", "明廷萬年，繼明重光。", "曾孫稼，如茨梁。", "嘉與萬邦，純嘏有常。"]'),
('fa631199-da31-4ea2-b383-5cb9d586c48d','古樂府 日重光','張載','宋','宋诗','song-poetry','','[]','日重光，天際翔，願言貞明永瞻望。',36,'全唐诗/poet.song.30000.json','["日重光，天際翔，願言貞明永瞻望。", "月重輪，淡溟淵。", "願猶月之恒，協帝儀中天。"]'),
('190d5f98-24c0-4fc6-8140-4e86185f4375','古樂府 度關山','張載','宋','宋诗','song-poetry','','[]','度關山，循九州，省耕寬徭詢明幽。',29,'全唐诗/poet.song.30000.json','["度關山，循九州，省耕寬徭詢明幽。", "人爲貴兮，哀我人斯敢予休。"]'),
('e1886502-58bf-4be8-bc6e-9e22fceb914f','古樂府 雞鳴','張載','宋','宋诗','song-poetry','','[]','雞鳴嘐嘐兮台懷憂，兄弟表裏兮台心求。',46,'全唐诗/poet.song.30000.json','["雞鳴嘐嘐兮台懷憂，兄弟表裏兮台心求。", "黄金門，白玉堂。", "置酒愷樂，榮華有光。", "桃傷李僵，爾如或忘。"]'),
('5a0cfe2b-546b-4d62-959c-5481d4603d4a','古樂府 燕歌行','張載','宋','宋诗','song-poetry','','[]','小雅廢兮，東山不作。',36,'全唐诗/poet.song.30000.json','["小雅廢兮，東山不作。", "哀我人斯，皇心不樂。", "烝哉斯人，胡然而天兮，王師于鑠。"]'),
('2b275ea3-0c17-40f9-805c-a2712eca5c61','古樂府 東門行','張載','宋','宋诗','song-poetry','','[]','古風出東門，我行樂巾綦。',42,'全唐诗/poet.song.30000.json','["古風出東門，我行樂巾綦。", "今歌東門行，牽衣強留甘餔糜。", "仗劍去，忽如遺，時清君去予心哀。"]'),
('c127492f-4dae-4b6a-b83f-fc5347991657','古樂府 鞠歌行','張載','宋','宋诗','song-poetry','','[]','鞠歌胡然兮，邈予樂之不猶。',118,'全唐诗/poet.song.30000.json','["鞠歌胡然兮，邈予樂之不猶。", "宵耿耿其尚寐兮，日孜孜焉繼予乎厥修。", "井行惻兮王收，曰曷賈不售兮，阻德音其幽幽。", "述空文以見志兮，庶感通乎來古。", "騫昔爲之純英兮，又申申其以告。", "鼓弗躍兮麾弗前，千五百年，寥哉寂焉。", "謂天實爲兮，則吾豈敢，羌審己兮乾乾。"]'),
('8224e113-ec9d-4546-aaf3-d61d0f8a04fe','古樂府 虞帝廟樂歌辭 其一','張載','宋','宋诗','song-poetry','','[]','皇胡爲兮西山之幽，翳長薄兮俯湖流。',95,'全唐诗/poet.song.30000.json','["皇胡爲兮西山之幽，翳長薄兮俯湖流。", "眇冀州兮何有，眷茲上兮淹留。", "皇之神兮如在，子我民兮不窮以愛。", "沛皇澤兮橫流，暢威靈兮無外。", "潔尊兮肥俎，九歌兮拓舞。", "嗟莫報皇之佑，皇欲下兮儼相羊，烈風雷兮暮雨。"]'),
('0a87a3aa-6853-41ad-91d4-a090b8f3824c','古樂府 虞帝廟樂歌辭 其二','張載','宋','宋诗','song-poetry','','[]','虞之陽兮漓之滸，皇降集兮巫屢舞。',84,'全唐诗/poet.song.30000.json','["虞之陽兮漓之滸，皇降集兮巫屢舞。", "桂酒湛兮瑤觴，皇之歸兮何所。", "聽駕兮天門，羽毛兮繽紛。", "俯故宮兮一慨，越宇宙兮無鄰。", "無鄰兮奈何，七政協兮羣生嘉。", "信玄功兮不宰，猶彷彿兮山阿。"]'),
('4e7ee02c-2b4b-4ac4-ab9b-0f8359a3af58','移疾','張載','宋','宋诗','song-poetry','','[]','移疾謝華省，問耕還弊舍。',48,'全唐诗/poet.song.30000.json','["移疾謝華省，問耕還弊舍。", "扶持便疏慵，曠僻逃將迓。", "晝棋莎徑側，暮粥梧陰下。", "久矣澄清心，永愧桑弧射。"]'),
('f772716c-bdce-415e-9626-ddf02c0896c8','宿興慶池通軒示同志','張載','宋','宋诗','song-poetry','','[]','清湘庭下千竿竹，百尺斑斕聳蒼玉。',128,'全唐诗/poet.song.30000.json','["清湘庭下千竿竹，百尺斑斕聳蒼玉。", "通軒軒外萬頃陂，陂接南山天與齊。", "唐基一壞半禾黍，舉目氣象增愁思。", "我來正當搖落時，塵埃七日無人知。", "東平叔子信予友，問學不厭堅相隨。", "叔子莫痛鳳沼湮，又莫悲愁花萼墮。", "所憂聖道久榛塞，富貴浮雲空點涴。", "明發予西叔且東，高談更爲通宵坐。"]'),
('241961db-6065-4395-9b44-4259f5e31987','岳陽書事','張載','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭水落洲渚出，疊翠疏峰遠湮沒。',193,'全唐诗/poet.song.30000.json','["洞庭水落洲渚出，疊翠疏峰遠湮沒。", "重樓百尺壓高城，畫棟沉沉倚天闕。", "湖光上下天水融，中以日月分西東。", "氣凌雲夢吞八九，欲與溟渤爭雌雄。", "澄瀾無風雨新霽，一日萬頃磨新銅。", "琉璃夜影貯星漢，騎鯨已在銀潢中。", "湘妃帝子昔何許，但有林壑青浮空。", "蒼梧雲深不可見，遺恨千古嗟何窮。", "須臾暝晦忽異色，風怒濤翻際天黑。", "乘陵瀨壑走魑魅，停滀百怪誰能測。", "也許看舟子玩行險，更欲飛帆借風力。", "安得晴雲萬里開，依依寒光浸虛碧。"]'),
('9eb5df3b-8336-493a-8986-045003246168','憶別','張載','宋','宋诗','song-poetry','','[]','柳絮飛時與君別，南樓把酒看明月。',96,'全唐诗/poet.song.30000.json','["柳絮飛時與君別，南樓把酒看明月。", "月似當年離別時，柳絮如君何處飛。", "千書百書要相就，思君不見令人瘦。", "念君情意只如初，顧我形骸已非舊。", "朝來有信渡黄河，雁足繫書多網羅。", "城南城北芳草多，月明如此奈愁何。"]'),
('298afd41-6701-4604-a8c2-c0ab9db7c2cf','牧牛兒','張載','宋','宋诗','song-poetry','','[]','牧牛兒，放牛莫放澗水西，澗水流急牛苦饑。',66,'全唐诗/poet.song.30000.json','["牧牛兒，放牛莫放澗水西，澗水流急牛苦饑。", "放牛莫放青草畔，牛臥得草兒亦懶。", "隨牛莫着鞭，幾年力作無荒田。", "雨調風順租稅了，兒但放牛相對眠。"]'),
('2a141d6b-a307-4c6a-80ae-1ec001b18871','呂不韋春秋','張載','宋','宋诗','song-poetry','','[]','秦市金懸魯史修，措辭當日兩難求。',32,'全唐诗/poet.song.30000.json','["秦市金懸魯史修，措辭當日兩難求。", "書傳果在西遷後，錐口諸儒未必休。"]'),
('f1043079-b6d1-4fe0-a408-e4519aac4285','我欲','張載','宋','宋诗','song-poetry','','[]','我欲庭前木葉疏，病枝衰蔓手披除。',32,'全唐诗/poet.song.30000.json','["我欲庭前木葉疏，病枝衰蔓手披除。", "從今燕坐無通塞，來往風煙任卷舒。"]'),
('6adda553-df58-4d00-a24e-031ccb804961','萱草','張載','宋','宋诗','song-poetry','','[]','萱草花開十日餘，花繁日日倍于初。',32,'全唐诗/poet.song.30000.json','["萱草花開十日餘，花繁日日倍于初。", "朝開暮落終非計，栽活青松漸剪除。"]'),
('dc5a89f8-561d-46e5-9062-cfe9ff914291','書齋自儆','張載','宋','宋诗','song-poetry','','[]','畫前有易不知易，玄上求玄恐未玄。',32,'全唐诗/poet.song.30000.json','["畫前有易不知易，玄上求玄恐未玄。", "白首紛如成底事，蠹魚徒自老青編。"]'),
('425a3c24-f2e8-47b3-a790-df18262a7282','合雲寺書事三首  其一','張載','宋','宋诗','song-poetry','','[]','山前咫尺市朝賒，垣屋蕭條似隱家。',32,'全唐诗/poet.song.30000.json','["山前咫尺市朝賒，垣屋蕭條似隱家。", "過客不須攜鼓吹，野塘終日有鳴蛙。"]'),
('96450c22-2a14-4fca-a9c0-a3814e838887','合雲寺書事三首  其二','張載','宋','宋诗','song-poetry','','[]','夾屋青松長數圍，午風搖影舞僛僛。',32,'全唐诗/poet.song.30000.json','["夾屋青松長數圍，午風搖影舞僛僛。", "幽禽葉底鳴相應，時引殘聲過別枝。"]'),
('abd04eaa-02fd-47fd-bb17-90c105f879eb','合雲寺書事三首  其三','張載','宋','宋诗','song-poetry','','[]','竹間幽徑草成圍，藜杖穿雲翠滿衣。',32,'全唐诗/poet.song.30000.json','["竹間幽徑草成圍，藜杖穿雲翠滿衣。", "石上坐忘驚覺晚，山前明月伴人歸。"]'),
('ebe872b1-490c-42cd-bf9b-07ef8cd63b00','劉陽歸鴻閣','張載','宋','宋诗','song-poetry','','[]','簾捲晴空獨倚闌，冥鴻點點無無間。',32,'全唐诗/poet.song.30000.json','["簾捲晴空獨倚闌，冥鴻點點無無間。", "秋風注目無人會，時與白雲相對閑。"]'),
('8322f084-80b1-49ff-bb61-b4ae035e45b2','江上夜行','張載','宋','宋诗','song-poetry','','[]','冰壺瀲灧接天浮，月色雲光寸寸秋。',32,'全唐诗/poet.song.30000.json','["冰壺瀲灧接天浮，月色雲光寸寸秋。", "不用乘槎厲東海，一江星漢擁行舟。"]'),
('8e3872b3-30e4-4ab9-ad65-0391a0d8bdfc','登峴首阻雨  其一','張載','宋','宋诗','song-poetry','','[]','羊公風績幾經秋，獨繞龜趺爲少留。',32,'全唐诗/poet.song.30000.json','["羊公風績幾經秋，獨繞龜趺爲少留。", "欲問荆人尋舊事，一江青泚自東流。"]'),
('1d087feb-f797-405b-93ed-e0616e201cb5','登峴首阻雨  其二','張載','宋','宋诗','song-poetry','','[]','江浮雲影抱層欄，雲外青山一水間。',32,'全唐诗/poet.song.30000.json','["江浮雲影抱層欄，雲外青山一水間。", "盡日倚闌看不足，杖藜欲去更回環。"]'),
('a72bee6a-04df-41e8-b6ba-ec531be9a462','登峴首阻雨  其三','張載','宋','宋诗','song-poetry','','[]','江風飛雨上雕欄，庭樹蕭蕭景自閑。',32,'全唐诗/poet.song.30000.json','["江風飛雨上雕欄，庭樹蕭蕭景自閑。", "向晚浮雲遮不盡，好山渾在有無間。"]'),
('c643db58-dd5d-48f9-a22a-7090cea7f91a','登峴首阻雨  其四','張載','宋','宋诗','song-poetry','','[]','庭前古木已經秋，天外行雲暝不收。',32,'全唐诗/poet.song.30000.json','["庭前古木已經秋，天外行雲暝不收。", "倚杖卻尋山下路，一川風雨濕征輈。"]'),
('d449a6bc-a4f2-4f3b-9a16-cc7cb2aef252','諸宮觀梅寄胡康侯','張載','宋','宋诗','song-poetry','','[]','欲驅殘臘變春風，自有寒梅作選鋒。',32,'全唐诗/poet.song.30000.json','["欲驅殘臘變春風，自有寒梅作選鋒。", "莫把疏英輕鬥雪，好藏清艷月明中。"]'),
('32dc3cba-5460-4bd0-967f-71a3a11481e5','春晚  其一','張載','宋','宋诗','song-poetry','','[]','雲靄浮空半雨晴，茅簷未忍掃殘英。',32,'全唐诗/poet.song.30000.json','["雲靄浮空半雨晴，茅簷未忍掃殘英。", "欲將春物飄零盡，只有黄鸝一兩聲。"]'),
('886b0225-08c4-4cf7-92d2-cf268a5057bc','春晚  其二','張載','宋','宋诗','song-poetry','','[]','浮花浪蕊自紛紛，點綴莓苔作繡茵。',32,'全唐诗/poet.song.30000.json','["浮花浪蕊自紛紛，點綴莓苔作繡茵。", "獨有猗蘭香未歇，可紉幽佩繫餘春。"]'),
('ce6f0d51-3509-48a1-9945-42d6fb6a76dd','閑居書事','張載','宋','宋诗','song-poetry','','[]','輕風拂拂撼孤檉，庭戶蕭然一室清。',32,'全唐诗/poet.song.30000.json','["輕風拂拂撼孤檉，庭戶蕭然一室清。", "隔葉蟬鳴微欲斷，又聞餘韻續殘聲。"]'),
('7748d645-4a8b-4da6-beee-d91b21c40d6d','集義齋','張載','宋','宋诗','song-poetry','','[]','小齋新創得新名，大筆標題字勢輕。',64,'全唐诗/poet.song.30000.json','["小齋新創得新名，大筆標題字勢輕。", "養勇所期肩孟子，動心那肯詫齊卿。", "川流有本源源聽，月入容光處處明。", "此道幾人能彷彿，浪言徒遣俗儒驚。"]'),
('9478dba8-403f-43d2-a5f5-247232df6e85','契重','張載','宋','宋诗','song-poetry','','[]','契重金蘭屈指誰，偶然傾蓋接英輝。',64,'全唐诗/poet.song.30000.json','["契重金蘭屈指誰，偶然傾蓋接英輝。", "疏慵唱和應嫌晚，久淡封題莫厭稀。", "致主每思烹鼎說，剪戎何日檄書飛。", "安仁久識儒家樂，老大情懷漸有依。"]'),
('0788e8e6-1f2c-46fe-ac4a-c5a137a65c57','孤宦','張載','宋','宋诗','song-poetry','','[]','孤宦殊方意自違，鄰光茲幸託餘輝。',64,'全唐诗/poet.song.30000.json','["孤宦殊方意自違，鄰光茲幸託餘輝。", "人心識盡童心減，世事諳多樂事稀。", "直有歲寒甘栢說，終無春思惜花飛。", "豈同毛刺墦間客，向望他門卜所依。"]'),
('5ac07d5c-6048-49cf-8b50-68fa412b4a57','和薛伸國博漾陂','張載','宋','宋诗','song-poetry','','[]','幾年煙浪掩遺蹤，今意扶持古意同。',160,'全唐诗/poet.song.30000.json','["幾年煙浪掩遺蹤，今意扶持古意同。", "簪笏每遊高聖世，蓴鱸聊爲快秋風。", "輕陰島嶼莓苔濕，夜雨蛟龍窟穴空。", "南浦雲峰晴不亂，北窗溪木暗難通。", "春濃岸酰成行碧，日暖汀花取次紅。", "歲月可悲唐廢苑，山河終近漢離宮。", "歸禽影轉沙堤曲，處土居鄰竹塢東。", "星斗已知天象富，菱蒲堪喜地毛豐。", "持竿幸有魚充鼎，混浴須嗟鶴在籠。", "吏隱苟能遊物外，江鄉何必羨吳中。"]'),
('931f1aae-2ea6-4078-b36b-756342798e4f','候人','張載','宋','宋诗','song-poetry','','[]','林木南山薈蔚時，工斤樵斧竟朝儕。',32,'全唐诗/poet.song.30000.json','["林木南山薈蔚時，工斤樵斧竟朝儕。", "舉知趨利青冥上，不念幽閨季女饑。"]'),
('4368e441-7a1a-4e10-8f2b-d90d78676e44','題北村六首  其一','張載','宋','宋诗','song-poetry','','[]','陸軸嘔啞麥上場，謳歌聲韻滿村坊。',32,'全唐诗/poet.song.30000.json','["陸軸嘔啞麥上場，謳歌聲韻滿村坊。", "茅齋病叟安閑久，帝力民歡殆兩忘。"]'),
('f632c9d6-b301-4ab6-9905-2982ede91141','題北村六首  其二','張載','宋','宋诗','song-poetry','','[]','求富誠非憚執鞭，安貧隨分樂丘園。',32,'全唐诗/poet.song.30000.json','["求富誠非憚執鞭，安貧隨分樂丘園。", "兩間茅屋青山下，贏得浮生避世喧。"]'),
('45f55c15-df0a-4b2a-a5c9-564a1a8d02dc','題北村六首  其三','張載','宋','宋诗','song-poetry','','[]','負郭吾廬二頃田，面山臨水跨通川。',32,'全唐诗/poet.song.30000.json','["負郭吾廬二頃田，面山臨水跨通川。", "蘇秦妾婦無高識，盛詫腰間六印懸。"]'),
('99ab87d2-4d4e-4505-8847-e6f1227fa997','題北村六首  其四','張載','宋','宋诗','song-poetry','','[]','風泉盈耳鬢斑斑，林下幽窗對萬山。',32,'全唐诗/poet.song.30000.json','["風泉盈耳鬢斑斑，林下幽窗對萬山。", "婦子職修簟食足，病身何幸亦安閑。"]'),
('75e611ae-fd1d-476c-9149-eaf72d1350c7','題北村六首  其五','張載','宋','宋诗','song-poetry','','[]','不堪煩暑病荒城，六月翛然寓野亭。',32,'全唐诗/poet.song.30000.json','["不堪煩暑病荒城，六月翛然寓野亭。", "珍重南山且歸去，再來相望雨中青。"]'),
('d79c450a-f485-426d-b379-e455a1375e64','題北村六首  其六','張載','宋','宋诗','song-poetry','','[]','渭南涇北已三遷，水旱縱橫數頃田。',32,'全唐诗/poet.song.30000.json','["渭南涇北已三遷，水旱縱橫數頃田。", "四十二年居陝右，老年生計似初年。"]'),
('f7e297e1-9500-4a1f-90d8-340d7653bf49','樂處','張載','宋','宋诗','song-poetry','','[]','樂處加功勉處行，事無甘苦必心亨。',32,'全唐诗/poet.song.30000.json','["樂處加功勉處行，事無甘苦必心亨。", "絅衣容有文章在，低首時人莫怨爭。"]'),
('e0c79198-8c7e-4132-b971-86f4a923c690','白髮','張載','宋','宋诗','song-poetry','','[]','白髮千梳晝景暄，烏瓶一啜夜窗寒。',32,'全唐诗/poet.song.30000.json','["白髮千梳晝景暄，烏瓶一啜夜窗寒。", "廟堂勤苦茅齋靜，不見人心是兩般。"]'),
('9b16b9e9-f10e-4741-87ea-ac6b07aafa3c','一室','張載','宋','宋诗','song-poetry','','[]','九萬笑鵬摶，幽居一室寬。',48,'全唐诗/poet.song.30000.json','["九萬笑鵬摶，幽居一室寬。", "雨聲便早睡，酒力壓新寒。", "懶覺閑多味，衰知死有端。", "此生吾自斷，不必夢邯鄲。"]'),
('fbe6bcfd-38a6-4880-b2f1-111117ae6e83','睢陽五老圖','張載','宋','宋诗','song-poetry','','[]','太平氣象養高閑，宴賞諸公老致冠。',64,'全唐诗/poet.song.30000.json','["太平氣象養高閑，宴賞諸公老致冠。", "朝野已聞親相業，廟堂曾睹漆丹桓。", "形容傑出新圖粲，德澤雄霑舊俗寒。", "一片忠心涵國史，桑田雖變迥謨看。"]'),
('af6f29be-c3c3-4137-ad38-f0846137a6d5','詩一首','張載','宋','宋诗','song-poetry','','[]','昌谷五月稻，平田垂青璣。',180,'全唐诗/poet.song.30000.json','["昌谷五月稻，平田垂青璣。", "遙巒相壓疊，頹綠互蔽芾。", "竹香滿凄寂，粉節塗生卉。", "攢蟲鎪古柳，芳徑生紅緯。", "鶯唱子夜歌，瀑懸楚被翡。", "昭華寒不粟，貴嬪暑無疿。", "桂蕊女幾簪，蕙花神娥扉。", "碧錦帖花檉，香衾事殘貴。", "霞巘殷嵯峨，煙嵐互靉霼。", "壁月舒窈斗，元雲爲彷彿。", "霠𩃟宛虹带，天空繁星衣。", "古檜拏屭贔，水華融觱沸。", "銷聲永薖軸，栖隱躭岑蔚。", "請事鴻寶元，至澹味無味。", "悲歌激流風，逸響迥秋氣。"]'),
('9ec61a86-0040-433b-90a0-25776ea84c2b','贈司馬君實','張載','宋','宋诗','song-poetry','','[]','二龍閑臥洛波清，今日都門獨餞行。',32,'全唐诗/poet.song.30000.json','["二龍閑臥洛波清，今日都門獨餞行。", "願得賢人均出處，始知深意在蒼生。"]'),
('6b0898b6-8936-4a3a-bc61-3d1910e760f0','句  其一','張載','宋','宋诗','song-poetry','','[]','十載相從應學得，怕人知事莫萌心。',16,'全唐诗/poet.song.30000.json','["十載相從應學得，怕人知事莫萌心。"]'),
('e827b326-3027-4445-9d04-07a435115177','句  其二','張載','宋','宋诗','song-poetry','','[]','若要居二宅，先須入禮門。',12,'全唐诗/poet.song.30000.json','["若要居二宅，先須入禮門。"]'),
('3987b605-e97a-4e75-aa46-8fcd97a84246','句  其三','張載','宋','宋诗','song-poetry','','[]','無限寒鴉冒雨飛。',8,'全唐诗/poet.song.30000.json','["無限寒鴉冒雨飛。"]'),
('fa870d38-f3fa-4446-aed6-8a3b927613b4','句  其四','張載','宋','宋诗','song-poetry','','[]','紅樹高高出粉牆。',8,'全唐诗/poet.song.30000.json','["紅樹高高出粉牆。"]'),
('c734dd48-6b6f-42fc-8c1c-77047d9e7269','句  其五','張載','宋','宋诗','song-poetry','','[]','苦厭塵沙隨馬足，卻思風浪拍船頭。',16,'全唐诗/poet.song.30000.json','["苦厭塵沙隨馬足，卻思風浪拍船頭。"]'),
('f8f50035-dc8f-4872-9c26-d21756cf61b7','句  其六','張載','宋','宋诗','song-poetry','','[]','一目全牛萬隙開。',8,'全唐诗/poet.song.30000.json','["一目全牛萬隙開。"]'),
('dc697cc8-76c8-4c4c-8f8c-bdc9f8dd0e64','句  其七','張載','宋','宋诗','song-poetry','','[]','歸燕羈鴻共斷魂，荻花楓葉泊孤村。',16,'全唐诗/poet.song.30000.json','["歸燕羈鴻共斷魂，荻花楓葉泊孤村。"]'),
('62274dfa-0289-4f0f-9610-f268bc46dc32','句  其八','張載','宋','宋诗','song-poetry','','[]','春菰牙露翠，水荇葉連青。',12,'全唐诗/poet.song.30000.json','["春菰牙露翠，水荇葉連青。"]'),
('f5538536-0607-4de0-9137-8d29d39a4e31','句  其九','張載','宋','宋诗','song-poetry','','[]','無疑菱荇香。',6,'全唐诗/poet.song.30000.json','["無疑菱荇香。"]'),
('43d9545a-b656-429e-9e26-7377b1d2896e','相公行','王陶','宋','宋诗','song-poetry','','[]','已枯斷竹鈞私被，既沒賢公帝念深。',32,'全唐诗/poet.song.30000.json','["已枯斷竹鈞私被，既沒賢公帝念深。", "仆木偃禾如不起，至今誰識大忠心。"]'),
('7b779d7c-6217-432a-94d3-99596e9ebe2e','異服','王陶','宋','宋诗','song-poetry','','[]','辛有嘆被髪，趙靈喜胡服。',108,'全唐诗/poet.song.30000.json','["辛有嘆被髪，趙靈喜胡服。", "遂成陸渾戎，終有沙丘辱。", "用夷反變夏，亡禮以從俗。", "先王仁義術，詎用此求福。", "齊桓九合功，不以兵車轂。", "仲尼嘆微管，幾爲左衽屬。", "爾來豪俠兒，往往異裝束。", "耀武何必然，禦戎有前躅。", "余敢告司關，異服宜禁肅。"]'),
('60298ba3-6cae-4a2c-99d4-5727accf1579','有竇復者世居鎮戎能道邊事','王陶','宋','宋诗','song-poetry','','[]','君不見鎮戎德順弓箭手，耕種官田自防守。',211,'全唐诗/poet.song.30000.json','["君不見鎮戎德順弓箭手，耕種官田自防守。", "相團置堡禦蕃軍，下視賊庭殊不有。", "殺羊取骨燃艾炙，試卜賦兵知拾寇。", "都校招呼入堡居，堡外重圍百里餘。", "牆低城小不難破，賊箭如棚城上過。", "堡中不及數十人，且鬥且罵且欣欣。", "登陴斫門謂平取，應弦死傷已無數。", "窗間定箭射酋豪，一箭已聞哭聲舉。", "爭將錦囊裹賊尸，鳴金收衆唯恐遲。", "不唯城堡依然固，吾衆不傷毫與釐。", "自從干戈動四鄙，覆軍殺將曾無恥。", "朝廷未省遺邊功，何事此勳不聞記。", "安得天兵百萬衆，盡如此輩堅且勇。"]'),
('3ed5a0f4-1c92-44fc-9065-37d97359e7b2','明智寺','王陶','宋','宋诗','song-poetry','','[]','邃壑重巒十里過，天圍佛境隱巖阿。',32,'全唐诗/poet.song.30000.json','["邃壑重巒十里過，天圍佛境隱巖阿。", "儻來功業忘情久，暫到山林結意多。"]'),
('b175cd5d-a398-4e26-965a-9932bda87ef6','佛光寺','王陶','宋','宋诗','song-poetry','','[]','五臺山上白雲浮，雲散臺高境自幽。',64,'全唐诗/poet.song.30000.json','["五臺山上白雲浮，雲散臺高境自幽。", "歷代珠幡懸法界，累朝金剎列峰頭。", "風雷激烈龍池夜，草木凄涼雁塞秋。", "世路忙忙名利客，塵機到此盡應休。"]'),
('07e687c1-ed9f-4914-bc87-aef7e89b0ded','詠月','釋樟不','宋','宋诗','song-poetry','','[]','月輪端似古人心，皎潔高深處處臨。',32,'全唐诗/poet.song.30000.json','["月輪端似古人心，皎潔高深處處臨。", "縱在波濤圓缺定，照塵塵亦不能侵。"]'),
('2fad548d-7d48-4185-93b6-1da7e6a0501d','句','夏噩','宋','宋诗','song-poetry','','[]','謝守風流爲勝事，杜郎吟咏屬多才。',16,'全唐诗/poet.song.30000.json','["謝守風流爲勝事，杜郎吟咏屬多才。"]'),
('3a6c5b3f-1d96-4020-8cfb-b49566e93048','送程給事知越州','丁執禮','宋','宋诗','song-poetry','','[]','曉辭龍尾下青冥，持節東南一鎮並。',64,'全唐诗/poet.song.30000.json','["曉辭龍尾下青冥，持節東南一鎮並。", "共治蚤分天萬寄，暮來今頌里民聲。", "吟高郢雪誰能擬，韻敵壺冰凜更清。", "遙想棠陰多暇日，江風吹角繞蓬瀛。"]'),
('95549c32-a55f-4037-ad14-a91f55175661','尋餘姚上林湖山','謝景初','宋','宋诗','song-poetry','','[]','山水有奇秀，何必耳目親。',132,'全唐诗/poet.song.30000.json','["山水有奇秀，何必耳目親。", "茲地世未知，偶游良可珍。", "平湖瞰其中，翠巘圍四垠。", "青松千萬植，落瀑如懸巾。", "佛廟聳殿塔，裝點繪圖新。", "清溪與斷崖，水石聲磷磷。", "峰巓見滄海，日出常先晨。", "花草時節異，寧問秋夏春。", "陵谷千萬古，豈無稱道人。", "德微言不信，又恐遠故堙。", "樽酒且樂我，醉來事事均。"]'),
('f35f296d-9989-49bd-8b21-a3decb181d43','觀餘姚海氛','謝景初','宋','宋诗','song-poetry','','[]','海上風與雨，未眹先氣升。',72,'全唐诗/poet.song.30000.json','["海上風與雨，未眹先氣升。", "澤鹵雜山雲，蓊鬰相薰蒸。", "交語面已障，安辨丘與陵。", "衣濡带革緩，臭腥殊可憎。", "自非昌其陽，疾癘得以乘。", "君子卻陰邪，何必醫師能。"]'),
('14944749-8c10-4307-b00b-7fe34159ba1f','餘姚董役海堤有作','謝景初','宋','宋诗','song-poetry','','[]','五行交相陵，海水不潤下。',72,'全唐诗/poet.song.30000.json','["五行交相陵，海水不潤下。", "處處壞堤防，白浪大於馬。", "顧予爲其長，恐懼敢暫捨。", "董衆完築塞，跋履率曠野。", "使人安於生，茲不羞民社。", "調和陰與陽，自有任責者。"]'),
('cdfcc201-2837-4cb3-8a3d-39b11e68163c','觀仙居山瀑布','謝景初','宋','宋诗','song-poetry','','[]','落泉下峭壁，斗絕千萬丈。',72,'全唐诗/poet.song.30000.json','["落泉下峭壁，斗絕千萬丈。", "濺急雪片飛，望若匹練廣。", "曲嶺隔青林，三里已聞響。", "其旁有巨石，平潤可俯仰。", "愚俗所不道，我輩偶來賞。", "須期秋色清，攀蘿將爾上。"]'),
('c5f2030b-fb5d-430b-99b8-784b6bf7cbdf','觀上林垍器','謝景初','宋','宋诗','song-poetry','','[]','作竈長如丘，取土深於塹。',96,'全唐诗/poet.song.30000.json','["作竈長如丘，取土深於塹。", "踏輪飛爲模，覆灰色乃紺。", "力疲手足病，欲憩不敢暫。", "發窰火以堅，百裁一二占。", "里中售高賈，鬥合漸收斂。", "持歸示北人，難得曾罔念。", "賤用或棄樸，爭乞寧有厭。", "鄙事聖猶能，今予乃親覘。"]'),
('fb17c8e0-2247-4fde-af7c-1e2aa0311556','粵俗','謝景初','宋','宋诗','song-poetry','','[]','粵俗嗜海物，鱗介無一遺。',96,'全唐诗/poet.song.30000.json','["粵俗嗜海物，鱗介無一遺。", "蝦蠃味已厚，況乃蟹與蜞。", "潮來浦嶼漲，遮捕張藩籬。", "潮去沙滿灘，拾掇盈籬箕。", "殺烹數莫記，瑣碎臭且奇。", "苟務貪咀嚼，寧識暴殄悲。", "蛟蜃吐雲氣，腹以人爲飴。", "呀口日肥大，洪波誰敢窺。"]'),
('9ea5a07e-47d8-4079-a30a-e4719ca09f93','禁煙即事','謝景初','宋','宋诗','song-poetry','','[]','時節一百五，疾風收雨天。',48,'全唐诗/poet.song.30000.json','["時節一百五，疾風收雨天。", "鳥催青帝馭，人重子推錢。", "蹴踘逢南陌，鞦韆送晚煙。", "墦間無限醉，唯我獨蕭然。"]'),
('4f3ee882-e391-4882-8522-8c0502306978','法喜堂','謝景初','宋','宋诗','song-poetry','','[]','虛堂庇風雨，結構不務壯。',96,'全唐诗/poet.song.30000.json','["虛堂庇風雨，結構不務壯。", "外飾無髹髵，置物況容長。", "開篋藥劑靈，拈棋白黑抗。", "階花澹亦夭，庭石碧交向。", "出門鳥雀喧，燕處物我喪。", "吳俗夸有素，佛徒侈相尚。", "獨能守質靜，坐以矯流宕。", "棲之果自喜，何須山海上。"]'),
('bb0f6c08-dd25-421d-8097-bc64aa5dfd4a','送唐介南遷  其一','謝景初','宋','宋诗','song-poetry','','[]','長蛇齒牙毒，誰使赤手捕。',48,'全唐诗/poet.song.30000.json','["長蛇齒牙毒，誰使赤手捕。", "六月河破堤，捧塊捍奔注。", "匹夫徒昭昭，天下皆慕顧。", "後世有至公，此計不爲誤。"]'),
('3f9bd1d4-37a1-4fe0-b3dc-8faac4c80a77','送唐介南遷  其二','謝景初','宋','宋诗','song-poetry','','[]','木秀風所折，膏明自煎然。',48,'全唐诗/poet.song.30000.json','["木秀風所折，膏明自煎然。", "折固理之必，明性其可遷。", "趨向人各異，公議日月懸。", "開言死不測，喑噤貴且年。"]'),
('7d1c1cb7-5e10-400b-ad87-cbbfca9d28d9','送唐介南遷  其三','謝景初','宋','宋诗','song-poetry','','[]','鬰鬰炎海旁，氣蒸霧露毒。',48,'全唐诗/poet.song.30000.json','["鬰鬰炎海旁，氣蒸霧露毒。", "得罪往投畀，幸貸吭頸戮。", "彼心學聖賢，於義無不足。", "奈何觸主威，未嘗有是辱。"]'),
('b78b74fa-49c9-4c54-bb8c-61d904cb71bc','送唐介南遷  其四','謝景初','宋','宋诗','song-poetry','','[]','身任言責地，眼見公路埋。',48,'全唐诗/poet.song.30000.json','["身任言責地，眼見公路埋。", "胡寧包心顔，踐履天子階。", "言出謫隨至，吏送南海涯。", "一臣不足惜，喋籭狽與豺。"]'),
('4d77dcb3-40ef-4817-bd67-01f4d449753d','送唐介南遷  其五','謝景初','宋','宋诗','song-poetry','','[]','諫逐古今有，例爲朝政疵。',48,'全唐诗/poet.song.30000.json','["諫逐古今有，例爲朝政疵。", "況與廊廟臣，世復惡其私。", "安危治亂迹，此事姑置之。", "儻未監謗者，失得何須悲。"]'),
('ab312ecf-544e-4427-8e22-59d9336ef5e5','和吳中復江瀆泛舟','謝景初','宋','宋诗','song-poetry','','[]','雨飛暑館變秋堂，息駕林祠意緒長。',64,'全唐诗/poet.song.30000.json','["雨飛暑館變秋堂，息駕林祠意緒長。", "筍脫萬苞風韻玉，蓮開百畝水浮香。", "楸盤力戰棋忘味，筠簟清吟扇遞涼。", "心惜吏閑文酒樂，雅歡未既即離觴。"]'),
('3ec70516-c959-4668-9a4b-6b1d7364279b','句  其一','謝景初','宋','宋诗','song-poetry','','[]','倒著衣裳迎戶外，盡呼兒女拜燈前。',16,'全唐诗/poet.song.30000.json','["倒著衣裳迎戶外，盡呼兒女拜燈前。"]'),
('38efa58f-fdf5-4126-8c25-ac3b27d5e33a','句  其二','謝景初','宋','宋诗','song-poetry','','[]','峰巓見滄海，日出常先最。',12,'全唐诗/poet.song.30000.json','["峰巓見滄海，日出常先最。"]'),
('953ae25a-e7fd-42bb-bc8d-a7f96d799b40','泛汝聯句','孫永','宋','宋诗','song-poetry','','[]','平居厭城郭，具舟泛清汝。',288,'全唐诗/poet.song.30000.json','["平居厭城郭，具舟泛清汝。", "藍光一水遠，鐵色兩崖古。", "日華動中流，沙紋亂前渚。", "湍鳴達公橋，草綠襄王墓。", "園英擁流沫，風葉墮殘雨。", "停橈弄山泉，扶杖過花塢。", "澄潭數亂石，斷石橫顛樹。", "泳波魚鬣舒，闖穴蛙首怒。", "衝雲一雁遠，唼荇羣鷗聚。", "村間桑柘春，川闊牛羊暮。", "回頭綠樹失，卷幔青峰露。", "尋幽恣盤桓，泊淺屢回互。", "靈草不知名，珍禽啼在處。", "夕陽散鳴鳩，荒阡拱游兔。", "挽纜謠歌童，簪花立田婦。", "高歌客自如，歸涉人相負。", "青蒲戢戢生，紫燕翩翩度。", "雲煙波底明，井邑林外睹。", "欣逢閭里舊，愧乏雞黍具。", "緡水薦囦鱗，掘石羞山茹。", "繞塘梅實綠，冒桂禽殻素。", "我巾聊一頹，石榼煩屢注。", "朱櫻出芳林，紫筍侑雕俎。", "高篇爛珠璧，至樂謝鐘鼓。"]'),
('cbdc20e8-889d-45e6-97a1-86e0638baae3','清明','孫永','宋','宋诗','song-poetry','','[]','每年每遇清明節，把酒尋花特地忙。',32,'全唐诗/poet.song.30000.json','["每年每遇清明節，把酒尋花特地忙。", "今日江頭衰病起，神前新火一爐香。"]'),
('89371300-a390-4212-bbcd-734037e9d753','上巳日','孫永','宋','宋诗','song-poetry','','[]','海內中和日，雲間上巳辰。',24,'全唐诗/poet.song.30000.json','["海內中和日，雲間上巳辰。", "笙歌九天半，花木十洲春。"]'),
('bcc79e51-073d-4a80-a205-a69ca254ffa4','送程給事知越州','滕元發','宋','宋诗','song-poetry','','[]','又領州麾過故鄉，誰憐肝膽異班行。',64,'全唐诗/poet.song.30000.json','["又領州麾過故鄉，誰憐肝膽異班行。", "患銷南海城先具，氣壓胡天國自強。", "造膝華褒輝黼黻，跋朝佳句敵琳瑯。", "聖君求治如星火，休鬥新詩萬丈光。"]'),
('d930142e-2e34-405e-b237-6a9db7d5649b','寄越州范希文太守','滕元發','宋','宋诗','song-poetry','','[]','江山千里接仁風，都在東南秀氣中。',32,'全唐诗/poet.song.30000.json','["江山千里接仁風，都在東南秀氣中。", "爲問玉皇香案吏，蓬萊何似水晶宮。"]'),
('09524ffd-7d7c-4081-b48c-21a8fd632a9f','結客','滕元發','宋','宋诗','song-poetry','','[]','結客結英豪，休同兒女曹。',48,'全唐诗/poet.song.30000.json','["結客結英豪，休同兒女曹。", "黄金裝箭鏃，猛獸畫旗旄。", "北閣芒星落，中原王氣高。", "終令賀蘭賊，不著赭黄袍。"]'),
('fdbe07f4-8a96-4cd9-9c67-da47bcfe164c','浮雲樓','滕元發','宋','宋诗','song-poetry','','[]','舉頭便是長安日，弄袖時飄夢澤風。',32,'全唐诗/poet.song.30000.json','["舉頭便是長安日，弄袖時飄夢澤風。", "茂苑久拋飛鳥外，楚臺遙在碧雲中。"]'),
('31789970-b4a9-46ae-9b9d-cc3b3387c8ab','送俞汝尚致仕還鄉','滕元發','宋','宋诗','song-poetry','','[]','清明沖節是身謀，御史郎把不肯留。',64,'全唐诗/poet.song.30000.json','["清明沖節是身謀，御史郎把不肯留。", "回首軒裳雙脫屣，放懷天地一輕漚。", "卞雲苕月柴門靜，菱雨蘋風野艇秋。", "仰羨冥鴻空自愧，區區圖報未知休。"]'),
('65820692-f094-4ff3-a912-0675d08bf62e','句  其一','滕元發','宋','宋诗','song-poetry','','[]','萬國休兵外，羣生奏凱中。',12,'全唐诗/poet.song.30000.json','["萬國休兵外，羣生奏凱中。"]'),
('d5d87de9-b2a6-419c-804c-f8eee64a4d84','句  其二','滕元發','宋','宋诗','song-poetry','','[]','寒日邊聲斷，春風塞草長。',24,'全唐诗/poet.song.30000.json','["寒日邊聲斷，春風塞草長。", "傳聞漢都護，歸奉萬年觴。"]'),
('111dddd1-5d6e-4ab6-bb3d-bb743808d576','句  其三','滕元發','宋','宋诗','song-poetry','','[]','葱嶺占佳氣，氈裘拜未央。',12,'全唐诗/poet.song.30000.json','["葱嶺占佳氣，氈裘拜未央。"]'),
('40e2333c-ebb7-4caa-89b2-83d601b382f7','句  其四','滕元發','宋','宋诗','song-poetry','','[]','野色更無山隔斷，天光直與水相連。',16,'全唐诗/poet.song.30000.json','["野色更無山隔斷，天光直與水相連。"]'),
('099f35a4-c596-4620-9b64-03d1b0a466e7','句  其五','滕元發','宋','宋诗','song-poetry','','[]','負鼎早爲湯右相，有文今作魯夫人。',16,'全唐诗/poet.song.30000.json','["負鼎早爲湯右相，有文今作魯夫人。"]'),
('258e83d2-7c4d-4915-bc1a-2f0192bd3822','句  其六','滕元發','宋','宋诗','song-poetry','','[]','主人留客醉，酒美蟹螯肥。',12,'全唐诗/poet.song.30000.json','["主人留客醉，酒美蟹螯肥。"]'),
('52220948-cc48-44ce-8ba1-84ed1d58b1be','辭衆','釋宗本','宋','宋诗','song-poetry','','[]','本是無家客，那堪任便遊。',24,'全唐诗/poet.song.30000.json','["本是無家客，那堪任便遊。", "順風加櫓棹，船子下揚州。"]'),
('71b25b67-120e-4dea-b6ae-5648c6592234','賦石鼓','釋宗本','宋','宋诗','song-poetry','','[]','造化功成難可測，不論劫數莫窮年。',32,'全唐诗/poet.song.30000.json','["造化功成難可測，不論劫數莫窮年。", "如今橫在孤峰上，解聽希聲用大千。"]'),
('31248840-b59f-4190-a051-bd124412f121','答東坡居士','釋法泉','宋','宋诗','song-poetry','','[]','指出明明是甚麽，舉頭鷂子穿雲過。',32,'全唐诗/poet.song.30000.json','["指出明明是甚麽，舉頭鷂子穿雲過。", "從來這碗最希奇，解問燈人能幾箇。"]'),
('a00617f6-cb43-4949-9ddd-377af8aae557','送東坡居士','釋法泉','宋','宋诗','song-poetry','','[]','脚下曹溪去路通，登堂無復問幡風。',32,'全唐诗/poet.song.30000.json','["脚下曹溪去路通，登堂無復問幡風。", "好將鍾阜臨歧句，說似當年踏碓翁。"]'),
('8e4e51a5-17e3-48ea-94c9-2d2da03ce29d','悼趙清獻公抃','釋法泉','宋','宋诗','song-poetry','','[]','仕也邦爲瑞，歸歟世作程。',48,'全唐诗/poet.song.30000.json','["仕也邦爲瑞，歸歟世作程。", "人間金粟去，天上玉樓成。", "慧劍無纖缺，冰壺徹底清。", "春風瀔水路，孤月照雲明。"]'),
('12116603-e453-44df-9943-91e995b1a464','偈七首  其一','釋法泉','宋','宋诗','song-poetry','','[]','來不來，去不去。',52,'全唐诗/poet.song.30000.json','["來不來，去不去。", "脚下須彌山，腦後擎天柱。", "大藏不能宣，佛眼不能覷。", "諸禪德，漸老逢春解惜春，昨夜飛花落無數。"]'),
('68040408-4e36-48ba-aea3-cd46672468dd','偈七首  其二','釋法泉','宋','宋诗','song-poetry','','["\u5199\u8bd7", "\u4e2d\u79cb\u8282", "\u8d4f\u6708"]','團團離海嶠，漸漸出雲衢。',24,'全唐诗/poet.song.30000.json','["團團離海嶠，漸漸出雲衢。", "此夜一輪滿，清光何處無。"]'),
('e946ab91-b8ab-4e1c-9ab2-6fea77e47ae8','偈七首  其三','釋法泉','宋','宋诗','song-poetry','','[]','要去不得去，要住不得住。',24,'全唐诗/poet.song.30000.json','["要去不得去，要住不得住。", "打破大散關，脫卻娘生袴。"]'),
('ad3083ce-76f9-41e4-9038-53ddfbaf12f4','偈七首  其四','釋法泉','宋','宋诗','song-poetry','','[]','時人欲識南禪路，門前有箇長松樹。',48,'全唐诗/poet.song.30000.json','["時人欲識南禪路，門前有箇長松樹。", "腳下分明不較多，無奈行人恁麽去。", "莫恁去，急回顧，樓臺煙鎖鐘鳴處。"]'),
('86370e4f-6861-45dd-afea-92aa18f188ab','偈七首  其五','釋法泉','宋','宋诗','song-poetry','','[]','文殊笑，普賢嗔，眼裏無筋一世貧。',32,'全唐诗/poet.song.30000.json','["文殊笑，普賢嗔，眼裏無筋一世貧。", "相逢盡道休官去，林下何曾見一人。"]'),
('b55d85d8-d973-4e05-b394-89b10972f494','偈七首  其六','釋法泉','宋','宋诗','song-poetry','','[]','快人一言，快馬一鞭。',50,'全唐诗/poet.song.30000.json','["快人一言，快馬一鞭。", "若更眼睛定動，未免紙裹麻纏。", "脚下是地，頭上是天。", "不信但看八九月，紛紛黄葉滿山川。"]'),
('1ba917f0-bf20-429c-80b7-0856f1491dd1','偈七首  其七','釋法泉','宋','宋诗','song-poetry','','[]','非佛非心徒擬議，得皮得髓謾商量。',32,'全唐诗/poet.song.30000.json','["非佛非心徒擬議，得皮得髓謾商量。", "臨行珍重諸禪侶，門外千山正夕陽。"]'),
('230b5d8e-0a3b-4303-9db5-837fed0d98b1','北邙行','釋法泉','宋','宋诗','song-poetry','','[]','前山後山高峨峨，喪車轔轔日日過。',288,'全唐诗/poet.song.30000.json','["前山後山高峨峨，喪車轔轔日日過。", "哀歌幽怨港巖谷，聞者潛悲薤露歌。", "哀歌一聲千載別，孝子順孫徒泣血。", "世間何物得堅牢，大海須彌竟磨滅。", "人生還如露易晞，從來有會終別離。", "苦樂哀感不暫輟，況復百年驚夢馳。", "去人悠悠不復至，今人不會古人意。", "栽松起石駐墓門，欲爲死者長年計。", "魂魄悠揚形化土，五趣茫茫井輪度。", "今人還葬古人墳，今墳古墳無定主。", "洛陽城裏千萬人，終爲北邙山下塵。", "沈迷不記歸時路，爲君孤坐長悲辛。", "昔日送人哭長道，今爲孤墳臥芳草。", "妖狐穿穴藏子孫，耕夫撥骨尋珠寶。", "老木蕭蕭生野風，東西壞塚連晴空。", "寒食已過誰享祀，塚畔餘花寂寞紅。", "日月相催若流矢，富貴賢愚盡如此。", "安得同遊常樂鄉，縱經劫火無生死。"]'),
('46307752-29c1-4244-8124-2a49de359259','佛印元公自京師還作詩贈之','釋可遵','宋','宋诗','song-poetry','','[]','上國歸來路幾千，渾身猶带御爐煙。',32,'全唐诗/poet.song.30000.json','["上國歸來路幾千，渾身猶带御爐煙。", "鳳凰山下敲篷咏，驚起山翁白晝眠。"]'),
('c1df839f-aff3-4b93-94dd-ba8110a91d92','題湯泉壁','釋可遵','宋','宋诗','song-poetry','','[]','禪庭誰立石龍頭，龍口湯泉沸不休。',32,'全唐诗/poet.song.30000.json','["禪庭誰立石龍頭，龍口湯泉沸不休。", "直待衆生塵垢盡，我方清冷混常流。"]'),
('2f5d3fc4-5e67-4417-8c11-25011fcfc0fa','贈東坡','釋可遵','宋','宋诗','song-poetry','','[]','君能識我湯泉句，我卻愛君三峽詩。',32,'全唐诗/poet.song.30000.json','["君能識我湯泉句，我卻愛君三峽詩。", "道得可嚥不可潄，幾多詩將竪降旗。"]'),
('9e10fa40-a7bf-4a76-842f-362c0d5b4a94','句','釋可遵','宋','宋诗','song-poetry','','[]','掣電引狂雷，晝天忽成暮。',24,'全唐诗/poet.song.30000.json','["掣電引狂雷，晝天忽成暮。", "萬里瀉銀河，四簷垂瀑布。"]'),
('46dfce72-0731-45f2-80bc-270cb24e6df0','南郊大禮慶成詩五首 朝享景靈宮','蘇頌','宋','宋诗','song-poetry','','[]','惟宋五世，將郊泰玄。',120,'全唐诗/poet.song.30000.json','["惟宋五世，將郊泰玄。", "祗若前典，欽崇道尊。", "其日吉午，天時薄寒。", "帝出齋寢，朝神紫垣。", "降輅就次，被龍搢山。", "禮薦蒼玉，樂歌太安。", "酌以瓊醴，羞以靈飧。", "飆御來格，上誠益虔。", "思我基命，系於帝軒。", "真祖膺符，錫類貽孫。", "皇繼其志，受祉彌繁。", "炎炎景歷，億萬斯年。"]'),
('e2290ec9-5327-4746-b370-9ff92abf0d81','南郊大禮慶成詩五首 薦享于太廟','蘇頌','宋','宋诗','song-poetry','','[]','天命有宋，系軒纂唐。',120,'全唐诗/poet.song.30000.json','["天命有宋，系軒纂唐。", "祖武宗文，積厚流光。", "奕奕清廟，八祏同堂。", "五祀備饗，百順儲祥。", "皇帝孝思，明發不忘。", "躬執圭瓚，再薦嘉觴。", "公卿陟降，鼎俎芬芳。", "廣樂九變，群神迪嘗。", "昭我先烈，緝熙萬方。", "永思繼述，成不敢康。", "始朝于廟，詩歌嗣王。", "烈聖在天，保佑我皇。"]'),
('2b6aae2f-0cb7-443c-990f-480a9c1f065a','南郊大禮慶成詩五首 有事于南郊','蘇頌','宋','宋诗','song-poetry','','[]','惟皇繼天，宅位三禩。',120,'全唐诗/poet.song.30000.json','["惟皇繼天，宅位三禩。", "靈德及遠，嘉生茂遂。", "仲冬月良，一陽氣至。", "上將告成，禮嚴肆類。", "自廟徂郊，萬靈拱衛。", "天收宿雰，日麗佳氣。", "月逾既望，再登午陛。", "對越蒼祗，配以太帝。", "奠玉酌匏，升烟燎幣。", "志盡虔恭，備成熙事。", "玉輿旋衡，歡聲沸渭。", "皇專乃誠，下蒙厥惠。"]'),
('7056840e-9106-4962-ba38-eccac6f64ab3','南郊大禮慶成詩五首 賜赦宣德門','蘇頌','宋','宋诗','song-poetry','','[]','帝陟圜丘，天降之祜。',120,'全唐诗/poet.song.30000.json','["帝陟圜丘，天降之祜。", "嘉與士民，均承福祚。", "還御端闈，躬布皇度。", "鷄星驗占，鵠書臚句。", "慶浹天淵，恩霏雨露。", "滌垢棄瑕，蠲租薄賦。", "三泉靡封，五刑幾措。", "太和充塞，群心率籲。", "自古無赦，孰除詿誤。", "我朝本仁，實清弊斁。", "赦匪其私，仁則有裕。", "萬民以懷，邦基鞏固。"]'),
('495c5a2e-ff1e-4e28-973b-5a4de655228d','南郊大禮慶成詩五首 發冊文德殿','蘇頌','宋','宋诗','song-poetry','','[]','大孝尊親，治本人倫。',120,'全唐诗/poet.song.30000.json','["大孝尊親，治本人倫。", "自家之政，所以刑民。", "天正元日，帝郊畢禋。", "將崇母儀，爰即嘉辰。", "正朝乾闢，羽衛星陳。", "金石既作，公卿薦臻。", "帝步西序，躬咨爾臣。", "授以冊寶，極其禮文。", "群官在位，靡不歡欣。", "謂天子孝，感于人神。", "祝天子年，後于靈椿。", "皇心匪懈，聖度惟新。"]'),
('c2dcb8b7-eb12-4dd5-a170-77ada543eb29','元日鴻慶宮朝拜二十韵','蘇頌','宋','宋诗','song-poetry','','[]','上國房心次，仙都太紫微。',240,'全唐诗/poet.song.30000.json','["上國房心次，仙都太紫微。", "璧門開倣雉，金闕立如翬。", "昔聖躬三祀，乘時動六飛。", "奠圭渦曲已，鳴蹕渙陽歸。", "孚號興王澤，尊名象日畿。", "經營原廟制，虔鞏上天威。", "祖系崇軒鼎，宗祊奉漢衣。", "豫游恩甚盛，謁款禮無違。", "却顧和鸞迹，咸嗟歲序非。", "璿源流永永，堯德冠巍巍。", "我后遵鴻烈，聲明極範圍。", "乾坤扶寶曆，日月拱琳扉。", "朝會元正始，班聯內著依。", "敘官風憲肅，就列羽儀輝。", "北面鸞分黨，東隅斗轉機。", "寒銷冰玉砌，風繞大龍旂。", "瑞色花藏綠，歡聲霧散霏。", "未竣真館集，遥仰帝陽晞。", "至治尤遐邈，先猷重發揮。", "邦人徒望幸，延首向端闈。"]'),
('a6a8a26f-b52d-42c7-9bcd-b108540349e7','恭和御製賞花釣魚','蘇頌','宋','宋诗','song-poetry','','[]','四照仙花次第開，上林重睹屬車來。',64,'全唐诗/poet.song.30000.json','["四照仙花次第開，上林重睹屬車來。", "雨晴馳道紆天步，風引濃香到壽杯。", "瑞燕入檐時拂掠，恩魚窺釣更徘徊。", "柏梁絕唱容賡綴，獨愧非才亦與陪。"]'),
('bf6d9ddb-0580-4ec2-a6be-c1ff2b0009d0','恭和御製上元觀燈','蘇頌','宋','宋诗','song-poetry','','[]','寶杯蓮燭艷宮臺，萬戶千門五夜開。',64,'全唐诗/poet.song.30000.json','["寶杯蓮燭艷宮臺，萬戶千門五夜開。", "樓下舞韶清吹發，雲間鳴蹕翠華來。", "九賓宴集占風使，四近班陞構夏材。", "自愧周南獨留滯，十三年隔侍臣杯。"]'),
('29edcd43-9f1a-480e-92b2-42b345da44f8','恭和御製賜太師致仕文彥博五言六韵詩一首','蘇頌','宋','宋诗','song-poetry','','[]','曉日清明霽，華林物色新。',72,'全唐诗/poet.song.30000.json','["曉日清明霽，華林物色新。", "詔頒慈惠宴，恩厚老成人。", "衮冕三川客，杯觴四府臣。", "獻酬同飽德，愷樂盡含醇。", "帝惜營丘去，民思尹氏均。", "宸章一褒賁，道不愧如仁。"]'),
('f36c3cf1-00b4-45ee-94dd-57ae17fd377a','恭和御製賜太師致仕文彥博七言四韵詩一首','蘇頌','宋','宋诗','song-poetry','','[]','出處逢時道不殊，當年功立老閒居。',64,'全唐诗/poet.song.30000.json','["出處逢時道不殊，當年功立老閒居。", "來膺冕紱三公命，歸奉雲章五色書。", "社稷元臣名已遂，山河雄鎮寵仍疏。", "瓊林詔餞衣冠盛，豈止都門百兩車。"]'),
('85112188-99c9-4188-844b-c814130b5efc','謝賜御書詩五言十二韵','蘇頌','宋','宋诗','song-poetry','','[]','聖學天攸縱，宸文日又新。',144,'全唐诗/poet.song.30000.json','["聖學天攸縱，宸文日又新。", "因摛鏤牙管，分賜挈囊臣。", "玉几繙經暇，瑶宮錫宴辰。", "清躬忘旰食，睿藻出絲綸。", "才賞唐詞客，人稱賀季真。", "開編掇風什，灑翰落霜筠。", "楷法前無古，書評妙入神。", "良慚孤陋甚，獲對寵光頻。", "得異登床誚，藏過韞匵珍。", "護持同始卒，荷戴等穹旻。", "職幸聯簪筆，憂常念負薪。", "惟勤黄卷業，仰答大君仁。"]'),
('363a50b5-08f0-495b-b3fe-2305f46e9209','皇帝初郊大禮慶成詩','蘇頌','宋','宋诗','song-poetry','','[]','六帝貽謀聖繼明，兩宮崇祀上躬行。',320,'全唐诗/poet.song.30000.json','["六帝貽謀聖繼明，兩宮崇祀上躬行。", "熙壇初展嚴禋報，觀盥三終孝享成。", "仰法祖宗尊本始，致隆高厚罄純精。", "告虔並薦圓方玉，在滌交充繭栗牲。", "吉土兆南殊漢畤，景圭迎至協周正。", "羽旄備物甘泉仗，觚陛層垓委粟營。", "齋寢累朝思志意，真廷穀旦奉粢盛。", "八神警蹕敺氛沴，九貊梯航入貢菁。", "過廟徂郊紆步武，撤茵停蓋肅公卿。", "服裘尚質遵前製，配冊修辭正重名。", "篆鼎割烹工奏夏，午階登降斗旋衡。", "先時非霧滋鱗隰，竟夕祥光燭縵城。", "鐘虡四廂庭樂畢，樵蒸千石燎煙輕。", "龍回雕輦昇嶢闕，鶴負恩書下采楹。", "海外鷄星占澤霈，樓前鼉鼓震霆驚。", "風雲氣應靈臺候，雷雨仁深犴圄清。", "有昊感通欽輔德，聿修寅畏念持盈。", "旁求遺逸搜巖穴，寬舍租逋惠隸氓。", "天錫泰元神策瑞，民歌華黍歲豐聲。", "老臣扈從知何補，敢次輿言頌太平。"]'),
('59432988-99cc-459d-a909-5fa80a8179a0','恭謝慶成詩十韵','蘇頌','宋','宋诗','song-poetry','','[]','聖孝當天世繼明，兩全能饗禮交行。',160,'全唐诗/poet.song.30000.json','["聖孝當天世繼明，兩全能饗禮交行。", "路朝躬款三年報，齋寢先端七日誠。", "穹厚博臨通肸蠁，祖宗嚴祀極專精。", "冕章從質更新製，鐘虡鏗純復舊聲。", "舞佾前陳徽烈茂，燎煙升達上儀成。", "不祈厚福歸諸己，務達厖恩及庶氓。", "還御端闈孚大號，載頒元曆慶鴻名。", "歡謠沸渭盈都輦，協氣旁流浹海瀛。", "百辟旅庭紛嶽抃，四方延首效葵傾。", "帝心虔鞏常無怠，億萬斯年享治平。"]'),
('7098702a-a9f0-4a2f-94e1-534e8b6c7901','送鄭無忌南歸','蘇頌','宋','宋诗','song-poetry','','[]','我家本南閩，處世若羈寓。',288,'全唐诗/poet.song.30000.json','["我家本南閩，處世若羈寓。", "侍親從宦遊，東西遷者屢。", "因循歷年載，未識南中路。", "間歲至都城，始與里儒遇。", "嘗聞閩中奇，英雋所叢聚。", "山川降靈氣，稟肖時魁梧。", "往在祥符中，黄李稱獨步。", "當時盛文物，在廷充振鷺。", "二子簉其間，軒軒並鑣驅。", "得志何所如，康莊躍騏馵。", "時文變新律，高辭無累句。", "人傳幼婦碑，朝奏客卿賦。", "奇器擅珪璧，至音有韶濩。", "當宁喜同時，士林爭景附。", "淵澄或無魚，木秀乃生蠹。", "嗟哉士之賢，入朝嘗見惡。", "叔才亦稍遷，秘書觀四庫。", "命窮時不偶，伶仃獨翁孺。", "名雖鼎甲貴，官止塵勞污。", "蹉跎三十年，困躓卒顛仆。", "伊予生後時，舉頸徒企慕。", "鄭子乃其甥，肖貌何穎悟。", "讀書博而詳，偉詞亦能鑄。", "朅來至京國，首與予款晤。"]'),
('7202105a-d7e4-4f29-89ec-3709e6acf5c2','送王秀才出京','蘇頌','宋','宋诗','song-poetry','','[]','都城大雪酒價高，我送故人傾濁醪。',304,'全唐诗/poet.song.30000.json','["都城大雪酒價高，我送故人傾濁醪。", "酒闌置杯欲話別，不覺中心生鬰陶。", "丈夫聚散豈爲念，所嘆人事多徒勞。", "憶昔我年未弱冠，西來觀藝遊神皋。", "金門獻賦嗟失路，因循四載何所遭。", "京華碌碌少知己，但聞嘲弄聲嗷嗷。", "今年詔書恤西事，大開言路烝群髦。", "因思平生負氣概，臨事始可觀持操。", "長纓羈虜豈無計，策慮未獻心徒忉。", "感君壯志正凌厲，術業沈究鈐與韜。", "上書論畫兵家事，直請西去親鞬櫜。", "又言若將衆十旅，可爲手足除紛搔。", "逾時待報不聞命，西秦便欲從遊遨。", "束書携劍瞥然去，却顧名利輕如毛。", "我謂方今正急士，帝言屢下搜英豪。", "公卿悉意奉詔旨，推賢好善如干旄。", "勸君失意且韜養，有能必見時稱褒。", "中朝列爵本馭衆，進任將相皆儒曹。", "一時未遇何須嘆，吾輩豈久居蓬蒿。"]'),
('268fffb8-2b26-4317-b098-7fcd69cdcdf2','和丘與權秘校咏寶寄林成之進士','蘇頌','宋','宋诗','song-poetry','','[]','天下豈無寶，此寶常曠乏。',288,'全唐诗/poet.song.30000.json','["天下豈無寶，此寶常曠乏。", "渾然肖天質，不與璆璠雜。", "萬産蓄精粹，百靈常護押。", "天王得而興，人事留豈盍。", "問將安所施，邦國憑鎮壓。", "問誰能爲售，靡物可酬答。", "孰嗟道不行，將以補千衲。", "孰憂大厦摧，用以支衆庘。", "在昔夏及周，相繼登天榻。", "搜索罄寰瀛，異物悉歸狎。", "萬玉會諸塗，九鼎安於郟。", "人神爲交歡，海嶽在呼欱。", "無遠不奔趨，無强不折拉。", "區區霸者君，猶能救收扱。", "譬夫至音奏，所聽纔鞺鞳。", "晉强由一戰，齊盛成九合。", "小邦願輸幣，鄰境求盟歃。", "至寶既見用，光價日以洽。", "豈若秦與趙，爭璧相蹂踏。", "其下數十代，交攻事矛甲。", "用捨亦異道，盛衰勢相沓。", "得之權綱震，失之基本塌。", "吾君系皇統，威稜海隅匝。", "大器固神扃，衆奇萃緹匣。"]'),
('dec091d0-de2b-41af-9571-68b56347d9ec','送閻秘丞宰雩都','蘇頌','宋','宋诗','song-poetry','','[]','江西劇藩曰南康，其山空青水貢漳。',320,'全唐诗/poet.song.30000.json','["江西劇藩曰南康，其山空青水貢漳。", "環封千里十巨邑，邑皆萬室居相望。", "地窮吳境雜楚粵，民生窘急矜豪强。", "積奸疊訟狃成俗，吏治紛擾多頹綱。", "緩其銜轡乃縱弛，繩以密網還滋彰。", "中和之政固難立，要在教化完堤防。", "爾來守宰尤慎擇，長人之計非尋常。", "儀儀閻君文且敏，風韵粹絜含珪璋。", "昨從筦榷薦稱最，就委墨綬雩川旁。", "周才治劇有餘地，猶以驥騄騰康莊。", "牛刀砉騞解衆理，排擊曾未嬰銛芒。", "聲華早已擅朝寀，群公稱薦交封章。", "况今知己正當路，拔擢賢俊登周行。", "謂宜平步陟清要，何乃遠官天一方。", "平時進人用資履，詳試政事觀循良。", "毋嗟邑令尚沉滯，昔賢爲吏多踐揚。", "漢庭卓魯終作輔，孔門言季俱升堂。", "于時百里振嘉譽，逮今史簡傳清芳。", "勉哉遠繼數賢迹，坐使慈惠流江鄉。", "政成績茂奏丹扆，行矣臺閣看徊翔。"]'),
('e1917355-e157-44a4-8cc1-b6b2e2886230','天禧寺竹','蘇頌','宋','宋诗','song-poetry','','[]','萬箇碧琅玕，兩傍蔭潭沼。',120,'全唐诗/poet.song.30000.json','["萬箇碧琅玕，兩傍蔭潭沼。", "叢深蔽巖麓，幹直露雲表。", "剎影下交加，山房上環繞。", "昔嘗止鳴鳳，今肯棲凡鳥。", "笋抽龍種瘦，籜墜孫枝小。", "美勝會稽箭，珍逾汶陽篠。", "兔園名非奇，渭川比終少。", "樵刪草根變，客玩茶煙燎。", "創亭僧意高，諭佛禪心了。", "吾愛有霜筠，一到忘昏曉。"]'),
('76025b19-7ed5-4cf5-bd95-9a66e0dacd0e','寒食後一日作和林秀才','蘇頌','宋','宋诗','song-poetry','','[]','寒食初過一百五，陌上風輕斂微雨。',64,'全唐诗/poet.song.30000.json','["寒食初過一百五，陌上風輕斂微雨。", "宮花鋪繡淺深紅，蜀柳垂絲千萬縷。", "都人士女趁時節，郡圃山樊樂樽俎。", "肯教容易度春光，來日清明更妍煦。"]'),
('4fa819d2-d8f7-4b53-841a-6034d6bcc8f8','暮春與諸同僚登鍾山望牛首','蘇頌','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','清明天氣和，江南春色濃。',180,'全唐诗/poet.song.30000.json','["清明天氣和，江南春色濃。", "風物正繁富，邦人競遊從。", "官曹幸多暇，交朋偶相逢。", "並驅出東郊，乘興遊北鍾。", "陟險不蠟屐，扶危靡搘筇。", "上登道林祠，俯觀辟支峰。", "辭山次阡陌，長江繞提封。", "蕭條舊井邑，茂盛新杉松。", "攬物思浩浩，懷古心顒顒。", "念昔全盛時，茲山衆之宗。", "天門對雙闕，霸業基盤龍。", "六朝遞興廢，百代居要衝。", "人情屢改易，世事紛交攻。", "當時佳麗地，一旦空遺蹤。", "惟有出岫雲，古今無變容。"]'),
('90664cf3-d23e-4822-8cd3-d892b3d4fea7','首夏即事與丘與權同韵作','蘇頌','宋','宋诗','song-poetry','','[]','朱曦漸永煩暑添，薰風當晝飄前檐。',384,'全唐诗/poet.song.30000.json','["朱曦漸永煩暑添，薰風當晝飄前檐。", "庭幽門邃搴帷簾，景物軒豁欣窺覘。", "方池綠瑩波文恬，兩傍森森生葦蒹。", "新荷未展排青尖，上下交映開鑑奩。", "園林果實繁李棎，原野麥秀勝稻稴。", "群飛衆走羽毛彡，求陰息影愁烹爓。", "江南鬰蒸非類痁，時雖早熱人心懨。", "忻忻笑語喧閭閻，言此豐歲將飫饜。", "正陽用事何太廉，乃使陰沴相陵詹。", "正當汗浹絺衣粘，凄風忽生增纊縑。", "淫霖旬日橫流霑，市井郊郭皆渰淹。", "林實墜落誰撦撏，麻麥散亂如刪鎌。", "斯民愁嗟言成譫，我時憂思坐閒檐。", "方食不知味苦甜，整齊几案抽書籤。", "發策一以天人占，少陰乘陽時最嫌。", "小人當此多欺憸，君子遇之難懷謙。", "天道雖遠誠可瞻，上曰高明下沈潛。", "四時中分寒與炎，一氣不可相并兼。", "推本事理知悉纖，災害所起由漬漸。", "豈非奸孽當除殲，又非直道傷詖譣。", "孰居鼎鼐調梅鹽，孰任閫闑懷韜鈐。", "聖皇言動謀於僉，布爲利澤濡蒼黔。", "將消祲沴頻深砭，感召沖氣安危阽。", "嗟嗟直口不可鉗，誰當一探龍頷髯。"]'),
('00dd9265-0d25-43d7-8b56-102c728cd761','與諸同僚偶會賦八題 不期而會','蘇頌','宋','宋诗','song-poetry','','[]','泛交以勢利，君子期久要。',48,'全唐诗/poet.song.30000.json','["泛交以勢利，君子期久要。", "道義苟契合，出處無阻遥。", "龍興雲必從，宮鳴商亦調。", "樂哉此席會，固非夙相招。"]'),
('6aeab250-ebee-4364-90cf-a4b66e87c851','與諸同僚偶會賦八題 待燈','蘇頌','宋','宋诗','song-poetry','','[]','黄昏蝙蝠飛，空堂蟋蟀吟。',48,'全唐诗/poet.song.30000.json','["黄昏蝙蝠飛，空堂蟋蟀吟。", "相對語未闌，不覺更漏侵。", "呼童持短檠，注以蘭膏深。", "皎皎見寒光，良宵愜予心。"]'),
('f325962c-49e1-4b6d-aebf-c1eede2326e2','與諸同僚偶會賦八題 坐久月初上','蘇頌','宋','宋诗','song-poetry','','[]','高軒微雨過，初夕凉風生。',48,'全唐诗/poet.song.30000.json','["高軒微雨過，初夕凉風生。", "兀坐正幽寂，雲間月華明。", "移榻向寒階，遥望孤蟾清。", "所思故人遠，對此傷予情。"]'),
('c8c68441-c4f3-4e74-b6cb-5d4ccc802db8','與諸同僚偶會賦八題 邑署獨鶴','蘇頌','宋','宋诗','song-poetry','','[]','常賦士衡雲，兼懷惠連雪。',48,'全唐诗/poet.song.30000.json','["常賦士衡雲，兼懷惠連雪。", "庭前聞清唳，天外見寒月。", "舞愛素琴橫，饑思朝露潔。", "問爾誰爲群，威鳳在丹穴。"]'),
('0612b620-cbf1-45c5-9927-bba8a9e60be9','與諸同僚偶會賦八題 府庠小沼','蘇頌','宋','宋诗','song-poetry','','[]','面向秦淮流，背枕清溪水。',48,'全唐诗/poet.song.30000.json','["面向秦淮流，背枕清溪水。", "當軒觀未足，鑿沼近可擬。", "月明練光寒，風動漪漣起。", "不用植菰蒲，惟將鑒容止。"]'),
('20dbefb8-84f2-4d78-b4a4-37192c4d5ef8','與諸同僚偶會賦八題 華藏竹','蘇頌','宋','宋诗','song-poetry','','[]','竹性本孤潔，况在祇園中。',48,'全唐诗/poet.song.30000.json','["竹性本孤潔，况在祇園中。", "經年蔭華宇，永日吟清風。", "心虛大道合，幹直賢人同。", "雪霜任摧挫，寒姿獨青葱。"]'),
('6de348dc-61bb-4353-84b8-bdd38608ae46','與諸同僚偶會賦八題 秦淮柳','蘇頌','宋','宋诗','song-poetry','','[]','古樹枕淮流，橋邊與亭畔。',48,'全唐诗/poet.song.30000.json','["古樹枕淮流，橋邊與亭畔。", "借問植秦堤，何如在隋岸。", "南朝正佳麗，綺陌多攀玩。", "嗟今非昔時，榮悴俱可嘆。"]'),
('7f2e7f50-cfd6-4721-9d10-02a011951869','與諸同僚偶會賦八題 登賞心亭','蘇頌','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','秦淮接長江，活活流不已。',48,'全唐诗/poet.song.30000.json','["秦淮接長江，活活流不已。", "高亭出城角，四面盡湍水。", "山川孤雲飛，檻閣清風起。", "望遠何所思，故人在千里。"]'),
('f88dcdaf-808e-4c9b-9494-6cf7fdb40eb7','與丘程凌林四君同賦食河豚','蘇頌','宋','宋诗','song-poetry','','[]','水族誠萬種，茲魚非衆儔。',192,'全唐诗/poet.song.30000.json','["水族誠萬種，茲魚非衆儔。", "形厖而味異，名與畜豕侔。", "江南春風和，乘時泝江流。", "貪婪爾之能，腥臊固相投。", "膨膨逞怒腹，駢駢競尖頭。", "靡因梁笱獲，謾污筌餌求。", "虛傳百金貴，不充四時羞。", "假以薑桂芼，薦之尊俎酬。", "飽飫有奚適，包藏乃爲憂。", "嗟予鄙異食，顧此偏憎尤。", "河魴風陳詩，蝦蟆譏柳州。", "腊毒戒厚味，茲言實嘉謀。", "盍投會稽犗，更垂渭濱鈎。", "一釣蓬山鼇，復連東海鰍。", "割鮮輕屠龍，和羹小函牛。", "誰同厭若魚，何必誇食鰌。"]'),
('08d7a658-8998-4db3-a1ee-3c76fceff7db','遊保寧院練光亭同丘程凌林四君分題用業字韵','蘇頌','宋','宋诗','song-poetry','','[]','寺本梁瓦棺，地臨吳建業。',288,'全唐诗/poet.song.30000.json','["寺本梁瓦棺，地臨吳建業。", "何人構虛亭，勝概壓危堞。", "巖扃豁常開，江練靜相協。", "洪濤雖震騰，迅流終妥帖。", "遠窮滄溟盡，近與長淮接。", "水色古今同，潮聲朝暮愶。", "中間數洲渚，來往拏桴楫。", "摇深鳴榔喧，渡閣孤帆怯。", "到此是安瀾，遊人無病涉。", "滿檻霽光浮，平林風勢獵。", "黄昏煙引素，清曉波成褶。", "歸雲閒自飛，列岫平如帖。", "秋岸狎鷗鳥，春城噪批頰。", "園橘冬垂丹，堤榆夏飛莢。", "竹徑粉筠墜，松梢飴露浥。", "老檜倚軒檐，幹勁如雄俠。", "野花鬥黄紫，格頑若婢妾。", "離觴歌柳枝，江人憶桃葉。", "往事杳難尋，欲問言成喋。", "惟惜建邦都，形勝敵岷鄴。", "後人奉竺乾，創寺據山脅。", "邑居正佳麗，棟宇爭煒燁。", "山遊鸑鷟羽，池變炎灰劫。", "鳳去臺遂空，國移人亦慴。"]'),
('4fefe444-c129-4090-bd81-0ed1fd7b83b5','咏丘秘校山水枕屏','蘇頌','宋','宋诗','song-poetry','','[]','遠山近山各奇狀，流水止水皆清曠。',64,'全唐诗/poet.song.30000.json','["遠山近山各奇狀，流水止水皆清曠。", "煙雲到處固難忘，筆墨傳之尤可尚。", "古人銘枕戒思邪，高士看屏助幽况。", "左有琴書右酒尊，怠偃勤興時一望。"]'),
('920d4659-d1fc-49cb-b488-4be8997af507','和林成之五題 客來','蘇頌','宋','宋诗','song-poetry','','[]','有客過我門，開顔喜相見。',48,'全唐诗/poet.song.30000.json','["有客過我門，開顔喜相見。", "貧居何以待，案上書千卷。", "高論到古人，終日自忘倦。", "非同豪富家，絲竹留飲宴。"]'),
('69dba26d-d6e3-4692-97af-794b9b0740f5','和林成之五題 城南','蘇頌','宋','宋诗','song-poetry','','[]','心樂郊原景，人應似我稀。',48,'全唐诗/poet.song.30000.json','["心樂郊原景，人應似我稀。", "城南時一到，山寺幾忘歸。", "新竹當行徑，飛雲戀客衣。", "誰能咏招隠，向此息塵機。"]'),
('2f8da7b9-539b-4fb0-8ba0-b76e74da580c','和林成之五題 江上','蘇頌','宋','宋诗','song-poetry','','[]','何處偏傷江上春，天涯失意未歸人。',64,'全唐诗/poet.song.30000.json','["何處偏傷江上春，天涯失意未歸人。", "片雲極望添鄉思，孤棹隨波寄客身。", "塞雁來時憑遠信，海鷗馴處見吾真。", "休嗟進取無成去，幸有榮名足慰親。"]'),
('278f87ec-f5f4-4b7b-94fa-1510a4fa3e86','和林成之五題 西鄰','蘇頌','宋','宋诗','song-poetry','','[]','西鄰擊鼓北鄰聽，飲馬持戈密相應。',208,'全唐诗/poet.song.30000.json','["西鄰擊鼓北鄰聽，飲馬持戈密相應。", "一朝奮躍事爭鋒，朔氣充盈誇戰勝。", "中原太平日已久，刃頓兵閒空細柳。", "二疆款附歲奔馳，捆載金繒萃淵藪。", "飫肥服煖四十年，但欲包藏忘德厚。", "謀夫憤憤壯士憂，屢獻忠言曾苦口。", "廟堂尚論正無爲，肯向平時議攻守。", "朔方三十有六郡，戶斂家輸佐行陣。", "非無碩畫破妖巢，直遣萬里威稜振。", "皇天愛人猶赤子，縱欲敺之言亦訒。", "彼方束手聽誓盟，重獲歲時贄琛賮。", "斯民懷德樂休兵，戍卒歸來解鋒刃。", "皆言鄰徼復清夷，嗟哉異類終難信。"]'),
('6ac55009-3d9c-4e2c-9299-0e961ed86ee2','和林成之五題 惜別吟','蘇頌','宋','宋诗','song-poetry','','[]','丈夫豈無淚，不學兒女悲。',84,'全唐诗/poet.song.30000.json','["丈夫豈無淚，不學兒女悲。", "今日獨潸然，爲別良交知。", "交知不易遇，一別會何時。", "念茲出門去，空有長相思。", "非無樽中酒，亦有桐與絲。", "未飲先嘆惋，欲歌還喑噫。", "誰能諒予心，惜哉此別離。"]'),
('7a98a18a-d48d-4326-a062-5d99a826f5d9','題畫草蟲扇子','蘇頌','宋','宋诗','song-poetry','','[]','蠉飛蠕動誠微物，尺素輕盈誰畫出。',64,'全唐诗/poet.song.30000.json','["蠉飛蠕動誠微物，尺素輕盈誰畫出。", "一朝君手將動摇，猶似吟風欲跳逸。", "竹梢草際弄輕翰，水墨淺深見纖質。", "昔人徒愛明月詩，何似今看老師筆。"]'),
('06fc42e5-4905-4724-a029-df26623e3fca','清暉茅亭','蘇頌','宋','宋诗','song-poetry','','[]','山僧構亭山之麓，旋結茅蓬架園竹。',64,'全唐诗/poet.song.30000.json','["山僧構亭山之麓，旋結茅蓬架園竹。", "千年巖樹怪枝虬，十畝龍池春水綠。", "閒移賓榻向松軒，一坐清風香馥郁。", "誰爲潄石枕流人，老此優游避喧俗。"]'),
('5004a413-53bc-45b2-ac14-81453097f796','逢錢塘詩僧','蘇頌','宋','宋诗','song-poetry','','[]','把手忽相逢，開談究詩義。',48,'全唐诗/poet.song.30000.json','["把手忽相逢，開談究詩義。", "子雖浮屠流，乃抱風騷志。", "錢塘佳山水，一一助清思。", "何處最堪懷，飛來峰下寺。"]'),
('863572d5-7f46-4322-8d73-7f2acc1c53bd','聞蛙','蘇頌','宋','宋诗','song-poetry','','[]','蛙黽何所恃，喧喧矜善鳴。',48,'全唐诗/poet.song.30000.json','["蛙黽何所恃，喧喧矜善鳴。", "不知穢污質，群沸沼池清。", "游子得無淚，羈人若爲情。", "華堂有絲竹，皆厭爾虛聲。"]'),
('1f3aff50-b44b-411e-85bd-54f8f7b6e9a3','和林丘二君會程坦之家二詩  其一','蘇頌','宋','宋诗','song-poetry','','[]','春晚寒不已，節候差季孟。',120,'全唐诗/poet.song.30000.json','["春晚寒不已，節候差季孟。", "木行怯初陽，水官恣餘橫。", "滂沱連月雨，愁嘆斯民病。", "已紊四時和，更傷群物性。", "園花半零落，猶逞晨妝靚。", "隴麥將痿摧，况值風威勁。", "我願天地心，慎舉陰陽柄。", "十雨應太平，時豐順睿聖。", "庶令疵沴消，永保寒暑正。", "無復三月中，慘慘行冬令。"]'),
('49b5b03d-f536-4a23-ba2c-5d9dec06e522','和林丘二君會程坦之家二詩  其二','蘇頌','宋','宋诗','song-poetry','','[]','天涯人未歸，飄然江海上。',120,'全唐诗/poet.song.30000.json','["天涯人未歸，飄然江海上。", "客心蓬任風，歸路萍隨浪。", "青雲少知己，白日多罹謗。", "著書見窮愁，倚門知骯髒。", "皇皇干名祿，戚戚足羞讓。", "豈特爲身謀，所懷慰親望。", "昔人在困躓，寧復論得喪。", "吾徒抱道義，豈不保趣嚮。", "勉希一簞賢，無慕千乘相。", "卷舒各有時，出處當自諒。"]'),
('f04bb1b4-e5db-456e-be7b-55045130da1d','奉陪府公賽雪橋公廟紀事兼呈倅幕諸君','蘇頌','宋','宋诗','song-poetry','','[]','北走出都門，寒坰冒初雪。',288,'全唐诗/poet.song.30000.json','["北走出都門，寒坰冒初雪。", "言瞻漢三公，嚴祠奉遺烈。", "襜帷未行春，首茲薦腥血。", "念昨冬愆陽，時風少凝冽。", "長人惜熯菑，坐閤苦憂惙。", "遣吏造靈宇，精心致蕭焫。", "冥感不逾旬，同雲寖融結。", "甸畿千里間，滋液遍農畷。", "兆爲豐年祥，倉箱行可閱。", "報祈禮則然，况乃人望觖。", "前期告祝史，按令肄儀蕝。", "俎豆載博肥，尊罍泲芳飶。", "朱轓朝啟行，騎從紛交列。", "雍容幕府盛，陪預愧蒙拙。", "聯行趨閟宮，就位修罄折。", "拜望已告虔，嘆咏想奇節。", "惟昔漢之季，奸雄逞權譎。", "公初任州郡，超然脫羈紲。", "敢犯跋扈鋒，終正狡吏讞。", "霽威遁世賢，先覺安民傑。", "舉當仇無避，義在親則滅。", "入朝掌武事，出塞受師孑。", "胡塵息邊土，蠻貊竄巢穴。", "屢進行惟危，保終名不缺。"]'),
('4129a603-29ee-49e7-9e58-b9ca397c0b29','送趙君權中歸福唐兼呈陳季中','蘇頌','宋','宋诗','song-poetry','','[]','趙子抱經術，儒林挺孤秀。',180,'全唐诗/poet.song.30000.json','["趙子抱經術，儒林挺孤秀。", "策足入上庠，高誼諸生右。", "秋闈再程文，懷寶不見售。", "京師首善地，翹然俊賢囿。", "朝廷舉新詔，多士四方走。", "主司搜擇艱，有如羿張彀。", "小善或不遺，寧當舍良茂。", "豈非繩準高，刀尺下難就。", "得喪不在己，自信非我疚。", "歲窮感親心，倚門方遠候。", "都亭謝知己，飄飄拂歸袖。", "樂彼閩中幽，里中賢友舊。", "且復從其游，行義益充厚。", "道存貴有用，獨善古所陋。", "明時無滯才，子行當勉懋。"]'),
('1bfdfef5-2692-431b-add8-d3329df27f8a','送許當世職方通判泉州','蘇頌','宋','宋诗','song-poetry','','[]','仕宦遠故鄉，古人之所譏。',240,'全唐诗/poet.song.30000.json','["仕宦遠故鄉，古人之所譏。", "懷祿去養親，千鍾且爲微。", "當世倅州行，二美其庶幾。", "符竹非不貴，誠與雅志違。", "獨駕箳篁車，東南去如飛。", "所懷戀晨昏，奚論官等威。", "遥遥七閩山，喬木正芳菲。", "駟馬過舊遊，道路增光輝。", "榮觀慰親心，佩綬紆銀緋。", "上堂拜慶日，喜氣生庭闈。", "躬扶版輿去，徑入牙城扉。", "潭潭公府盛，華顯猶布韋。", "膳羞盈其前，酒紅魚蟹肥。", "人生苟適意，富貴安所希。", "况今邦伯賢，早辭尹王畿。", "亦從北堂養，再擁雙輪歸。", "君欣舊知己，復得相親依。", "守相同鄉州，會遇時所稀。", "純孝自感人，遠近聞風徽。", "豈徒對交親，誇詫晝錦衣。"]'),
('06d34a41-666b-4d0e-8169-af0953f358cf','和胡俛學士游西池書事','蘇頌','宋','宋诗','song-poetry','','[]','皇都有滄池，近在金商陌。',288,'全唐诗/poet.song.30000.json','["皇都有滄池，近在金商陌。", "淵源控河汴，襟带引京索。", "衆派瀉寒光，一鑑涵空碧。", "晴明天垂幕，陰靄地滋脈。", "煙嵐隘五湖，氣象吞七澤。", "漪漣十餘里，縞練千萬尺。", "樓殿起參差，門闉開岝峉。", "人間識方壺，古來慚太液。", "美哉臺沼名，壯我帝王宅。", "惟昔經始謀，茲見神武迹。", "非同泗淵濫，蓋用昆夷策。", "萬乘紆警蹕，群官扈鑾軛。", "津頭駐翠華，唐中蒐赤籍。", "水犀陳百旅，畫鷁棹千隻。", "時多呂梁人，士有中黄伯。", "旋淵齊出沒，桅檣競跳躑。", "鼓枻變魚麗，飛江生羽翮。", "一時軍事嚴，四表皇威赫。", "承平垂百年，聲教重九譯。", "朝惟講文物，民亦厭金革。", "樓戈無復用，池籞因不易。", "年年春風暮，處處禊筵闢。", "曲堤柳交陰，上苑花遍拆。", "舟師校艨衝，樂佾鏘金石。"]'),
('2ff464b3-d7b1-4979-95cd-7621045cfb55','和胡俛學士紅絲桃','蘇頌','宋','宋诗','song-poetry','','[]','京都花品予嘗評，夭桃僅有十數名。',192,'全唐诗/poet.song.30000.json','["京都花品予嘗評，夭桃僅有十數名。", "含絲繁艷今始識，鮮苞長蕊彯紅纓。", "春晴日暖助顔色，灼灼一片朝霞輕。", "鮫綃剪碎旋裝綴，虬須摘盡將紉縈。", "因知化工巧難狀，偏于草木呈瑞精。", "又疑華燈九光爛，蜂蝶不敢來窺爭。", "江南萱草易滋殖，維揚芍藥初種成。", "此花皆有紅絲號，恨不同時相合并。", "君家數株發庭際，愛玩常掛簾鈎瓊。", "有客風流欲寄目，主人喜笑張筵迎。", "飛觴灑翰偏得意，都緣尤物牽風情。", "我雖多病不能飲，猶思强舉花前觥。"]'),
('a24d2bab-34c5-4ef2-933e-7e88b8767e12','即席分韵送李才元學士守臨邛','蘇頌','宋','宋诗','song-poetry','','[]','君登石渠閣，荏苒十過春。',156,'全唐诗/poet.song.30000.json','["君登石渠閣，荏苒十過春。", "編摩業既卒，出入命已頻。", "人情嘆榮滯，雅意猶逡巡。", "襟懷恬而曠，鬢髮黳如新。", "躬隨省中籍，念切堂上親。", "前時動鄉思，歸夢趨梁岷。", "乞符去故里，拜疏伏紫宸。", "恩頒尺一詔，寵駕雙朱輪。", "朝爲浮瀛侶，暮作臨邛賓。", "誰言蜀道遠，自喜家山鄰。", "歲晏風慘慘，行役心欣欣。", "怊悵同舍友，仳離照心人。", "杯行莫辭滿，分携只明晨。"]'),
('ea6005a0-cf1e-45d5-b6aa-f9cad4833cc9','和諸君觀畫鬼拔河','蘇頌','宋','宋诗','song-poetry','','[]','關中古有拔河戲，傳聞始盛隋唐世。',384,'全唐诗/poet.song.30000.json','["關中古有拔河戲，傳聞始盛隋唐世。", "長絙百尺人兩朋，遞以勇力相牽制。", "芳華樂府務誇大，黎園公卿謾輕肆。", "拔山扛鼎烏足矜，引繩排根非勝事。", "當時好尚人競習，鬼物何爲亦能是。", "展吳畫格入神品，陸法尤長寫靈異。", "蒲津古寺筆迹奇，世疑二子之𥿡置。", "旗門雙立衆鬼環，大石當中坐渠帥。", "蓬頭圜目互奮踴，植鼓揚桴各凌厲。", "東西挽引力若停，賦彩自分傾奪勢。", "畫來已歷數百年，牆壁巋然今不廢。", "觀風使者集賢翁，每遊其下幾忘味。", "因令搨手裂齊紈，橫卷傳看得形似。", "精神氣韵信瓌詭，毫髮輕濃皆彷彿。", "持來都下示朋僚，一見飄然動詩思。", "諸公詩豪固難敵，形容物象尤精緻。", "氣完語健雋衆口，二子聲名轉增貴。", "予觀昔之善畫者，心手規橅無不至。", "窮奇極怪千萬端，特出一時之用意。", "鬼神冥漠不可詰，豈有便能人勇智。", "仙官佛像亦如斯，變態隨時轉奇麗。", "遂令來者信有說，塔廟從而增侈費。", "後賢雖欲究端倪，竟亦無由革頹弊。", "因知怪誕一崇長，漸靡成風滋巧僞。"]'),
('6d571241-2070-47fa-86c7-29e9a92a5f0c','補和王深甫潁川西湖四篇 甘棠湖','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','爲湖始何人，人賢物亦久。',24,'全唐诗/poet.song.30000.json','["爲湖始何人，人賢物亦久。", "所以甘棠名，百年猶不朽。"]'),
('64dba1aa-f54d-4e01-a75c-d191c377f6e0','補和王深甫潁川西湖四篇 宜遠橋','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','溪流去無窮，路遠更難盡。',24,'全唐诗/poet.song.30000.json','["溪流去無窮，路遠更難盡。", "信步到橋邊，望中千里近。"]'),
('cd619152-5309-43a9-9e7b-f38670006957','補和王深甫潁川西湖四篇 竹間亭','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','青青林間竹，有亭才袤丈。',24,'全唐诗/poet.song.30000.json','["青青林間竹，有亭才袤丈。", "林深隔囂塵，人間見真尚。"]'),
('60525ffa-ff64-4306-a55a-28ed1af4673d','補和王深甫潁川西湖四篇 明月舫','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','明月照寒宵，湖水白如晝。',24,'全唐诗/poet.song.30000.json','["明月照寒宵，湖水白如晝。", "縱覽泊中流，清光應可就。"]'),
('c968bf4f-0d8b-4335-91b8-5e118136358b','刁景純學士寄示嘉篇述前後過潁遊覽之樂不鄙虛陋曲蒙推奬感嘆不足輒用本韵通成五十仰答來貺','蘇頌','宋','宋诗','song-poetry','','[]','昔歲寓文館，雅志慕藩屏。',288,'全唐诗/poet.song.30000.json','["昔歲寓文館，雅志慕藩屏。", "嘗聞近畿州，勝絕惟南潁。", "十年走京華，官局苦閒冷。", "欲求一麾去，數奏囊章請。", "適會擇茲守，乘時竊僥倖。", "君相寵儒林，念久貸諐眚。", "旋蒙左符賜，上戴天恩併。", "扁舟促行役，洪渠逐奔猛。", "飄然離塵囂，有若出機穽。", "從容光景多，歷覽江山迥。", "去都時值秋，到官月逢寎。", "此邦信名區，民願俗無警。", "昔守皆巨公，今猶蒙鎮靖。", "非才偶承乏，繼治實多幸。", "前賢有規模，遇事見要領。", "因此頗閒暇，得以探物景。", "溪湖繞郡郭，臺榭跨岡嶺。", "春媚花百名，秋香荷十頃。", "野色連莽蒼，水容迷淥浄。", "虹駕逵路長，鷁泛源流永。", "幽尋窮勝處，登陟疲足脛。", "適意自留連，對人成詫逞。", "是時汴流阻，北客多過境。", "景純罷山陰，前旆亦南騁。"]'),
('1e18e0af-9d86-4234-a2ac-8738a9894355','省中早出與同僚過譚文思西軒咏太湖石','蘇頌','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','洞庭山連震澤水，怪石巉巖出波底。',64,'全唐诗/poet.song.30000.json','["洞庭山連震澤水，怪石巉巖出波底。", "誰言行遠莫致之，好事經營俄至此。", "愛君小軒才袤丈，滿地新芳雜紅紫。", "偶來憑檻見奇峰，便有江湖秋思起。"]'),
('4b904980-b64e-4b34-adb5-e06bd367fe1d','送朱郎中壽昌通判河中府','蘇頌','宋','宋诗','song-poetry','','[]','邶詩咏凱風，以成孝子志。',288,'全唐诗/poet.song.30000.json','["邶詩咏凱風，以成孝子志。", "鄭人復君母，傳稱能錫類。", "中郎常有懷，生不識所恃。", "登朝雖厚祿，當食每忘饋。", "念昔鞠育勞，嗟今出處異。", "倚門豈不待，兩求終莫致。", "乳烏思反哺，哀鳴自垂翅。", "百草摇春暉，寧無謝生意。", "灑血向穹壤，解組出臺寺。", "馳驅咸雍郊，歷訪經行地。", "至行感神明，精神通夢寐。", "悠悠大道傍，親息忽相值。", "紫綬拜北堂，白頭歸長嗣。", "悲忻敘契闊，恍如隔生事。", "四紀世路殊，一朝板輿侍。", "茲事昔未有，聞者共驚喟。", "帥守爲之言，詔趣還官次。", "當年二千石，寵名非所利。", "仕或便鄉關，安用竹符使。", "蒲中母家近，自屈爲倅貳。", "受命慰慈顔，騰裝愜歸思。", "既徇報德心，亦安效官智。", "觴以萬壽薦，衣成五綵戲。", "無復興寒泉，何須賦大隧。"]'),
('07a01a3f-a7a1-4e9d-844b-d1363ee2b80d','寄題徐郎中鄱陽高居望雲臺','蘇頌','宋','宋诗','song-poetry','','[]','子牟在江海，心存魏闕下。',144,'全唐诗/poet.song.30000.json','["子牟在江海，心存魏闕下。", "君居雖遠方，不忘朝廷者。", "築室負郊郭，虛堂連廣厦。", "浮梁江湖間，風物最蕭灑。", "官罷得優閒，一到休車馬。", "開軒命賓客，棋壺雜觴斝。", "園亭助登覽，山川入騷雅。", "霄漢不可跂，惓惓誰能捨。", "目睇西北雲，丹成此傾瀉。", "出還擁旌旟，歸復傲林野。", "真得吏隠趣，豈累榮名假。", "宦遊羈紲中，適意如君寡。"]'),
('bebeea4b-f7ff-4cd6-9537-dc1d90d149be','秀才石君予同年子也携書見投重之以歌詩意甚勤厚其歸也邀予言爲贈因作五言以勉之','蘇頌','宋','宋诗','song-poetry','','[]','石生故人子，袖書遠相過。',192,'全唐诗/poet.song.30000.json','["石生故人子，袖書遠相過。", "趨翔有父風，步闊冠峨峨。", "自言少也孤，奉親由江鄱。", "區區營甘旨，靡暇謀其他。", "三十未有成，無門托絲蘿。", "求知走四方，慷慨成悲歌。", "顧我舊朝寀，謂能激餘波。", "多慚僻郡守，局趣如生何。", "空持贈我句，坐閤長吟哦。", "方今紹唐虞，咏歌繼卷阿。", "舉世用經術，革去辭章訛。", "詔書起遺逸，草澤咸搜羅。", "高爵待俊傑，世礪鈍以磨。", "君子務藏器，生其勤切磋。", "乘時挾才策，繼世收賢科。", "壯懷無自忽，流年易蹉跎。"]'),
('ed775b1b-ea85-42bc-ac5e-c317bca55c20','石縫泉清輕而甘滑傳聞有年矣前此數欲疏引入州治久不克就予至則命工人尋舊迹相地架竹旬月而水懸聽事又析一支以給中堂一支以入西閤其下流則釃出外廡往來取汲人以爲利因抒長篇以紀其功云','蘇頌','宋','宋诗','song-poetry','','[]','峨峨鳳凰山，有泉出其腋。',288,'全唐诗/poet.song.30000.json','["峨峨鳳凰山，有泉出其腋。", "初微才濫觴，漸大乃穿石。", "靈苗蔭荼檟，寶氣近金錫。", "毖彼淵源長，茲惟雲霧液。", "人傳煮茗奇，味與中泠敵。", "陸生不到此，云誰能賞識。", "牙城據岡巒，舊井皆滷瀉。", "先時屬經營，曾未致點滴。", "及此川谷盈，空爲畎澮積。", "我昨尋勝遊，偶見爲心惻。", "料工度山原，舉步過門戟。", "水道茲可行，面勢正相直。", "剪裁竹千竿，接聯筧萬尺。", "派別起中阿，架空逾下稷。", "不及浹旬間，已到堂皇側。", "吐溜始涓涓，循除俄㶁㶁。", "盈科殊未止，過顙非用激。", "公堂及燕寢，股引各疏脈。", "何期南澗流，近在使君宅。", "日用助烹爨，歲儲供醴醳。", "冬春雖暫竭，秋夏多餘瀝。", "一支出橫廊，通衢見勿幕。", "衆器競挹𣂏，萬口得盥滌。", "無愧抱甕人，幸寬挈壺役。"]'),
('53f4fb7b-d1e3-45e8-8759-3522102f709f','次韵蔣穎叔金部遊介亭望湖山二十四韵','蘇頌','宋','宋诗','song-poetry','','[]','我昨來餘杭，孟陬值杓建。',288,'全唐诗/poet.song.30000.json','["我昨來餘杭，孟陬值杓建。", "春色正融怡，皇華紆睠眄。", "言此佳山水，巧麗極怪變。", "有如畫屏風，羅列圍四面。", "城南古浮圖，又爲一郡冠。", "聯驅松徑中，信步蒼崖畔。", "莓苔粘履屐，虬枝拂簪弁。", "縱覽識高深，顧慕增詫嘆。", "心迷真賞奇，意覺旅遊倦。", "物色雖難窮，指注亦粗遍。", "樓臺鬰相望，無異挂盤線。", "向非適幽遐，何由盡聞見。", "惟昔吳越君，塔廟務華煥。", "依山鎸大像，疊石累高岸。", "經構無已時，貲費豈復算。", "較其輿地中，佛寺占過半。", "榮華一朝盡，金石空殘片。", "款識刻猶存，排衙行不亂。", "虛亭復增修，郡府餘壯觀。", "故人柏臺彥，早歲歷監殿。", "自從交臂來，幾回傷聚散。", "聲光日以高，使節復頻換。", "江湖偶追陪，旬浹停車傳。", "更有山林期，茲焉適予願。"]'),
('dccce555-1485-4f30-8847-71681b889c56','次韵蘇子瞻學士臘日遊西湖','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','臘日不飲獨遊湖，如此清尚他人無。',160,'全唐诗/poet.song.30000.json','["臘日不飲獨遊湖，如此清尚他人無。", "唱酬佳句如連珠，况復同好相應呼。", "君嘗聽事嗟罪孥，雖在樂國猶寡娛。", "是社稷臣魯顓臾，直道自任心不紆。", "最愛靈山之僧廬，彼二惠者清名孤。", "案上梵夾床龍鬚，爐銷都梁饌伊蒲。", "潔行自欲敦薄夫，長吟擁褐忘昕晡。", "坐客不設氈氍毹，對鏡如看方輿圖。", "君懷經濟才有餘，名聲妖孽懲顔蘧。", "且來山林尋遁逋，更玩四營兼參摹。"]'),
('de207c50-28b6-4318-b118-b7e992da890b','陳和叔內翰得莊生觀魚圖於濠梁出以相示且邀作詩以紀其事','蘇頌','宋','宋诗','song-poetry','','[]','公堂四合臨中衢，翰林壁挂觀魚圖。',384,'全唐诗/poet.song.30000.json','["公堂四合臨中衢，翰林壁挂觀魚圖。", "傳之近自濠梁客，云是蒙邑先生居。", "先生昔仕楚園吏，傲世不蘄卿大夫。", "逍遥淮上任造適，高岸偶見群鯈魚。", "清波出遊正容與，潭底傳沫喣以濡。", "悠然餌綸不可及，誰知此樂真天娛。", "惠施好辯發閎論，謂彼固異若與吾。", "至人冥觀盡物理，豈以形質論精粗。", "稟生大塊厥類衆，合則一理散萬殊。", "淵潛陸走各自適，天機內發寧拘拘。", "鳶飛戾天獸易藪，螣蛇游霧龜曳塗。", "味色誰能辨带鹿，足頸烏用嗟蚿鳬。", "蜄筐信美害愛馬，鐘鼓雖樂愁鶢鶋。", "青寧久竹代生變，螽蟲風化相鳴呼。", "方游溟海大空外，坎井詎能談尾閭。", "若知飛息分皆足，圖南未必勝搶榆。", "人生均是受形氣，好惡歡養同一區。", "死生壽夭亦大矣，自本而視奚有無。", "方當在夢則栩栩，及其既覺還蘧蘧。", "入榮軒冕不累性，獨往丘壑非爲愚。", "不求刻意不徇利，孰是隠几孰據梧。", "惟能應變不囿物，天籟自與人心俱。", "一從郢匠喪其質，狂言空見傳于書。", "當時陳迹復何在，客有過者猶踟躕。"]'),
('f1ccc89e-56d8-4936-93f3-fddc91ab2a4e','次韵蔣穎叔同遊南屏見惠長篇','蘇頌','宋','宋诗','song-poetry','','[]','青山橫莽蒼，萬石出南麓。',180,'全唐诗/poet.song.30000.json','["青山橫莽蒼，萬石出南麓。", "古剎表耆闍，高聲聳群玉。", "居惟擇岡巒，近靡數松竹。", "郡郭路非遥，遊人舂不宿。", "陟巘極躋攀，循崖勞傴伏。", "架筒引流泉，跨嶺構重屋。", "講座據妙峰，禪堂對枯木。", "幽尋難屢期，將往誰能獨。", "偶逢霜臺客，暫駐驄馬足。", "聯步訪叢林，終朝走郊牧。", "相期方外遊，頓忘河上曲。", "夷路喜君騰，高閣慚予束。", "更聽名理言，俯愜中心欲。", "况已證真常，詎止齊寵辱。", "願言挹清風，可用警浮俗。"]'),
('bf2c48eb-a924-45a7-a6d0-a9de72e96903','次韵蔣穎叔同遊超化院','蘇頌','宋','宋诗','song-poetry','','[]','賢良才識明，御史風望清。',144,'全唐诗/poet.song.30000.json','["賢良才識明，御史風望清。", "命駕千里至，高談一座驚。", "舊故偶獲道，離憂自茲平。", "朅來湖上寺，共語堂西楹。", "念昔一交臂，幾年兩摇旌。", "契闊信靡定，邂逅欣偕行。", "日薄聊頓轡，興來再飛觥。", "霜林隕丹葉，泉坻結新冰。", "湖月金炯炯，竹風玉玲玲。", "峰巒對三山，樓殿如九成。", "南州足奇麗，此地尤兼并。", "因君發題咏，足使增嘉聲。"]'),
('84c6d394-11fd-4100-9f9a-97193b79686a','次韵三弟學士題七寶英師壁','蘇頌','宋','宋诗','song-poetry','','[]','巖居得幽勝，俗累無憂傷。',168,'全唐诗/poet.song.30000.json','["巖居得幽勝，俗累無憂傷。", "占彼鳳山腋，建茲法雲堂。", "宵眠一氈蒲，晝食幾稻粱。", "浄衆集善緣，勇猛能自强。", "瑞相嚴中楹，梵夾羅四旁。", "軒窗據蒼崖，松竹圍重岡。", "不雜人世喧，更覺禪味長。", "我嘗命賓友，間或携肴觴。", "中休憩丈室，遠覽登上方。", "念昔保城塹，屹然壯金湯。", "列剎以百數，息民殄千殃。", "爰居盡樂土，利用無缺斨。", "遂使吳會俗，長爲禮義鄉。", "何獨竺乾域，寶山亦清凉。"]'),
('07f14d5e-062a-4960-b63e-cbcf4e83cb92','與蒙城知縣陳著作同賦吐綬鳥','蘇頌','宋','宋诗','song-poetry','','[]','羽毛之美其類衆，雉曰吐綬世尤重。',384,'全唐诗/poet.song.30000.json','["羽毛之美其類衆，雉曰吐綬世尤重。", "靈姿異稟來何方，有客携持自咸雍。", "朱籠馴習繡墩調，珍貴不與常禽共。", "庭前愛玩不能已，欲買未有千金俸。", "一座嘉賓共詫誇，留連爲倒春醪甕。", "送將題目與詩人，要待清才如屈宋。", "斑斑赤質鬥花紋，瓅瓅明珠絡衣縫。", "暖風晴日正閒暇，綺翼丹趺時𩭩鬆。", "垂胡兩組錦舒張，約髮雙笄玉浮動。", "倏忽披開疊勝文，蒙茸亂綰青絲綜。", "初疑瑞草銜鶻啄，又訝牦纓彯馬鞚。", "行縢赤芾交脛足，羽服袿衣曳蜺蝀。", "漢官綬䓞何須染，鄭公書带徒勞種。", "引頸纔盈尺寸間，鏤彩盤絛無缺空。", "未容俯近復卷收，頃刻無由發清哢。", "向人顧盼雖無言，奮臆猶如將告控。", "有生之樂貴得所，所樂山林殊市哄。", "斥鷃飛翔本蓬蒿，鷾鴯社稷存梁棟。", "不慕爰居享鐘鼓，要逐鳬鷖唼菰葑。", "臨流照影刷羽翰，朝飛求偶隨群從。", "十步一啄百步飲，烏用樊中久羈𢮍。", "主人提挈誠厚恩，豈若郊原使閒縱。", "我聞章服以旌禮，物有等威須折衷。", "鞶囊厲带最光華，寵錫或招三褫訟。"]'),
('d5720ae8-9806-43ae-8f6d-a24038682b4f','次韵陳蒙城金風堂射飲','蘇頌','宋','宋诗','song-poetry','','[]','南都綠蟻封初拆，西圃芳條換新碧。',208,'全唐诗/poet.song.30000.json','["南都綠蟻封初拆，西圃芳條換新碧。", "賓僚相遇惜餘春，樽俎留連因促席。", "百夫决拾看和容，何用娛賓循飲格。", "前者新詩嚴武事，幾日毬場較鋒鏑。", "幕中頼有從事賢，抱器逢時隼當射。", "聊從把酒發笑談，豈獨鳴弦觀準的。", "分明爭計算多少，舉令都忘歌節拍。", "蒙邑大夫富才藝，早擅詞林名藉藉。", "昨來州序偶淹留，幸接話言逾宿昔。", "行籌不必苦辭觴，得雋况曾先射澤。", "多慚病守鮮歡悰，出口無奇但喑啞。", "貪榮竊祿未能歸，每聽春禽愁杜魄。", "今朝何似强開顔，爲喜尊前有嘉客。"]'),
('747a48a8-dd7c-4c1b-894f-dbcf3476bca6','和蔣穎叔亳州矮檜','蘇頌','宋','宋诗','song-poetry','','[]','檜生本修直，此種特殊異。',180,'全唐诗/poet.song.30000.json','["檜生本修直，此種特殊異。", "高不盈尋丈，廣乃遍階砌。", "短幹自堅强，附枝交蔭翳。", "森然葆羽欹，隠若虬龍墜。", "不知何代有，木老色彌翠。", "嘗聞古仙者，應化在茲地。", "手植有遺迹，深根幾千歲。", "神靈應護持，道宮存款識。", "自此物色繁，因爲圃人利。", "封殖雖地宜，屈蟠由巧智。", "以彼凌雲姿，還同蔽牛類。", "拳曲如能壽，輪囷不爲器。", "誰云矯生質，終亦遺世累。", "詩伯一留題，禪叢重增貴。", "豈若榴檉然，空傳草木記。"]'),
('90fdf60b-afad-478f-87aa-c9fcc758b412','暇日遊逍遥臺睹南華塑像獨置一榻旁無侍衛前無香火對之歆然起懷古之思因抒長句一千四百字題於臺上','蘇頌','宋','宋诗','song-poetry','','[]','憶昔初讀南華篇，但愛閎辨如川源。',384,'全唐诗/poet.song.30000.json','["憶昔初讀南華篇，但愛閎辨如川源。", "沉酣漸得見真理，馳騖造化遊胚渾。", "潛心四紀不知倦，閒日講解時尋溫。", "其言無端極放肆，大抵順物尤連犿。", "六經高深如韞櫝，百氏蔽偏迷蹢閽。", "伯陽語道最淵邃，中士尚或疑亡存。", "竺乾權實信廣大，妙用不出我藩垣。", "偉茲三篇粹精奧，推本一化開幽𠊽。", "反覆孝慈去願譽，胎育仁義除詐諼。", "情類相親自才德，踶跂不立存樸惇。", "寓言本爲大方設，弔詭難與常人論。", "祖尚玄虛滅理學，乖背宗旨由後昆。", "遂矜放曠爲任達，由此道真流亡反。", "自非通識造閎遠，安能超悟還淳元。", "大鈞斡旋本何有，相禪以種紛無垠。", "載其形聲直喑醷，感彼氣類相嬗媛。", "死生之辨在旦夜，夢覺之異分形魂。", "神奇臭腐互美惡，蜩甲蛇蛻奚代迍。", "卵胎無以易生種，風化自爾成蟲蜫。", "出入于機泯無際，始卒若環焉可捫。", "芒乎萬致始同體，明以一指彌滋繁。", "異則肝膽爲楚越，同則蕭竹猶枅圈。", "真宰難以眹迹見，靈臺莫由形器援。", "何者非彼何者是，孰爲親愛孰爲怨。"]'),
('4ef801a6-2023-4f38-9fab-815a686a19d7','次韵司徒富公耆年會詩','蘇頌','宋','宋诗','song-poetry','','[]','古人稱宴安，居處必擇地。',168,'全唐诗/poet.song.30000.json','["古人稱宴安，居處必擇地。", "諸公來河南，有若不期會。", "巖巖大司徒，早辭槐鼎貴。", "嘉謨納淵衷，故事留臺寺。", "構第銅駝坊，開門瀍水次。", "居守德爵同，位重官三事。", "高軒每過從，縱言談道藝。", "復有鄉里賢，夙昔承嘉惠。", "崧嶺高橫空，洛波清見底。", "履道追昔遊，行厨載芳醴。", "燕毛禮所重，安車皆戾止。", "年尊二國公，齒序衆君子。", "願公壽千秋，慰民瞻具爾。", "三載一來朝，當陪天子祀。"]'),
('f8b8f808-d57a-4595-9a10-968bfe27907a','次韵王宣徽太尉耆年會詩','蘇頌','宋','宋诗','song-poetry','','[]','古來賢相稱高奇，虞有皋夔商傅伊。',384,'全唐诗/poet.song.30000.json','["古來賢相稱高奇，虞有皋夔商傅伊。", "帝臣王佐見謨訓，千載相望如同時。", "我朝公輔代間出，鍾秀辰象分躔離。", "堂堂太尉實異稟，風質粹美和而威。", "仁皇始擢自藩翰，渭水兆告非熊羆。", "立朝早已擅風采，料敵曾不失毫釐。", "聖聖相承倚時棟，入登槐鼎出擁麾。", "司徒相繼據魁軸，勢壓諸夏摧附枝。", "一言寤意尊社稷，萬里奔命來戎夷。", "君臣一體自同德，下鄙漢相矜規隨。", "功成治定預告老，還鄉治第當西圻。", "十年休佚養沖氣，泰宇充茂心欣嬉。", "二公勳德誦人口，載于彝鼎歌于詩。", "吾皇得相柄文武，調燮四序齊璇璣。", "孟軻嘗稱聖之任，乃曰百世人之師。", "固宜天畀兩元老，期頤常保松筠姿。", "規橅載在廟堂上，自使風俗淳澆漓。", "前年召自大名尹，對罷累請菟裘歸。", "帝曰公今更强固，閔煩幾政留清規。", "兩加金貂百官首，再剖玉麟三水涯。", "洛人聞之喜且抃，如在旱歲逢雲霓。", "朝臨留府暮私第，偃息又將彌再期。", "今春欲作耆英會，涓日象值神俱比。", "謂宜飲食與宴樂，對接賓客心忘機。"]'),
('0f4f5287-7f0f-4de3-8443-034c06df7410','次韵君實內翰同遊范景仁東園','蘇頌','宋','宋诗','song-poetry','','[]','鑾禁限沉深，鼇頭雄贔屭。',84,'全唐诗/poet.song.30000.json','["鑾禁限沉深，鼇頭雄贔屭。", "主人出休沐，秋色正明麗。", "偶爲東園遊，便有中林意。", "縱言得造適，覽物增意氣。", "風清濯煩襟，日永忘歸轡。", "朝野本無間，簪組何用棄。", "未必幽棲人，識茲真樂地。"]'),
('91c70572-3252-479f-8d95-08390d856a16','效范景仁侍郎次韵和君實端明長句奉呈龍舒楊守','蘇頌','宋','宋诗','song-poetry','','[]','公居幽絕誰能紀，欲到應須勞屐齒。',128,'全唐诗/poet.song.30000.json','["公居幽絕誰能紀，欲到應須勞屐齒。", "從官出入路縈紆，况今又去藩龍舒。", "人在天南居在北，鄉心千里雲山碧。", "山庭不用勒移文，時樂中和歸未得。", "他年若尋仙老會，洛下諸公盡中外。", "百二十坊山水間，甲第相望門巷對。", "過從不獨賞芳珍，造適何妨談道真。", "回頭却望朝市裏，多少思歸未去人。"]'),
('6630156a-edec-4847-a242-2ff582f7874f','六月六日訪晁美叔吏部越宿蒙惠長篇因次其韵','蘇頌','宋','宋诗','song-poetry','','[]','近伏值休澣，端居無所爲。',216,'全唐诗/poet.song.30000.json','["近伏值休澣，端居無所爲。", "觸熱事造請，有如褦襶詩。", "偶到昭德里，主人不吾非。", "惟今吏部郎，望清秩非卑。", "而與兩銓選，事聯相附離。", "每聽人物論，尤詳臺閣儀。", "沿襲尋本原，左右逢津涯。", "登朝鬢猶綠，繼世衣仍緇。", "歡然久相接，甚矣嗟吾衰。", "誰言同趣舍，何力能噓吹。", "但慚蒹葭陋，坐對瓊林枝。", "時或把書卷，不厭顔生饑。", "間亦忘形骸，任譏嗣宗癡。", "喜君方得塗，騫騰復何疑。", "豈此哀烏省，能留威鳳姿。", "君才適時用，早聞天子知。", "荷囊與鳴玉，獻納無不宜。", "寧校歲月勞，求爲法令師。"]'),
('6b4a68a3-462c-4509-b477-dd4f5caa4fc3','次韵蘇子瞻題李公麟畫馬圖','蘇頌','宋','宋诗','song-poetry','','[]','霜紈橫卷書縚垂，軸以瑇瑁囊青絲。',163,'全唐诗/poet.song.30000.json','["霜紈橫卷書縚垂，軸以瑇瑁囊青絲。", "披圖二妙駭人目，筆畫勁利如刀錐。", "龍媒迥出丹青手，勢若飛動將奔馳。", "韉銜如在赤墀立，僕御猶縱紅纓羈。", "子虔六轡衒沃若，長康駿骨稱天奇。", "雖傳畫譜入神品，未有墨客評黄雌。", "六詩形似到作者，三馬意象能言之。", "奇蹤莫辨霸或幹，高韵壓倒陸與皮。", "從來神物不常有，未遇真賞何人知。", "君不見開元廏馬四十萬，作頌要須張帝師。"]'),
('ad18e1ae-0dee-45d5-ae73-a4394db3f018','元祐癸酉秋九月蒙恩補郡維揚十一月到治蒞事之始首閱題名前後帥守莫非一時豪傑固所欽慕矣然於其間九公頗有夤緣感舊思賢嗟嘆不足因作長韵題於齋壁以寄所懷耳','蘇頌','宋','宋诗','song-poetry','','[]','維揚禹九州，淮南唐四鎮。',288,'全唐诗/poet.song.30000.json','["維揚禹九州，淮南唐四鎮。", "地據江海衝，星占楚吳分。", "五季劇荒擾，我朝夷僭閏。", "督府時稱雄，守帥選常遴。", "由來竹符使，莫匪邦家聞。", "其間九賢者，尤推萬人俊。", "太原文章伯，師友淵源濬。", "五事陳便宜，七制推典訓。", "屢薦官雖崇，三已色無慍。", "岐公老藩朝，惠愛浹吳晉。", "薦士言有味，偃兵功不陳。", "鼎飪方燮和，丘園終委順。", "淵哉文肅公，生遘休明運。", "三朝翰墨工，二府謀猷奮。", "道卷任推遷，名全蔑緇磷。", "鄭公梁棟才，天質璆琳韵。", "大筆弟兄同，萬事朝廷問。", "徊翔極宰樞，終始無疵吝。", "仁宗初倦勤，魏公復來覲。", "堂堂真相尊，謇謇嘉言進。", "十字篆勛勞，大烝報忠藎。", "樂安予舊館，早歲窺牆仞。", "儒林仰宗工，政府發閎論。", "雖無鼎銘勛，却有書傳信。"]'),
('0eb243bc-0fce-4113-acf5-7631f7d9a7df','累年告老恩旨未俞詔領祠宮遂還鄉閈燕閒無事追省平生因成感事述懷詩五言一百韵示兒孫輩使知遭遇終始之意以代家訓故言多不文','蘇頌','宋','宋诗','song-poetry','','[]','我昔就學初，齠童齒未齔。',288,'全唐诗/poet.song.30000.json','["我昔就學初，齠童齒未齔。", "嚴親念癡狂，小藝誘愚鈍。", "始時授章句，次第教篇韵。", "蒙泉企層瀾，覆簣期九仞。", "十齡獨侍行，千里赴朝覲。", "靡依心向吳，能事躬在浚。", "應門待賓客，睦族周分親。", "雖免逃杖諐，猶虞裕蠱吝。", "十三從師友，群彥得親近。", "箕裘襲素風，蘭芷漸腴潤。", "佔畢自忘勞，攻堅常切問。", "六經日沈酣，百氏恣蹂躪。", "禮樂原夏商，春秋道堯舜。", "論詩識溫柔，講易知謙巽。", "書要通上古，史亦蘄盡信。", "復熟中庸篇，推名善惡混。", "楹書迨今存，手澤亦未泯。", "頼此漸摩益，稍知賢聖藴。", "十八隨鄉書，三冬閱文陣。", "同時韋带倫，共試棘闈濬。", "少年事矜豪，屬辭少繩準。", "程文竟乖疏，貢籍果遺擯。", "內負未蹉跎，不能忘起僨。", "賞延輒辭官，雅志將自奮。"]'),
('4b05cebd-1f3b-4e36-a801-390c380f9cd0','金陵府舍重建金山亭二首  其一','蘇頌','宋','宋诗','song-poetry','','[]','地出城隅闢故臺，斬茅刪竹受良材。',64,'全唐诗/poet.song.30000.json','["地出城隅闢故臺，斬茅刪竹受良材。", "春塘夢草成詩後，畫棟飛雲式燕開。", "一境山形天際望，四時風物坐中來。", "府公經構民偕樂，魚鳥猶知喜躍迴。"]'),
('14dfb506-0fdd-413b-8e1b-02b9e2001db6','金陵府舍重建金山亭二首  其二','蘇頌','宋','宋诗','song-poetry','','[]','故時臺榭對池心，空有名傳擬穴金。',64,'全唐诗/poet.song.30000.json','["故時臺榭對池心，空有名傳擬穴金。", "鬋理茅茨修竹茂，經營軒檻綠楊深。", "橋橫斷岸虹流彩，花滿芳園鳥囀音。", "盛府多歡頻命席，每容疏外共窺臨。"]'),
('895eb56d-adf8-4659-8f6b-5b082ab65074','潤州錢祠部新建寶墨亭','蘇頌','宋','宋诗','song-poetry','','[]','王蕭書迹衛公詩，流落江南世少知。',64,'全唐诗/poet.song.30000.json','["王蕭書迹衛公詩，流落江南世少知。", "古寺購尋遺刻在，新亭龕置斷珉奇。", "模傳遂比黄庭字，埋沒非同石鼓碑。", "墨藪書評多逸事，何妨揮翰與題辭。"]'),
('fff969f1-ce34-403e-8c3a-daa4c0faf13e','和俞仲素太博遊茅山二首 宿明真觀','蘇頌','宋','宋诗','song-poetry','','[]','平林行盡到巖扃，一昔恬然道味生。',64,'全唐诗/poet.song.30000.json','["平林行盡到巖扃，一昔恬然道味生。", "爽籟遠隨林谷響，飛雲時拂棟梁輕。", "閒傾仙斝流瓊液，高論神方鍊日精。", "更想真遊成不寐，坐聽松韵到黎明。"]'),
('b4811859-19f9-4012-b670-1ea003ff78bc','和俞仲素太博遊茅山二首 馬上初望茅峰','蘇頌','宋','宋诗','song-poetry','','[]','三士隠淪地，上林句曲前。',48,'全唐诗/poet.song.30000.json','["三士隠淪地，上林句曲前。", "朅來思訪道，屬望賦遊仙。", "松引飛輪路，雲收積玉巔。", "華陽不知遠，趣駕似行天。"]'),
('3cc7a839-942b-4859-bce8-f7dbac21fe3f','次韵和丘秘校登長干寺塔','蘇頌','宋','宋诗','song-poetry','','[]','九劫半依山，經營昔甚艱。',120,'全唐诗/poet.song.30000.json','["九劫半依山，經營昔甚艱。", "周遭嚴佛宇，直上俯天關。", "登陟緣梯險，淹留布坐慳。", "椽楹亦塗附，櫺檻遍朱殷。", "白日分明到，青雲咫尺攀。", "龍潭斜影落，鳥翼怯飛還。", "基構從吳晉，聲名動朔蠻。", "燈然時照耀，梵唱每循環。", "往事稠重問，前朝指顧間。", "誰知息心處，香火老僧閒。"]'),
('b29d58cc-1d94-42a0-9f87-7389ae6cadfc','次韵約諸君遊長干寺','蘇頌','宋','宋诗','song-poetry','','[]','寺按郡東南，僧嘗爲我談。',216,'全唐诗/poet.song.30000.json','["寺按郡東南，僧嘗爲我談。", "初因晉大士，來獲古靈龕。", "歷世名空在，重興德乃堪。", "先朝賜新額，此地建精藍。", "億載扶皇統，生民息戰函。", "剎仍存故里，龍復止深潭。", "九級惟塗甓，千梁盡架楠。", "亭臺各軒豁，巖谷更空谽。", "殿角芝成玉，松稍露隊甘。", "穴棲金禮鼲，池怪集神𪚫。", "可愛臨岡曲，何人結草庵。", "欲來尋隠逸，誰與共歡酣。", "念往須勤到，登高已舊諳。", "低頭小城市，舉目遍村嵐。", "靜境由茲達，塵容却自慚。", "常思真趣響，可抑俗饕貪。", "宇宙開懷適，江山極望涵。", "相邀幸多暇，命駕即追參。"]'),
('660bacf2-8512-4e1d-9930-84a7dbd0df66','同賦山寺郁李花','蘇頌','宋','宋诗','song-poetry','','[]','小樹扶疏若剪裁，新英濃淡對山齋。',96,'全唐诗/poet.song.30000.json','["小樹扶疏若剪裁，新英濃淡對山齋。", "青紅相間垂羅带，華葉同開綴寶釵。", "未必無言芳徑列，須看成實翠珠排。", "禪扃掩映情多感，藥譜標題品最佳。", "衆卉分敷爭欲並，三春顔色此誰偕。", "誰憐寂寞遊觀少，便與移根向玉階。"]'),
('63a8dfbc-33b4-4656-89f1-0ffb6b37f349','丘林諸君以春雪三絕見寄走賦長句奉酬','蘇頌','宋','宋诗','song-poetry','','[]','彼美春工用意多，剪裁瓊蕊綴庭柯。',64,'全唐诗/poet.song.30000.json','["彼美春工用意多，剪裁瓊蕊綴庭柯。", "妍辭重識梁園賦，寡和還推郢國歌。", "莫嘆餘花皆慘悴，共看修柏自婆娑。", "尊前謾愛風光好，不見山陰泛棹過。"]'),
('01c941fa-7dcb-4489-92a4-2008e624f649','次韵江南感事','蘇頌','宋','宋诗','song-poetry','','[]','京洛倦遊後，江南感慨多。',48,'全唐诗/poet.song.30000.json','["京洛倦遊後，江南感慨多。", "壯懷傷歲月，醉眼小山河。", "無路通談說，窮年謾揣摩。", "知音如有遇，終采擊轅歌。"]'),
('ebf6ec30-a343-458d-a906-0b03e2d61260','春日會飲懷丘思同林成之作四首','蘇頌','宋','宋诗','song-poetry','','[]','濁酒澆腸遣旅懷，春宵常苦漏聲催。',32,'全唐诗/poet.song.30000.json','["濁酒澆腸遣旅懷，春宵常苦漏聲催。", "坐中不見丘夫子，明月無光厭舉杯。"]'),
('bfb3efcd-23e0-4d87-8ca3-54cac5717818','春日會飲懷丘思同林成之作四首 次林韵','蘇頌','宋','宋诗','song-poetry','','[]','二月中和氣序均，酒酣偏覺長精神。',32,'全唐诗/poet.song.30000.json','["二月中和氣序均，酒酣偏覺長精神。", "之人歡會何稀闊，惆悵尊前更惜春。"]'),
('d604ff73-14c2-4756-8b33-e7900d3bdedd','春日會飲懷丘思同林成之作四首 又和前韵','蘇頌','宋','宋诗','song-poetry','','[]','詩論心膽見天真，酒逐羈懷若有神。',32,'全唐诗/poet.song.30000.json','["詩論心膽見天真，酒逐羈懷若有神。", "一夕所思惟我友，四時最樂是熙春。"]'),
('52835697-f43b-4091-ae0e-20f91d183062','春日會飲懷丘思同林成之作四首 又次林韵','蘇頌','宋','宋诗','song-poetry','','[]','右持巵酒左持螯，慷慨酣歌憶藉糟。',32,'全唐诗/poet.song.30000.json','["右持巵酒左持螯，慷慨酣歌憶藉糟。", "因想良交成不寐，清談終夕未爲高。"]'),
('c6ada7af-b632-4753-a0a2-0cbd6ea05d9f','景德寺飲會丘思同作述懷詩兼紀一席之事見約同賦輒次元韵','蘇頌','宋','宋诗','song-poetry','','[]','瀕江多勝宇，茲地更推高。',240,'全唐诗/poet.song.30000.json','["瀕江多勝宇，茲地更推高。", "結友爲文會，開樽較飲豪。", "春華今始盛，聖代况親遭。", "美景堪行樂，雄談任叫號。", "數家供法饌，百斝和春醪。", "異味頻登俎，良庖旋奏刀。", "盤豐介象鱠，手馬畢生螯。", "極量觚并榼，忘形甖與槽。", "憐君皆曠達，獨我嘆徒勞。", "俗狀區區外，剛腸漸漸熬。", "壯心雖不屈，讒口亦奚逃。", "感寓嘗懷古，愁來幾悼騷。", "宦塗蝸鬥角，世事蝟森毛。", "自得猶千慮，誰能挫一毫。", "無煩惡蠅點，須擬效龍韜。", "暫適惟詩酒，難兼是燕敖。", "縱歡忘倦厭，論契甚堅牢。", "峻節凌修幹，清風遏怒濤。", "就賢知不倦，營道豈云叨。", "此席今誰繼，知音盡俊髦。"]'),
('72453f49-1a8a-4806-bd8a-e0c42bdfec48','和惟晤師遊鶴林寺寄穎長老','蘇頌','宋','宋诗','song-poetry','','[]','黄鵠山前古梵宮，參差樓殿倚巖中。',64,'全唐诗/poet.song.30000.json','["黄鵠山前古梵宮，參差樓殿倚巖中。", "群峰重疊圍松徑，三伏嬉遊愛竹風。", "牛首禪宗懷馬素，襄陽耆舊憶龐翁。", "長思勝會真幽適，誰使句嬰不與同。"]'),
('8d04b25a-e4f4-431a-b17b-bfd3c941b5bb','和刁節推郊居寄說晤二詩僧','蘇頌','宋','宋诗','song-poetry','','[]','倦賦從軍咏式微，山齋重此理松扉。',64,'全唐诗/poet.song.30000.json','["倦賦從軍咏式微，山齋重此理松扉。", "春來園圃朱櫻遍，霜後盤飧綠芋肥。", "瓶錫時邀高士駕，臺緇多學野人衣。", "白蓮詩社方求友，喜得支公與共歸。"]'),
('2b616e66-b859-44ca-a8f4-25999956e053','又和月夜理笛答晤見寄','蘇頌','宋','宋诗','song-poetry','','[]','聞說羌戎出塞行，征人纔聽淚交橫。',64,'全唐诗/poet.song.30000.json','["聞說羌戎出塞行，征人纔聽淚交橫。", "三秋霜氣先時至，萬里鄉心半夜驚。", "子野踞床思逐弄，季長卧鄔亦牽情。", "闋終更想關山月，不惜新辭記舊聲。"]'),
('8aa8b873-c3e3-4ce7-ae0b-45db8edb0cd3','送惟晤遊廬山','蘇頌','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','飛錫指湓城，秋風一衲輕。',48,'全唐诗/poet.song.30000.json','["飛錫指湓城，秋風一衲輕。", "溪雲隨晚渡，嶺月伴晨征。", "敏思登臨發，空談舉動明。", "他時二林會，名字繼融生。"]'),
('a9b0d561-c04e-4540-8e8c-05b178fb1bb8','送沈太博倅滑臺','蘇頌','宋','宋诗','song-poetry','','[]','早歲淮陽宰邑初，相君連上薦能書。',64,'全唐诗/poet.song.30000.json','["早歲淮陽宰邑初，相君連上薦能書。", "新從墨綬諸侯國，便領油泥別駕輿。", "東郡提封今輔屏，南都接軫舊鄉閭。", "優游樂職人應羨，官便家榮兩莫如。"]'),
('1e42b839-5211-4762-865b-d51f72dbacac','次韵王伯益同年留別二首','蘇頌','宋','宋诗','song-poetry','','[]','桂籍昔叨聯署等，蓮帷今幸接芳塵。',64,'全唐诗/poet.song.30000.json','["桂籍昔叨聯署等，蓮帷今幸接芳塵。", "塤篪契合均天屬，金石交深過古人。", "直向歲寒期茂悅，肯同時俗論甘辛。", "優游且作江南令，惠愛於民此最親。"]'),
('96b6442c-1d77-48a0-a5b5-f66f49a2f813','次韵王伯益同年留別二首 再次前韵','蘇頌','宋','宋诗','song-poetry','','[]','從宦飄飄九見春，共嗟名迹尚埃塵。',64,'全唐诗/poet.song.30000.json','["從宦飄飄九見春，共嗟名迹尚埃塵。", "相逢梁苑留趨幕，不鄙池陽去長人。", "蚤向文科分甲乙，嘗於命曆校庚辛。", "窮通定分非嬰慮，惟有交情久益親。"]'),
('a076dad0-f747-432f-9e5b-607abdf359aa','卞巡檢重建蘋節堂','蘇頌','宋','宋诗','song-poetry','','[]','棟宇更新構，亭名即舊規。',96,'全唐诗/poet.song.30000.json','["棟宇更新構，亭名即舊規。", "和容君子志，歌闋大夫儀。", "官政搜兵暇，賓賢命席時。", "弦開秋月滿，矢落曉星馳。", "疊中朋籌勝，交酬飲樹移。", "連鼙呈畫的，急管送金巵。", "更得蕭齋榜，重看沈壁詩。", "恩勤主人意，雅志最相宜。"]'),
('7f58034c-7343-4f80-9c74-b4c376f61af7','和刁推官蓼花二首  其一','蘇頌','宋','宋诗','song-poetry','','[]','烟雨寒塘外，蕭條廣隰中。',48,'全唐诗/poet.song.30000.json','["烟雨寒塘外，蕭條廣隰中。", "花逢秋至盛，人愛水邊紅。", "碎纈排霜葉，纖蕤拂露叢。", "尊罍不見賞，留得伴溪翁。"]'),
('e264209b-a264-46a0-add9-94d9bfe0063a','和刁推官蓼花二首  其二','蘇頌','宋','宋诗','song-poetry','','[]','蓮疏菊未破，野艷獨敷榮。',48,'全唐诗/poet.song.30000.json','["蓮疏菊未破，野艷獨敷榮。", "濯水紅纓細，鋪園步障平。", "露寒偏發色，風勁不摧莖。", "採掇聊供餌，丹房助氣清。"]'),
('d6a01e3f-6afb-49b1-9e0c-b144458986aa','次韵簽判張太博移竹','蘇頌','宋','宋诗','song-poetry','','[]','梁苑有脩竹，移來正得時。',240,'全唐诗/poet.song.30000.json','["梁苑有脩竹，移來正得時。", "新開一齋館，分植兩軒墀。", "璅碎青金影，纖圓碧玉枝。", "物應人共美，性與地兼宜。", "漸喜聲成韵，毋傷色暫衰。", "寧因惡土變，自與好風期。", "窗闥常相對，闌干不用施。", "看憐朝露爽，坐覺晝陰遲。", "擬富非侯等，親鄰見鳳姿。", "燕杯留几席，畫筆置藩籬。", "護長防將折，刪枯欲更滋。", "破憂談將解，化恐誤仙騎。", "節聳蛟螭骨，苞翻虎豹皮。", "竿長終勁挺，根困任離披。", "肯顧柯亭賞，休思渭水持。", "吟餘毫亦健，灌罷器頻欹。", "戴譜須書此，淇園未羨之。", "七賢嘗伴侶，六逸重猶夷。", "緬繼斯人躅，如吹仲氏篪。", "蕭然發清思，頼爾作良知。"]'),
('84b605af-1ff7-4582-a858-b242893f58a9','再和倒韵','蘇頌','宋','宋诗','song-poetry','','[]','新植蒼筤竹，欣欣若感知。',240,'全唐诗/poet.song.30000.json','["新植蒼筤竹，欣欣若感知。", "日陰紛展蓋，風韵巧吹篪。", "幸對人瀟灑，兼依地坦夷。", "二年官此者，一日可忘之。", "抱節疏仍密，交柯挺復欹。", "藂生相友善，特立甚矜持。", "長處苔微破，看來露亦披。", "鳳姿聊側翅，蛇變但存皮。", "莫作恂兵伐，留爲介杖騎。", "雪霜饒欲冒，雨露已先滋。", "初見猶齊架，俄驚漸出籬。", "中虛緣物性，外勁是天姿。", "比畝雖云少，成林亦未遲。", "廟丘當見採，栝羽豈勞施。", "鵲尾冠須製，鵷雛食可期。", "拂雲思柏悅，盈畹笑蘭衰。", "任土前書貴，名園此地宜。", "縱難聽嶰管，肯學唱巴枝。", "既許親齋几，寧辭局甃墀。", "更煩勤愛護，有用在他時。"]'),
('cef14b02-0cad-4b24-aff5-a32e67dec8fe','次韵簽判梁寺丞阻水見寄','蘇頌','宋','宋诗','song-poetry','','[]','京府偕趨幕，彌年接坐隅。',288,'全唐诗/poet.song.30000.json','["京府偕趨幕，彌年接坐隅。", "駑駘攀驥足，魚目混驪珠。", "風誼敦貪薄，吹噓變朽枯。", "交親齊魯衛，政事擬阿蒲。", "契合寧容間，情通不鄙無。", "邀歡困萍蟻，較味賸蓴鱸。", "氣盛吞雲夢，文雄獵具區。", "報投均縞紵，應和念篪竽。", "巢閣行觀鳳，爲裘佇薦狐。", "世家傳鵲瑞，職業在鴻都。", "聳壑方騰幹，乘風好縱艫。", "一飛嘗得志，平步即夷塗。", "見比親瓊樹，清如隠玉壺。", "終當拾青紫，詎止學盤盂。", "少別如旬日，相望似五湖。", "荒郊逢轍涸，激水待雲膚。", "窟穴增蛇鼠，腥臊惡蚋蛄。", "尊思孔北海，釜嘆范萊蕪。", "始見生蓂魄，俄驚繞樹烏。", "初猶甘杞菊，久漸厭粱苽。", "晝咏依依柳，宵看歷歷榆。", "晨興常過午，朝膳每通晡。", "閒逸輸吾子，馳驅屬鄙夫。", "無因隨李郭，長日想田蘇。"]'),
('f9ea271b-b4cd-481c-afc8-557df8eab28c','謝太傅杜相公惠吳柑','蘇頌','宋','宋诗','song-poetry','','[]','任土吳邦果，分甘故相庭。',240,'全唐诗/poet.song.30000.json','["任土吳邦果，分甘故相庭。", "纍纍朱實爛，馥馥蜜筒馨。", "玉液三重釀，神丹九鍊形。", "盤中堆火齊，案上鬥銅釘。", "玩比韓嫣彈，餐勝楚子萍。", "瓊津融不竭，塵慮滌還醒。", "近比瓜稱瓝，休誇李似瓶。", "南樓今匪貴，東望亦虛靈。", "盛乃長洲苑，傳之大禹經。", "秋包千樹富，霜葉一林青。", "薦味同飴露，淪輝信景星。", "租園輸歲賦，守吏占官丁。", "貢罷中都府，供先綠野扃。", "緘封重篚襲，道里百郵亭。", "想憶金華宴，須傾縹甕醽。", "同梨資可口，與棗助延齡。", "豈意殊方物，頻霑俗吏廳。", "食珍時有愧，拜賜敢遑寧。", "顧乏齊瑶報，宜追戴带銘。", "永言難紀美，應念思飄零。"]'),
('0e9fc78e-ef60-44e3-85b5-bc5ecfd4074e','太傅相公以梅聖俞寄和建茶詩垂示俾次前韵','蘇頌','宋','宋诗','song-poetry','','[]','近來不貴蜀吳茶，爲有東溪早露芽。',64,'全唐诗/poet.song.30000.json','["近來不貴蜀吳茶，爲有東溪早露芽。", "二月製成輸御府，經時猶未到人家。", "太官供罷頒三吏，東閤開時咏九華。", "從此閩鄉益珍尚，佳章奇品兩相誇。"]'),
('f5385266-e47f-41e9-89ee-d5f82064891c','送句判官赴大理詳斷','蘇頌','宋','宋诗','song-poetry','','[]','廷尉咨賢佐讞刑，辟書連上得翹英。',64,'全唐诗/poet.song.30000.json','["廷尉咨賢佐讞刑，辟書連上得翹英。", "時推黄霸持平久，衆伏兒寬定奏成。", "尺竹泛疑資審劾，惠文彈治要詳精。", "從來法吏多陰德，勉務哀矜助聖明。"]'),
('11d74b48-7d54-4233-ac75-6f173492ffad','府尹歐陽公以臨書智信篇爲貺謹以長句酬謝','蘇頌','宋','宋诗','song-poetry','','[]','八法能工世罕精，帥鈐多暇錄遺經。',64,'全唐诗/poet.song.30000.json','["八法能工世罕精，帥鈐多暇錄遺經。", "言稱智信文毋害，體具真行筆不停。", "勢似公權題殿壁，心希逸少寫黄庭。", "下僚何幸蒙垂贈，循覽留爲座右銘。"]'),
('9116844a-8606-489d-91b0-23ebacde1f89','次韵簽判太博謝府公新詩墨迹','蘇頌','宋','宋诗','song-poetry','','[]','幕府雍容但省文，筆精詩格兩難倫。',64,'全唐诗/poet.song.30000.json','["幕府雍容但省文，筆精詩格兩難倫。", "臨池得法毫端健，擊鉢成篇藻思新。", "征虜雅歌追樂事，蘭亭賡唱掩芳塵。", "梁王賓友鄒枚在，末至慚非賦雪人。"]'),
('3c1dd08d-2615-47ed-8db6-a2251a70455e','次韵和宣甫叔父遷謫過都見寄','蘇頌','宋','宋诗','song-poetry','','[]','解組從戎五筦城，壯謀期欲盪蠻腥。',64,'全唐诗/poet.song.30000.json','["解組從戎五筦城，壯謀期欲盪蠻腥。", "數奇不意同飛將，肺腑何因學衛青。", "報國有心猶慷慨，謫官無悶但沈冥。", "竹林此日重相過，高論時欣側耳聽。"]'),
('c0ff84fa-3831-4f24-b2e2-157a2bf740e2','宣甫以栟櫚茶刷見惠繼之以詩依韵奉和','蘇頌','宋','宋诗','song-poetry','','[]','裝橐分餘具，茶筒使拂塵。',48,'全唐诗/poet.song.30000.json','["裝橐分餘具，茶筒使拂塵。", "製時工匪易，得處賞尤頻。", "常與輪槽並，宜爲焙匣珍。", "齋中延客語，供辦未應貧。"]'),
('75dea192-ce4c-433d-8ca6-8ffc2342bd3b','宣甫宿約見過既而不至翌日有詩爲示謹次元韵','蘇頌','宋','宋诗','song-poetry','','[]','夙昔成嘉約，朝來不見過。',48,'全唐诗/poet.song.30000.json','["夙昔成嘉約，朝來不見過。", "出門非有礙，掩室返多魔。", "咫尺且猶爾，分携將奈何。", "徘徊延望久，雲際待金波。"]'),
('f7e70c06-0bf8-4445-a2d7-cab84115e85d','宣甫隨行有端石茶匣甚佳道中爲僕夫所損某見之謂微瑕無傷尋蒙送示有二絕句依韵拜答  其一','蘇頌','宋','宋诗','song-poetry','','[]','物重齎輕豈易持，何時登頓損瑰奇。',32,'全唐诗/poet.song.30000.json','["物重齎輕豈易持，何時登頓損瑰奇。", "曾爲什襲緹巾寶，一見寒姿不忍遺。"]'),
('c929b2df-f381-45e8-9b24-aeac1398b92d','宣甫隨行有端石茶匣甚佳道中爲僕夫所損某見之謂微瑕無傷尋蒙送示有二絕句依韵拜答  其二','蘇頌','宋','宋诗','song-poetry','','[]','鎸礱圭角制尤精，豈爲微瑕用便輕。',32,'全唐诗/poet.song.30000.json','["鎸礱圭角制尤精，豈爲微瑕用便輕。", "且賞巖珍終耿介，休思人事有虧成。"]'),
('ce3dd7bd-25b8-4d19-8c66-d000284aa46b','送沈學士守毗陵','蘇頌','宋','宋诗','song-poetry','','[]','使君四十五專城，新向鴻都得請行。',64,'全唐诗/poet.song.30000.json','["使君四十五專城，新向鴻都得請行。", "高閣和鉛人暫去，秋郊驅弩吏趨迎。", "蘭陵郡邑今尤盛，陽羨溪山古有名。", "賦政優游多樂事，東園應不負飛觥。"]'),
('e5119ea2-bfe4-4e29-840d-2480e707a2c8','送李留後赴鎮天平','蘇頌','宋','宋诗','song-poetry','','[]','出擁朱轓就鎮雄，須句封國濟亭東。',64,'全唐诗/poet.song.30000.json','["出擁朱轓就鎮雄，須句封國濟亭東。", "干旄光動奎躔外，閫節權并魯分中。", "兩綬鵰鷹紋異繡，半符魚虎佩兼銅。", "朝廷慎重惟良選，定有能聲愜帝衷。"]'),
('590a828b-62c9-4d47-a34a-cafbdb81e20b','送朱屯田赴辟成都','蘇頌','宋','宋诗','song-poetry','','[]','贊條初罷浙江回，辟命還從蜀道來。',64,'全唐诗/poet.song.30000.json','["贊條初罷浙江回，辟命還從蜀道來。", "朱紱聊光新幕府，烏星重照舊行臺。", "秋登危棧烟霄界，曉望通闤錦繡堆。", "樂職定應能賦頌，知君堪繼子淵才。"]'),
('014c4106-5e20-4f37-b5be-9023017ac983','送黄從政宰晉江','蘇頌','宋','宋诗','song-poetry','','[]','泉山南望海之濱，家樂文儒里富仁。',64,'全唐诗/poet.song.30000.json','["泉山南望海之濱，家樂文儒里富仁。", "弦誦多于鄒魯俗，綺羅不減蜀吳春。", "懷章近輟樞廷傑，製錦重紆學館人。", "豈獨光榮生邑里，須知美化浹甌閩。"]'),
('15786ecc-78d1-4c14-87a2-ccd15dabbf86','送李屯田子震赴宛丘簽判','蘇頌','宋','宋诗','song-poetry','','[]','交游情分十年餘，從宦差池後會疏。',64,'全唐诗/poet.song.30000.json','["交游情分十年餘，從宦差池後會疏。", "遠塞新歸饒意氣，長年相遇倍勤渠。", "登朝蚤卧郎官帳，入幕還陪丞相車。", "咫尺淮陽曹事簡，郵筒莫遣少音書。"]'),
('38ebbfa0-044c-4cf9-9006-75d7bf93009f','道元上人累示禪偈詩筆并諸賢賡唱見索鄙作因成短句奉酬','蘇頌','宋','宋诗','song-poetry','','[]','釋子南宗秀，囊文數見過。',48,'全唐诗/poet.song.30000.json','["釋子南宗秀，囊文數見過。", "燈分壁觀後，詩學寶書多。", "摘句心游刃，談空辯注河。", "儒林盛推挹，風勢張雲柯。"]'),
('c6a3ea0e-2d4e-416d-a72d-40b94ed42a44','次韵宋次道學士重過禮院','蘇頌','宋','宋诗','song-poetry','','[]','齋居永日坐重簾，共嘆清才久滯淹。',64,'全唐诗/poet.song.30000.json','["齋居永日坐重簾，共嘆清才久滯淹。", "詩格轉精緣大手，風情不薄早斑髯。", "曲臺論議于今美，東觀繙讎載世兼。", "孤學尸官猶有頼，繄君餘潤遠相霑。"]'),
('fd9bb38c-f8f6-46e0-8171-75a457749d20','判秘閣何龍圖赴職宴集諸公同賦詩以紀出入之盛','蘇頌','宋','宋诗','song-poetry','','[]','一去鴻都歲始旬，職更河澳與言綸。',64,'全唐诗/poet.song.30000.json','["一去鴻都歲始旬，職更河澳與言綸。", "出爲戎閫蕃宣守，歸作儒林典頌人。", "寓直重遊唐麗正，繙書還上漢麒麟。", "參陪樽俎俱時彥，獨愧非才踵後陳。"]'),
('5f4575e6-d998-4d61-ada2-26fb0cb34853','送朱職方赴天彭','蘇頌','宋','宋诗','song-poetry','','[]','曉鼓頻趨宣政朝，左符還領郡封遥。',64,'全唐诗/poet.song.30000.json','["曉鼓頻趨宣政朝，左符還領郡封遥。", "三春車馬逾邛阪，千里帷裳布漢條。", "蚤接朋僚情款款，舊傳詞筆氣飄飄。", "西南留滯應非久，可奈離襟重黯消。"]'),
('b6a9ffb7-9705-4d93-9b91-19242c0ed15b','和丁御史出郊雩祀夕雨初霽','蘇頌','宋','宋诗','song-poetry','','[]','雩帝臨初孟，涓辰用吉辛。',72,'全唐诗/poet.song.30000.json','["雩帝臨初孟，涓辰用吉辛。", "肄儀慚陋學，司直接名臣。", "出從籠街馭，時觀避路人。", "雨餘鮮野服，雲霽變魚鱗。", "觚陛牲匏潔，公卿冕佩轃。", "共期嚴薦享，上副聖心純。"]'),
('8ce405a4-969b-4306-b071-db5ec61e0820','和楊直講寒食感懷','蘇頌','宋','宋诗','song-poetry','','[]','永日輕風起暝陰，傷春情緒苦難禁。',64,'全唐诗/poet.song.30000.json','["永日輕風起暝陰，傷春情緒苦難禁。", "流連節物遊人意，悵惜時光志士心。", "桃李新芳添遠思，龍蛇遺事感悲吟。", "知君退直饒歡趣，每向尊前賞奏音。"]'),
('01aabf34-60e4-4861-8ac7-eec2b1f3a49b','又和春日對酒','蘇頌','宋','宋诗','song-poetry','','[]','倦遊城闕祗疏慵，偏愛君家好事風。',64,'全唐诗/poet.song.30000.json','["倦遊城闕祗疏慵，偏愛君家好事風。", "後院按歌聲不歇，雕章得句曲方終。", "歡來趨向諸緣息，醉裏情懷萬慮空。", "誰道廣文官獨冷，未曾虛度一春中。"]'),
('8dd866ea-40eb-48fa-b393-926e8c66287d','再和','蘇頌','宋','宋诗','song-poetry','','[]','朱門羅綺競珊珊，未必儒官偏少歡。',64,'全唐诗/poet.song.30000.json','["朱門羅綺競珊珊，未必儒官偏少歡。", "隨分管絃娛性尚，等閒唱咏過暄寒。", "幽人棲遁心非適，夸者經營席靡安。", "一絓利名均是徇，能遺斯事更爲難。"]'),
('b8110d05-a66e-4546-99c2-42315273a1c5','送韓玉汝太博出守洋州','蘇頌','宋','宋诗','song-poetry','','[]','州封繁會逼梁嶓，繼世爲藩盛事多。',64,'全唐诗/poet.song.30000.json','["州封繁會逼梁嶓，繼世爲藩盛事多。", "遺德在人棠蔽芾，舊遊經眼樹婆娑。", "春生劍外壺漿溢，花滿褒中駟馬過。", "父老逢迎應善祝，緇衣將入鄭風歌。"]'),
('b560ed97-e72a-423b-a676-00fa0c2ac2ec','送集賢趙少卿出守淝州','蘇頌','宋','宋诗','song-poetry','','[]','行色光輝水國春，龍函畫弩菟分銀。',64,'全唐诗/poet.song.30000.json','["行色光輝水國春，龍函畫弩菟分銀。", "瀛洲舊侶還揮袂，淮甸諸侯半望塵。", "三品新緺垂若若，兩朱華轂去轔轔。", "誰言貴仕猶榮滯，二紀儒林最舊人。"]'),
('9fd27908-6da1-4b89-a343-70684b1ff3d3','送若訥上人歸衢州','蘇頌','宋','宋诗','song-poetry','','[]','應供何來此，囊書謁紫宸。',48,'全唐诗/poet.song.30000.json','["應供何來此，囊書謁紫宸。", "清閒頻賜對，止觀久談真。", "懇謝蘭袍寵，恩頒寶字新。", "重還鄉寺日，學侶益歸親。"]'),
('103d2d7f-91fb-4706-98a1-0804f59936b0','和林喬年學士','蘇頌','宋','宋诗','song-poetry','','[]','高閣清寒夜未暝，獨持鉛筆校中經。',64,'全唐诗/poet.song.30000.json','["高閣清寒夜未暝，獨持鉛筆校中經。", "燈殘短檠人初靜，月上虛廊戶不扃。", "倚蓋星河檐際直，玉晨鐘磬枕邊聽。", "歸來欲記通宵景，恍若曾遊上帝庭。"]'),
('6040b455-eb12-46f8-a126-37b99c92cd76','館西迎駕起居','蘇頌','宋','宋诗','song-poetry','','[]','一梢鳴蹕啟重關，廣殿傳呼趣就班。',64,'全唐诗/poet.song.30000.json','["一梢鳴蹕啟重關，廣殿傳呼趣就班。", "瑞日初臨黄蓋外，紫雲先繞翠裘間。", "和鸞音裏趨翔過，錦繡圍中拜舞還。", "共詫書林清近地，彤墀咫尺對天顔。"]'),
('2e116db5-9850-4f8b-b91e-2b84d9c93bef','送邵裔員外尉長洲','蘇頌','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭山側第新成，門對湖陰水鑑明。',64,'全唐诗/poet.song.30000.json','["洞庭山側第新成，門對湖陰水鑑明。", "紫綬使君還政日，綵衣仙尉拜官榮。", "丘園自適親心樂，桴鼓稀鳴吏局清。", "退食不妨晨夕養，人生從宦此難并。"]'),
('b8ae0531-afc0-4d6b-a969-6e46a6854c90','和李子儀學士上元','蘇頌','宋','宋诗','song-poetry','','[]','傾都繁盛數宵中，知是鈞天第幾重。',64,'全唐诗/poet.song.30000.json','["傾都繁盛數宵中，知是鈞天第幾重。", "岧闕開筵紆警蹕，綵山張樂戲魚龍。", "月華高下隨燈麗，春色融和入酒濃。", "擬逐勝遊行樂去，長年于事亦無悰。"]'),
('a778165f-8fa8-400b-8d3e-ce5a2fc105bc','送襄州李觀察','蘇頌','宋','宋诗','song-poetry','','[]','半符雙節鎮關東，漢沔從來地望雄。',64,'全唐诗/poet.song.30000.json','["半符雙節鎮關東，漢沔從來地望雄。", "帕首諸侯趨道左，題襟群彥寄邦中。", "江魴鱠玉飧盤貴，霜橘堆金燕豆豐。", "心厭紛華欣吏職，當時朝議寵民功。"]'),
('aa73a964-2940-4911-907c-8a047c92b425','送僧務靜還吳','蘇頌','宋','宋诗','song-poetry','','[]','琴詩清絕事，靜也兩兼能。',48,'全唐诗/poet.song.30000.json','["琴詩清絕事，靜也兩兼能。", "技有知音許，名因國士稱。", "故山何日別，歸舫待春乘。", "却遂林泉適，絃歌結舊朋。"]'),
('31c2d1d0-6323-4b67-b7e5-aa8ea4ce1c0e','送都官辛七丈赴治江夏','蘇頌','宋','宋诗','song-poetry','','[]','官柳春來已可攀，使君旌蓋駐江干。',64,'全唐诗/poet.song.30000.json','["官柳春來已可攀，使君旌蓋駐江干。", "還頒明詔恩優渥，坐使環封俗阜安。", "西塞山川餘舊迹，南樓風月有清歡。", "幕中才雅今應盛，暇日追遊興未闌。"]'),
('fd3500e2-44f2-4c52-aad3-f44d81e2165e','送薛宗孺通理并州','蘇頌','宋','宋诗','song-poetry','','[]','河東望族衣冠盛，漢署潛郎閥閱優。',64,'全唐诗/poet.song.30000.json','["河東望族衣冠盛，漢署潛郎閥閱優。", "久擅才名宜治劇，又分朝寄去監州。", "民風近古藩房肅，邊候無塵戍役休。", "元帥正求賢者佐，得君應喜助咨謀。"]'),
('2b3d7da0-4286-46bd-83b8-ca5a91b365ad','寄題宗室世澤太博修性齋','蘇頌','宋','宋诗','song-poetry','','[]','人情安逸或驕惛，君子操修有本原。',64,'全唐诗/poet.song.30000.json','["人情安逸或驕惛，君子操修有本原。", "結宇近同閒燕處，題顔深警聖賢言。", "游心最樂群書富，寓目無窮百卉繁。", "治世右文風教洽，彬彬儒雅遍宗藩。"]'),
('f91a7ba5-c5a1-4cbe-b521-7c56cf77cb03','送唐安虞部趙侯','蘇頌','宋','宋诗','song-poetry','','[]','朱紱郎官領要藩，西南勝處蜀江源。',64,'全唐诗/poet.song.30000.json','["朱紱郎官領要藩，西南勝處蜀江源。", "若非閥閱才資美，豈稱朝廷選任恩。", "路近烟霄經棧險，山如錦繡見花繁。", "郡民舊染文翁化，禮教風流尚可論。"]'),
('9cd3558e-fb65-4f04-8720-f2e03fd97c55','送石舍人得告還蜀','蘇頌','宋','宋诗','song-poetry','','[]','寤寐家山謁告還，錦衣駟馬路人觀。',64,'全唐诗/poet.song.30000.json','["寤寐家山謁告還，錦衣駟馬路人觀。", "逢迎喜識詞臣貴，行役誰言蜀道難。", "江上田桑應不改，里中牛酒欲交歡。", "岷峨信美毋多戀，盛典方資大手刊。"]'),
('698f97d7-80be-4d5c-bcbd-052645bf1565','又送石舍人','蘇頌','宋','宋诗','song-poetry','','[]','予告西還上寵優，輝華行李照亭郵。',64,'全唐诗/poet.song.30000.json','["予告西還上寵優，輝華行李照亭郵。", "內朝簪橐虛嚴直，故國山川想舊遊。", "一去秋光連棧道，及歸春色動皇州。", "眼看景物皆清絕，定有佳章到處留。"]'),
('cdb6ba35-c0ff-4f39-a649-d240efb7a92c','送達夫同年殿丞宰吳江','蘇頌','宋','宋诗','song-poetry','','[]','嘗誇吳會土風嘉，新領銅章一水涯。',64,'全唐诗/poet.song.30000.json','["嘗誇吳會土風嘉，新領銅章一水涯。", "豈爲江山遊賞勝，只貪晨夕旨甘奢。", "魚登盤俎霜縈縷，蘋滿洲汀雪吐花。", "舊令多才君繼美，松陵賡唱未應賒。"]'),
('0a3143f3-7766-4505-8bdc-22b6f6bfb645','送李屯田倅丹陽','蘇頌','宋','宋诗','song-poetry','','[]','西津秋晚度歸艎，新領監州建禮郎。',64,'全唐诗/poet.song.30000.json','["西津秋晚度歸艎，新領監州建禮郎。", "蚤伏能名動江左，重聞謠咏入朱方。", "部中句曲三茅阜，境上吳門二陸鄉。", "官近仙都家在望，錦衣此日倍輝光。"]'),
('18fb56e7-e343-4959-8fad-831b87921aeb','楊君寵示嘉篇次韵奉和','蘇頌','宋','宋诗','song-poetry','','[]','江湖一別歲經旬，携手重遊上苑春。',64,'全唐诗/poet.song.30000.json','["江湖一別歲經旬，携手重遊上苑春。", "華髮滿頭猶未仕，少年得意果何人。", "利名機淺貧奚恤，道義交深老益親。", "清世懷文終有用，窮途寧久困無津。"]'),
('ebe74884-a459-44d4-9966-4685d6a9d9ff','送冀州向團練','蘇頌','宋','宋诗','song-poetry','','[]','河外諸藩北控胡，美君家世領魚書。',64,'全唐诗/poet.song.30000.json','["河外諸藩北控胡，美君家世領魚書。", "舊傳將略名尤重，却過親庭慶有餘。", "使節頻煩民未息，邊庭清晏候仍虛。", "惟宣聖主威懷德，長使天聲讋虜墟。"]'),
('62d80140-6a0e-4283-816c-33e5099340ae','送儀州李太保丈','蘇頌','宋','宋诗','song-poetry','','[]','持節出西闉，腰章入舊秦。',48,'全唐诗/poet.song.30000.json','["持節出西闉，腰章入舊秦。", "家傳虎韜術，朝有象賢人。", "閤閉關山月，帷褰渭水春。", "虜塵今向息，正是雅歌辰。"]'),
('d4189d4d-4f21-4114-a7da-ef0b81c175c2','同呂縉叔諸君寄懷希用師','蘇頌','宋','宋诗','song-poetry','','[]','方袍爲佛者，學術以儒兼。',48,'全唐诗/poet.song.30000.json','["方袍爲佛者，學術以儒兼。", "迹慕山林逸，心從典籍潛。", "白雲中寄趣，浮世外安恬。", "遐想觀書室，焚香正下簾。"]'),
('64a8dfef-c73c-480e-8025-4b0c25c0a27d','送祖擇之少卿學士出疆','蘇頌','宋','宋诗','song-poetry','','[]','四方專對昔難人，今輟文章侍從臣。',64,'全唐诗/poet.song.30000.json','["四方專對昔難人，今輟文章侍從臣。", "萬里光華宣使指，百年恩信浹殊鄰。", "出關飛蓋塵生路，度漠輕車雪擁輪。", "少別書林還隔歲，歸來期宴曲江春。"]'),
('c1a6e25e-3f70-4bdb-a334-585e4b400eac','送王廣淵司門出守絳州','蘇頌','宋','宋诗','song-poetry','','[]','仕宦人言爲郡樂，名藩古有絳臺雄。',64,'全唐诗/poet.song.30000.json','["仕宦人言爲郡樂，名藩古有絳臺雄。", "居園幽絕刻樊記，分國盛强歌晉風。", "歷覽勝遊千騎上，坐頒仁政兩河中。", "當年誰似高門慶，五守同時閒望隆。"]'),
('7456b978-f256-4bcc-a0d4-5558fab147d8','送句都官倅建陽','蘇頌','宋','宋诗','song-poetry','','[]','玉嶺名都古越疆，監州今用上臺郎。',64,'全唐诗/poet.song.30000.json','["玉嶺名都古越疆，監州今用上臺郎。", "溪山絕勝神仙宅，絃誦相聞禮義鄉。", "龍焙槍旗爭早晚，刺桐花葉候災穰。", "朝廷恤遠頻頒詔，更倚賢能慰一方。"]'),
('3611e7b9-943e-480f-b535-f0314a6c52bf','送句湛太博通守汝陰','蘇頌','宋','宋诗','song-poetry','','[]','天漢南通潁水清，新恩監郡赴官榮。',64,'全唐诗/poet.song.30000.json','["天漢南通潁水清，新恩監郡赴官榮。", "數舟旗鼓家人喜，兩岸壺漿父老迎。", "暫試吏能收治績，蚤聞時譽伏朝纓。", "十年京國同遊者，何日如君補外行。"]'),
('bb96359c-5f82-4a0a-a310-1767749640f9','和陳和叔秋寒','蘇頌','宋','宋诗','song-poetry','','[]','夕雨初開霽，晨霜已結寒。',48,'全唐诗/poet.song.30000.json','["夕雨初開霽，晨霜已結寒。", "增裘肌怯重，對酒面生丹。", "急節驚收潦，歸心念採蘭。", "昕趨更清栗，委佩綴公桓。"]'),
('d5bc8157-ddb0-4fe9-8d41-0c5cf1b303d6','又和蔡子直','蘇頌','宋','宋诗','song-poetry','','[]','官局誠俱冷，交盟信不寒。',48,'全唐诗/poet.song.30000.json','["官局誠俱冷，交盟信不寒。", "風霜兩鬢白，冰蘗一心丹。", "未剖方州竹，猶熏畫省蘭。", "北宮陪論定，應似漢丁桓。"]'),
('92798fd0-09e9-4232-9eb5-b61cfdc24200','又自和','蘇頌','宋','宋诗','song-poetry','','[]','一入石渠署，八逢霜樹寒。',48,'全唐诗/poet.song.30000.json','["一入石渠署，八逢霜樹寒。", "任譏書尚白，不廢研磨丹。", "騎省愁看鬢，騷人興佩蘭。", "壯年幾已過，遊樂謝曹桓。"]'),
('fe714ada-8fc0-4870-bd21-b8a4d7a4bbfd','即席分得秋字送張吉老學士移使京西','蘇頌','宋','宋诗','song-poetry','','[]','賜對中楹喜暫留，駐旌聊復到蓬丘。',64,'全唐诗/poet.song.30000.json','["賜對中楹喜暫留，駐旌聊復到蓬丘。", "朋遊少別三周歲，尊酒相逢半白頭。", "頻拜恩光龍鑄節，屢宣風力隼橫秋。", "二邦已見澄清效，更盡寬平緩主憂。"]'),
('61c76ce4-8701-40df-9b03-fb7c8ea966ae','和陳彥升學士九月校書懷舊之作','蘇頌','宋','宋诗','song-poetry','','[]','京國重陽冊府家，正披墳史獵菁華。',64,'全唐诗/poet.song.30000.json','["京國重陽冊府家，正披墳史獵菁華。", "思飄昔日龍山帽，阻看殘秋上苑花。", "悵惜歲華霜染鬢，滯留歸思角生車。", "自憐高閣窮年業，青簡刊讎未有涯。"]'),
('ef1ba761-f08d-40f0-86ce-27e9b23af861','送張中正先生歸廬陵','蘇頌','宋','宋诗','song-poetry','','[]','白首師儒學愈專，未應褐博慕纓鮮。',64,'全唐诗/poet.song.30000.json','["白首師儒學愈專，未應褐博慕纓鮮。", "離群舊友青雲上，負笈諸生絳帳前。", "京洛風塵銷客袂，江湖春色趁歸船。", "飄然無復羈名累，道信鄉閭足謂賢。"]'),
('43a3f416-7375-462d-ab9a-079ffe5da8a3','二月晦日過范景仁舍人留飲聯句分夜而歸','蘇頌','宋','宋诗','song-poetry','','[]','聞道星軺稅鞅鞿，朋遊相繼款齋扉。',64,'全唐诗/poet.song.30000.json','["聞道星軺稅鞅鞿，朋遊相繼款齋扉。", "正當春霽園英富，况值時清諫疏稀。", "共喜開顔論雅舊，須留持酒玩芳菲。", "屬酬新句尤歡縱，不限嚴更未許歸。"]'),
('9b5ec3a2-da58-4fb4-96ce-31ffb988a2e6','和宣甫叔讀白傅丁相詩集','蘇頌','宋','宋诗','song-poetry','','[]','二公清尚固難偕，遷謫襟懷亦洞開。',64,'全唐诗/poet.song.30000.json','["二公清尚固難偕，遷謫襟懷亦洞開。", "得志已觀邪與正，寓言寧校福兼災。", "恬然委順誠高識，展矣文華信雅才。", "珍重佳篇堪繼美，咏歌中遣待時來。"]'),
('3259bb1a-d4d5-49d7-9b17-f0449a9ea3d7','次韵和丹陽裴如晦學士寄示與蔡子直陳述古唱酬五篇  其一','蘇頌','宋','宋诗','song-poetry','','[]','登瀛忝繼唐詞客，補郡仍陪漢望郎。',32,'全唐诗/poet.song.30000.json','["登瀛忝繼唐詞客，補郡仍陪漢望郎。", "政事將何攀邵杜，聲名空貴躡王楊。"]'),
('36f6f64c-7b48-4450-b11a-4402755f9c00','次韵和丹陽裴如晦學士寄示與蔡子直陳述古唱酬五篇  其二','蘇頌','宋','宋诗','song-poetry','','[]','三賢領劇緣才選，拙者求閒屬倦飛。',32,'全唐诗/poet.song.30000.json','["三賢領劇緣才選，拙者求閒屬倦飛。", "幸得汝陰當僻左，無能尸祿衆應譏。"]'),
('b0c117b9-1ae2-48fc-9060-81a1ecc15c9e','次韵和丹陽裴如晦學士寄示與蔡子直陳述古唱酬五篇  其三','蘇頌','宋','宋诗','song-poetry','','[]','紞鼓吳門徹曙開，郡人還喜鄧侯來。',32,'全唐诗/poet.song.30000.json','["紞鼓吳門徹曙開，郡人還喜鄧侯來。", "政成歲稔庭無訟，誰伴南園舉宴杯。"]'),
('6424b8f1-9467-475a-afd0-7ffe449ddbc3','次韵和丹陽裴如晦學士寄示與蔡子直陳述古唱酬五篇  其四','蘇頌','宋','宋诗','song-poetry','','[]','當年二邑絃歌洽，所幸諸生簦蹻隨。',32,'全唐诗/poet.song.30000.json','["當年二邑絃歌洽，所幸諸生簦蹻隨。", "此日毗陵流美化，風流應似贊皇時。"]'),
('0ca65f11-562a-401a-8dce-e1eb466b4e57','次韵和丹陽裴如晦學士寄示與蔡子直陳述古唱酬五篇  其五','蘇頌','宋','宋诗','song-poetry','','[]','惠愛昔曾留二浙，能聲行復表三河。',32,'全唐诗/poet.song.30000.json','["惠愛昔曾留二浙，能聲行復表三河。", "更傳騷雅聯編富，可是江山助思多。"]'),
('0b04f852-1219-4b30-8c1f-17fd34269afe','次韵刁景純學士將至郡見寄','蘇頌','宋','宋诗','song-poetry','','[]','偃伏聲名三十年，當時倫輩有誰前。',64,'全唐诗/poet.song.30000.json','["偃伏聲名三十年，當時倫輩有誰前。", "曾隨貢籍逢標鑒，更向詞林接俊躔。", "上館久違牽夢寐，歸舟將至想神仙。", "襟懷曠達應如舊，遲對清尊一問焉。"]'),
('74004397-7afb-45b2-b7b6-f6502e94f5ad','和梁簽判潁州西湖十三題 涵春圃','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','桃李陰陰一水涯，因人封殖更繁華。',32,'全唐诗/poet.song.30000.json','["桃李陰陰一水涯，因人封殖更繁華。", "湖光凝碧花飄錦，春物惟應此地嘉。"]'),
('c03b117d-456a-4b7e-a9d8-23b19aa587a6','和梁簽判潁州西湖十三題 射堂','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','射者如仁求審固，美哉成室序朋儔。',32,'全唐诗/poet.song.30000.json','["射者如仁求審固，美哉成室序朋儔。", "今時賓禮存無幾，捨矢猶堪一獻酬。"]'),
('7b6eb166-9fe4-4b23-a719-077a31f2bb10','和梁簽判潁州西湖十三題 碧瀾堂','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','北渚清泠十頃波，偶來憑檻意如何。',32,'全唐诗/poet.song.30000.json','["北渚清泠十頃波，偶來憑檻意如何。", "且觀秋水蒙莊論，休聽滄浪漁父歌。"]'),
('6b7bc136-4e01-4c0e-98a9-2d705af6dee2','和梁簽判潁州西湖十三題 野翠堂','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','郊原西與莽蒼連，隔岸人家小徑穿。',32,'全唐诗/poet.song.30000.json','["郊原西與莽蒼連，隔岸人家小徑穿。", "滿目風光杳無際，柳如山色草如烟。"]'),
('aabcacee-860f-4dd4-b1ce-08b813ed6c19','和梁簽判潁州西湖十三題 西湖','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','椒澤疏源勢不休，繞城冰玉湛寒流。',32,'全唐诗/poet.song.30000.json','["椒澤疏源勢不休，繞城冰玉湛寒流。", "鳬鷖容與菰蒲亂，占得江湖一望秋。"]'),
('5829b919-33bb-4d82-96e6-1b2727093be2','和梁簽判潁州西湖十三題 飛蓋橋','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','朱橋矗矗兩園間，湖水平時柳可攀。',32,'全唐诗/poet.song.30000.json','["朱橋矗矗兩園間，湖水平時柳可攀。", "車馬等閒湖上去，遊人常踏月中還。"]'),
('a80153ff-add3-440f-ae4b-579019529943','和梁簽判潁州西湖十三題 臨勝閣','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','近郭溪流一衣带，中流鳬嶼小蓬萊。',32,'全唐诗/poet.song.30000.json','["近郭溪流一衣带，中流鳬嶼小蓬萊。", "西園勝事憑高盡，到者踟躕不忍迴。"]'),
('d0ffc324-e65b-48d5-98e9-970f506a12ee','和梁簽判潁州西湖十三題 清風亭','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','廣寒宮殿誠誇誕，消暑樓臺久寂寥。',32,'全唐诗/poet.song.30000.json','["廣寒宮殿誠誇誕，消暑樓臺久寂寥。", "未似虛亭面空闊，時時清籟濯煩歊。"]'),
('242806ad-dd23-40f2-a816-73e76f1aca01','和梁簽判潁州西湖十三題 擷芳亭','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春來何處最花繁，湖水西頭百畝園。',32,'全唐诗/poet.song.30000.json','["春來何處最花繁，湖水西頭百畝園。", "無限遊人折紅蕊，可憐桃李自無言。"]'),
('56d2f68c-b61f-4bc3-8682-f31732f7ed37','和梁簽判潁州西湖十三題 四望亭','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','高亭春望思無窮，千里人煙指顧中。',32,'全唐诗/poet.song.30000.json','["高亭春望思無窮，千里人煙指顧中。", "比屋如雲濃被野，頤頤醇俗樂時豐。"]'),
('4738af31-6ac1-4d17-b5ea-baa25c3b871f','和梁簽判潁州西湖十三題 去思堂','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','丞相臨人以惠和，三年鄉校起絃歌。',32,'全唐诗/poet.song.30000.json','["丞相臨人以惠和，三年鄉校起絃歌。", "至今旌旆曾遊處，猶道當時樂事多。"]'),
('dcd3d308-128c-4956-8811-447ab183feda','和梁簽判潁州西湖十三題 西溪','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夾岸垂楊展綠陰，倚空庭樹照波心。',32,'全唐诗/poet.song.30000.json','["夾岸垂楊展綠陰，倚空庭樹照波心。", "遊人不泛西溪水，豈見回環野徑深。"]'),
('33882152-d1fe-48fd-aa8d-2d3f236c4fc6','和梁簽判潁州西湖十三題 女郎臺','蘇頌','宋','宋诗','song-poetry','','["\u897f\u6e56"]','荒臺孤映拂晴霓，曾是諸侯築館基。',32,'全唐诗/poet.song.30000.json','["荒臺孤映拂晴霓，曾是諸侯築館基。", "一郡人誇最高處，年年長作會春期。"]'),
('2e4d1175-f7ee-4949-a7a2-6df100e91784','送祖印忠師南歸','蘇頌','宋','宋诗','song-poetry','','[]','擾擾京華客，營營不自閒。',48,'全唐诗/poet.song.30000.json','["擾擾京華客，營營不自閒。", "胡爲丘壑者，亦到市朝間。", "孤月無留影，歸雲靡定山。", "東南清勝處，羨子一舟還。"]'),
('1c5f81ce-dc62-4a97-8898-a06d52b2e6f5','和朱純臣兵部上巳錫宴','蘇頌','宋','宋诗','song-poetry','','[]','故事脩春禊，恩筵啟鳳林。',72,'全唐诗/poet.song.30000.json','["故事脩春禊，恩筵啟鳳林。", "風光來莽蒼，和氣動幽沈。", "六豆分肴貴，千鍾酌醴深。", "執蘭遊洧水，忘味聽韶音。", "鳬藻群官意，雲天上帝心。", "叨陪宴湑召，非服愧華簪。"]'),
('fed43d29-8bc2-4b2f-b647-76a09d1b4469','又和內院海棠','蘇頌','宋','宋诗','song-poetry','','[]','華萼相輝采翠重，幾番濃艷九春中。',64,'全唐诗/poet.song.30000.json','["華萼相輝采翠重，幾番濃艷九春中。", "根盤省闥偏含潤，影拂鄰牆暗逐風。", "繁若百枝然寶炷，深于三入染纁紅。", "諸君賞咏時連屬，珍重多才好事同。"]'),
('a0012adf-f67e-4ddd-815c-1631e98dc36f','次韵程公闢暮春','蘇頌','宋','宋诗','song-poetry','','[]','日日尋春春欲還，園林遊興未應闌。',64,'全唐诗/poet.song.30000.json','["日日尋春春欲還，園林遊興未應闌。", "間關鶑囀衝牙韵，爛漫花開歷綠團。", "須信馬蹄隨處健，肯教金盞暫時乾。", "休驚節物頻更換，適意歡娛定一般。"]'),
('91d5aa71-93b1-4311-9f84-5713b4f60754','再和暮春','蘇頌','宋','宋诗','song-poetry','','[]','黄鶑初囀燕新還，林館清虛景未闌。',64,'全唐诗/poet.song.30000.json','["黄鶑初囀燕新還，林館清虛景未闌。", "甕撥金膏傾臘脚，封開綠絹試春團。", "條風吹笋苞猶嫩，穀雨催花色漸乾。", "若待休閒頻宴集，牽拘人事恐多般。"]'),
('090548c9-be77-470e-a1f0-4469a11915fa','再和','蘇頌','宋','宋诗','song-poetry','','[]','十分春色九分殘，計日追遊至夜闌。',64,'全唐诗/poet.song.30000.json','["十分春色九分殘，計日追遊至夜闌。", "月照餘花光燭燭，露垂新葉影團團。", "壅焙萱背尤宜厚，汲引荷池莫放乾。", "看即熏風催暑景，要須佳玩兩三般。"]'),
('37597cec-bccd-49f4-b519-64e2a3e74a07','再和入省宿','蘇頌','宋','宋诗','song-poetry','','[]','雕龍辭辨幹時才，重贊甘泉屈壯懷。',64,'全唐诗/poet.song.30000.json','["雕龍辭辨幹時才，重贊甘泉屈壯懷。", "被擁綾香歸漢直，食葷忘茹似顔齋。", "休嗟簿領書堆案，况是鴻鸞序漸階。", "公論共推資望久，春雲高步信難排。"]'),
('1431ac89-9f71-42f3-820f-8be145859d7f','和北軒薜荔','蘇頌','宋','宋诗','song-poetry','','[]','分得巖枝带蘚文，壁間延蔓密含春。',64,'全唐诗/poet.song.30000.json','["分得巖枝带蘚文，壁間延蔓密含春。", "摇風似展垂雲翼，和雨疑騫化浪鱗。", "寒對竹軒陵霰雪，靜陪犀柄辟埃塵。", "省闈不比山河遠，休擬靈均咏若人。"]'),
('18796fb7-1cf7-4c2c-b2f0-dc02a108e786','和清明後一日遊西池','蘇頌','宋','宋诗','song-poetry','','[]','萬家供帳集西明，綵艦芳林酒屢行。',64,'全唐诗/poet.song.30000.json','["萬家供帳集西明，綵艦芳林酒屢行。", "强對鶑花無奈老，時聞歌吹不勝情。", "輪囷佳氣城頭近，烋噢清風語下生。", "休沐儻閒須數往，水邊庭際解朝纓。"]'),
('0234d83e-e52f-4998-9e44-d07f0704ead2','行次塘堤','蘇頌','宋','宋诗','song-poetry','','[]','淼淼寒流千里餘，带城襟壘似江湖。',64,'全唐诗/poet.song.30000.json','["淼淼寒流千里餘，带城襟壘似江湖。", "侯王設險古未有，夷狄窺邊今遂無。", "數郡營屯歸耒耨，萬家生聚利菰蒲。", "長堤不絕才如綫，南北衝衝是坦途。"]'),
('b8321b7c-aaf5-4e19-b017-dfed3a43f2fc','登雄州城樓','蘇頌','宋','宋诗','song-poetry','','[]','三關相直斷華戎，燕薊山川一望中。',64,'全唐诗/poet.song.30000.json','["三關相直斷華戎，燕薊山川一望中。", "斥堠人間風馬逸，朝廷恩廣使軺通。", "歲頒金絮非無策，利盡耕桑豈有窮。", "自古和親誚儒者，可憐漢將亦何功。"]'),
('d3a588ec-a2bc-4674-aace-8fa517f570a7','接伴北使至樂壽寄高陽安撫吳仲庶待制','蘇頌','宋','宋诗','song-poetry','','[]','道路傳聞北守賢，就中清尚是河間。',64,'全唐诗/poet.song.30000.json','["道路傳聞北守賢，就中清尚是河間。", "轅門卧鼓軍無警，幕府賡歌筆不閒。", "只合論思居禁闥，豈宜留滯在邊關。", "寧容舊客升堂室，擬請新篇滿篋還。"]'),
('461b1972-4ea4-49f0-8b63-eefd2664b232','和吳仲庶待制見寄','蘇頌','宋','宋诗','song-poetry','','[]','幾日風沙結襟袖，忽傳嘉惠眼重開。',64,'全唐诗/poet.song.30000.json','["幾日風沙結襟袖，忽傳嘉惠眼重開。", "交情不改乘車約，和氣先隨掞藻來。", "元帥本由詩禮選，行人愧匪語言才。", "相逢且喜論平素，若校文章未易陪。"]'),
('85810b4c-494b-4ab5-b1f3-9bdd402b467e','冬至日瓦橋與李綖少卿會飲','蘇頌','宋','宋诗','song-poetry','','[]','使傳驅馳同被命，邊城迢遞偶相從。',64,'全唐诗/poet.song.30000.json','["使傳驅馳同被命，邊城迢遞偶相從。", "風霜正急偏催老，歲月如流又過冬。", "方念去家千里遠，無辭沈醉十分濃。", "須知此會洵堪喜，北上河橋便寡悰。"]'),
('c758eab3-d78c-4b09-8d53-ae128277b5b4','和王臨謝寄蜀箋雙井茶','蘇頌','宋','宋诗','song-poetry','','[]','鈴閤優閒斲句新，客亭傳誦慰馳神。',64,'全唐诗/poet.song.30000.json','["鈴閤優閒斲句新，客亭傳誦慰馳神。", "誠知擷露敲冰陋，豈敵揮毫掞藻春。", "固乏瓊瑶酬錯寶，多慚魚目換驪珍。", "近來聞道談機迅，更恐難當彼上人。"]'),
('f12c8300-c494-4880-8b59-dde809505190','和李少卿寄吳仲庶','蘇頌','宋','宋诗','song-poetry','','[]','延閣儒臣出撫邊，指縱胡虜坐揮鞭。',64,'全唐诗/poet.song.30000.json','["延閣儒臣出撫邊，指縱胡虜坐揮鞭。", "歌謠早已留南楚，唱和今還到北燕。", "使客過從車結轍，耕夫安佚土開阡。", "更將佳句刊齋壁，留作河間故事傳。"]'),
('30ab0c76-e667-4585-a1b2-3abf5b80f630','和吳仲庶寄李子儀','蘇頌','宋','宋诗','song-poetry','','[]','五紀修戎好，重關四向開。',48,'全唐诗/poet.song.30000.json','["五紀修戎好，重關四向開。", "村郊縱牛馬，戰地長蒿萊。", "過客朝連暮，征軺去復回。", "元侯勤主禮，一一倒瓶罍。"]'),
('a24ea87e-8f04-43a3-b60d-d0ce4427d7d3','和李子儀寄吳仲庶','蘇頌','宋','宋诗','song-poetry','','[]','並馳絕塞待燕鄰，喜過重關值故人。',64,'全唐诗/poet.song.30000.json','["並馳絕塞待燕鄰，喜過重關值故人。", "闊別經年勞遠夢，留連此日奉清塵。", "威行列郡連營肅，恩浹諸戎異域春。", "願學子雲承漢詔，未央宮壁頌功臣。"]'),
('a4bf2c6c-6ac5-4f4a-87ae-6c6baf55c86a','和李子儀瀛州借馬寄安撫待制','蘇頌','宋','宋诗','song-poetry','','[]','塞草黄明畜牧肥，外閑千駟氣增威。',64,'全唐诗/poet.song.30000.json','["塞草黄明畜牧肥，外閑千駟氣增威。", "權奇毛骨森相映，騕褭精神動若飛。", "暫借行人持玉節，屢陪方伯展朱旂。", "料君早晚趨嚴召，安穩乘歸從六騑。"]'),
('6f8dc539-28b1-463c-87fe-498395966199','和北遊','蘇頌','宋','宋诗','song-poetry','','[]','銜命初開朔土遊，故人威重肯回眸。',64,'全唐诗/poet.song.30000.json','["銜命初開朔土遊，故人威重肯回眸。", "旌旗在列千餘騎，棨戟遥臨十一州。", "令尹投兵方秉羽，羊公臨塞但輕裘。", "諸賢酬唱無閒日，卷軸今應束兩牛。"]'),
('260e7f3e-020d-4761-aed2-e683d8fd9451','和吳仲庶龍圖寄德仁致政比部二首  其一','蘇頌','宋','宋诗','song-poetry','','[]','道骨仙風擅世華，肯將璠玉混泥沙。',64,'全唐诗/poet.song.30000.json','["道骨仙風擅世華，肯將璠玉混泥沙。", "潛郎未老辭朝路，傲吏歸來學道家。", "逸似子荆將潄石，清如中散本餐霞。", "應思平日市朝客，韁鏁拘攣正可嗟。"]'),
('527eae7e-8b0a-47e3-aae4-a13e268acef8','和吳仲庶龍圖寄德仁致政比部二首  其二','蘇頌','宋','宋诗','song-poetry','','[]','倦遊城闕厭紛華，一棹南歸出白沙。',64,'全唐诗/poet.song.30000.json','["倦遊城闕厭紛華，一棹南歸出白沙。", "簪紱棄來如釋負，山林到處便爲家。", "流泉繞舍鏘金玉，仙餌盈槃泛露霞。", "珍重宗英嘉隠操，遠裁清句重咨嗟。"]'),
('52fe6939-0c8f-47cb-a425-ff744893ae67','某忝被給札之召伏蒙景純學士文丈寵示嘉篇且述早歲先人試職之日嘗亦相遇于政府感愴不已輒次高韵','蘇頌','宋','宋诗','song-poetry','','[]','先友勤渠慶得時，相逢仍在右垣扉。',64,'全唐诗/poet.song.30000.json','["先友勤渠慶得時，相逢仍在右垣扉。", "負山徒荷君恩重，起草多慚筆力微。", "早歲應門叨賞識，幾年聯襼接音徽。", "雕章華藻蒙褒賁，知我從今不患稀。"]'),
('56f98058-55da-4242-be25-e6d7c056038c','景純學士文丈再錄早年見慶嘉篇重用前韵奉和','蘇頌','宋','宋诗','song-poetry','','[]','載世交遊共一時，立朝幾見盛門扉。',64,'全唐诗/poet.song.30000.json','["載世交遊共一時，立朝幾見盛門扉。", "官班早合登青瑣，星象俄聞返少微。", "曾向瀛仙陪雅集，更同綿蕝講鴻徽。", "江干千里勞魂夢，常恨平安信息稀。"]'),
('ca64f443-275f-4178-9e99-d0f582d8e4d4','與次道集賢諫議元素翰林赴沖卿樞密諫議見招宴會同賦','蘇頌','宋','宋诗','song-poetry','','[]','江淮罷郡許歸朝，臺閣重來鬢漸凋。',64,'全唐诗/poet.song.30000.json','["江淮罷郡許歸朝，臺閣重來鬢漸凋。", "內禁群英容接武，西樞元弼記嘗僚。", "當年已絕坐中禮，此日猶蒙客右招。", "衰病無堪還自慰，交游相繼上層霄。"]'),
('4e0e7ffd-1d39-43af-bd4d-5f99067c2cce','用諸公本韵各和一篇共三首  其一','蘇頌','宋','宋诗','song-poetry','','[]','早陪鵷鷺侍丹闈，旋見夔龍陟近司。',64,'全唐诗/poet.song.30000.json','["早陪鵷鷺侍丹闈，旋見夔龍陟近司。", "西閣屢觀新詔草，東曹猶記舊文移。", "半途霄壤成分異，幾歲江湖役夢思。", "席面故人皆顯重，可憐顔尉獨厖眉。"]'),
('63a6cd98-9dee-41e3-ab0f-190d1fa451c8','用諸公本韵各和一篇共三首  其二','蘇頌','宋','宋诗','song-poetry','','[]','二紀書林得並遷，升沈俱喜在樽前。',64,'全唐诗/poet.song.30000.json','["二紀書林得並遷，升沈俱喜在樽前。", "非才幸復登群正，大筆猶稽直五磚。", "欣聽友聲同伐木，坦忘情類似虛船。", "白頭光景尤須惜，樂事相逢且豁然。"]'),
('530c9dc6-aa8a-44d3-938d-c4a0dd7815d5','用諸公本韵各和一篇共三首  其三','蘇頌','宋','宋诗','song-poetry','','[]','繼踵螭階入右垣，曾參何敢望淵騫。',64,'全唐诗/poet.song.30000.json','["繼踵螭階入右垣，曾參何敢望淵騫。", "複門重慶登庸命，樞閤仍陪話舊筵。", "貴賤交情都不改，始終風節固難遷。", "公卿平日推高譽，朝論今誰過鄧先。"]'),
('1800afea-ebb3-421a-8d01-a1e1ccab0066','寄題傅欽之學士濟源草堂','蘇頌','宋','宋诗','song-poetry','','[]','大形南址直河津，君有茅廬泲水濱。',64,'全唐诗/poet.song.30000.json','["大形南址直河津，君有茅廬泲水濱。", "蒼翠入檐藏絕景，潺湲繞舍隔囂塵。", "久遊臺閣忘聲利，長憶漁樵狎隠淪。", "待得功成年至日，歸來不負故園春。"]'),
('aef14df8-9611-4cdb-b734-660acd16e8e9','寄題蒲傳正學士清風閣','蘇頌','宋','宋诗','song-poetry','','[]','閣倚青山書滿堂，門齊通德里高陽。',64,'全唐诗/poet.song.30000.json','["閣倚青山書滿堂，門齊通德里高陽。", "傳家載世惟清白，教子何人似義方。", "班嗣一丘雖道卷，劉商七業已名彰。", "他年駟馬充閭貴，須信文儒澤施長。"]'),
('f5b15ac6-e3c1-4686-8e2a-6369db77c578','寄譯經清衍大師','蘇頌','宋','宋诗','song-poetry','','[]','輦寺棲遲不計年，衡門無異對林泉。',64,'全唐诗/poet.song.30000.json','["輦寺棲遲不計年，衡門無異對林泉。", "試闈給筆頻辭命，譯館翻經屢奏篇。", "九陌塵埃方外境，六時香火靜中緣。", "思陪丈室談名理，自愧常爲俗累牽。"]'),
('b9cfe456-248c-4b85-96e6-2da3fdf27451','送王彥祖學士守毗陵','蘇頌','宋','宋诗','song-poetry','','[]','黄州終始宋名臣，載世逢時見裔孫。',64,'全唐诗/poet.song.30000.json','["黄州終始宋名臣，載世逢時見裔孫。", "賜第中宸躋甲等，遷官京寺出殊恩。", "文章已復光儒館，風節應須繼祖門。", "堅請麾符知有意，聊將慈惠振元元。"]');
